import {
	mapActions,
	mapGetters,
	mapMutations
} from 'vuex'

export default {
	components: {

	},
	props: {
		// 整理过的动态组件列表
		styleConfig: {
			type: Array,
			default: () => []
		},
		// 页面配置数据
		pageConfig: {
			type: Object,
			default: () => {
				return {}
			}
		},
	},
	data() {
		return {
			isScrolled: false,
			scrollTop: 0,
			oldScrollTop: 0,
		};
	},
	computed: {
		...mapGetters(['deviceInfo']),
		pageShow() {
			return this.pageConfig.is_show ? true : false
		},
		isShowFoot() {
			return this.pageConfig.is_show_foot ? true : false
		},
		bgTabVal() {
			return this.pageConfig.bg_tab_val
		},
		pageStyle() {
			let obj = {
				backgroundColor: '',
				backgroundImage: '',
				backgroundAttachment: 'scroll'
			}
			if (this.pageConfig.is_bg_color) {
				obj.backgroundColor = this.pageConfig.color_picker
			}
			if (this.pageConfig.is_bg_pic) {
				obj.backgroundImage = this.pageConfig.bg_pic ? `url(${this.$util.img(this.pageConfig.bg_pic)})` : ''

			}

			return obj
		},
		shareInfo() {
			return {
				...this.pageConfig.gzh_share
			}
		},
		isToTop() {
			return this.pageConfig.is_to_top
		},
		toTopConfig() {
			return {
				...this.pageConfig.to_top_config
			}
		},
	},
	watch: {

	},
	options: {
		styleIsolation: 'shared'
	},
	methods: {
		scroll(e) {
			this.oldScrollTop = e.detail.scrollTop

			if (e.detail.scrollTop > 10) {
				this.isScrolled = true
			} else {
				this.isScrolled = false
			}
			// 为easy-loadimage组件发送事件
			uni.$emit('scroll', e)
			// 为back-top组件发送事件,无所谓组件存在不存在。这个可以在后台diy设置事件，后面再优化
			uni.$emit('back-up-scroll-top', e.detail.scrollTop)
		},
		scrolltolower(e) {
			// 为categoods组件发送事件
			uni.$emit('scrolltolower', e.detail)
		},
		goTop() {
			this.scrollTop = this.oldScrollTop
			this.$nextTick(() => {
				this.scrollTop = 0
			})
		},
	}
};