<template>
	<view :style="[compStyle]" class="comp-box" v-if="goodsList && goodsList.length>0">
		<view class="today-goods-container">
			<view class="hd">
				<view class="left">
					<view class="name">{{titleTxtConfig}}</view>
				</view>
				<view v-if="rightBtnConfig" class="more" @click="$util.on(linkConfig)">{{rightTextConfig}}<text
						class="iconfont icon-jinrujiantou"></text>
				</view>
			</view>
			<view class="content">
				<view ref="todayScroll" :id="'todayScroll'+dataConfig.id" class="scroll-box"
					@touchstart="handleTouchStart" @touchend="handleTouchEnd">
					<view class="scroll-container">
						<view v-for="(item, index) in goodsList" :key="index" class="goods-item"
							:style="{borderRadius:itemRadius}">
							<u-image :src="img(item.goods_img)" height="164" width="164"
								:border-radius="goodsItemRadius" @click="handelCitemClick(item)" />
							<view class="name line1" v-if="checkboxInfo.includes(0)" @click="handelCitemClick(item)">
								{{item.goods_name}}
							</view>
							<view class="price" v-if="checkboxInfo.includes(1)" @click="handelCitemClick(item)"><text
									class="money">￥</text>{{item.goods_price}}</view>
						</view>
					</view>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	import raf from '@/common/requestAnimationFrame'

	export default {
		components: {

		},
		name: 'NewGoods',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				moveStatus: 'right',
				isMove: false,

				goodsList: [],
			};
		},
		computed: {
			titleTxtConfig() {
				return this.dataConfig.titleTxtConfig.value
			},
			rightBtnConfig() {
				return !this.dataConfig.rightBtnConfig.tabVal ? true : false
			},
			rightTextConfig() {
				return this.dataConfig.rightTextConfig.value
			},
			linkConfig() {
				return this.dataConfig.linkConfig.value
			},
			// 商品圆角
			goodsItemRadius() {
				return this.getAttr('goodsItemRadius.val', 0) * 2
			},
			// 商品容器圆角
			itemRadius() {
				const {
					radius
				} = this.dataConfig
				return radius.type ?
					`${radius.valList[0].val * 2}rpx ${radius.valList[1].val*2}rpx ${radius.valList[2].val*2}rpx ${radius.valList[3].val*2}rpx` :
					`${radius.val*2}rpx`
			},
			// 
			checkboxInfo() {
				const {
					checkboxInfo
				} = this.dataConfig
				return checkboxInfo.type
			}
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {
				const {
					typeCustomConfig,
					typeConfig,
					goodsList,
					classList,
					goodsSort,
					numberConfig
				} = this.dataConfig

				if (typeCustomConfig.tabVal == 0) {
					this.goodsList = await this.$u.api.getDiyTodayGoods({
						limit: this.getAttr('numberConfig.val', 10),
					})
				} else if (typeCustomConfig.tabVal == 1) {
					if (typeConfig.activeValue == 1) {
						this.goodsList = await this.$u.api.getDiyTodayGoods({
							ids: goodsList.list.map(item => item.id),
						})
					} else if (typeConfig.activeValue == 2) {
						let sort_type = 5
						if (goodsSort.tabVal == 0)
							sort_type = 1
						else if (goodsSort.tabVal == 1)
							sort_type = 5
						else if (goodsSort.tabVal == 2)
							sort_type = 3

						this.goodsList = await this.$u.api.getDiyTodayGoods({
							cid: classList.classVal,
							count: numberConfig.val,
							sort_type,
						})
					}
				}

				uni.$on(`page-show-${this.pageConfig.id}`, () => {

				})
				uni.$on(`page-hide-${this.pageConfig.id}`, () => {

				})

				this.$nextTick(() => {
					this.scrollToday()
				})


			},
			handleTouchStart() {
				this.isMove = true
				if (this.timer) {
					clearTimeout(this.timer)
					this.timer = null
				}
			},
			handleTouchEnd() {
				// 一秒后开始自动滚动
				this.timer = setTimeout(() => {
					this.isMove = false
				}, 1000)
			},
			scrollToday() {
				const t = this.$refs.todayScroll
				const e = t.$children[0].$el.scrollWidth
				const s = e - t.$el.clientWidth

				const i = () => {
					if (!this.isMove) {
						if (this.moveStatus == 'right') {
							t.$el.scrollLeft++
							if (t.$el.scrollLeft >= s) {
								this.moveStatus = 'left'
							}
						}
						if (this.moveStatus == 'left') {
							t.$el.scrollLeft--
							if (t.$el.scrollLeft <= 1) {
								this.moveStatus = 'right'
							}
						}
					}
					raf(i)
				}
				i()
			},
			handelCitemClick(item) {
				this.$kss.JumpPath(`/pages/goods/detail?id=${item.id}`)
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.comp-box {
		padding: 20rpx;
	}

	.today-goods-container {
		width: 100%;
		height: auto;
		border-radius: 10px;

		.hd {
			display: flex;
			align-items: center;
			justify-content: space-between;
			width: 100%;
			padding: 20rpx 0;

			.left {
				display: flex;
				align-items: center;

				.iconfont {
					color: rgb(233, 51, 35);
					font-size: 30rpx;
					margin-right: 12rpx;
				}

				.name {
					color: rgb(51, 51, 51);
					font-size: 28rpx;
					font-weight: 600;
				}
			}

			.more {
				font-size: 26rpx;
				color: #999;

				.iconfont {
					font-size: 30rpx;
				}
			}
		}

		.content {
			width: 100%;
			border-radius: 0 0 20px 20px;

			.scroll-box {
				width: 100%;
				padding: 3px 0;
				overflow: auto;

				::-webkit-scrollbar {
					display: none;
				}

				scrollbar-width: none;
				-ms-overflow-style: none;

				.scroll-container {
					width: 100%;
					height: 100%;
					white-space: nowrap;
				}
			}

			.goods-item {
				display: inline-block;
				overflow: hidden;
				width: 164rpx;
				background: #fff;

				&+.goods-item {
					margin-left: 20rpx;
				}

				.img {
					margin: 0 auto;
				}

				.name {
					margin-top: 5rpx;
					text-align: center;
					width: 100%;
					color: #888;
					font-size: 24rpx;
				}

				.price {
					width: 100%;
					text-align: center;
					color: #eb223d;
					font-weight: 600;

					.money {
						font-size: 20rpx;
					}
				}
			}
		}
	}
</style>