<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compContentStyle2]">
			<view v-if="styleConfig == 0" class="style-0">
				<view class="hd">
					<text :style="[titleTextStyle]">{{ titleTxtConfig.value}}</text>
				</view>
				<view class="menu-box">
					<view v-for="(item, index) in menuConfig" :key="index" class="menu-item"
						@click="$kss.JumpPath(item.link)">
						<u-image :src="$util.img(item.img)" width="48" height="48" />
						<view class="txt">{{ item.title}}</view>
					</view>
				</view>
			</view>
			<view v-if="styleConfig == 1" class="style-1">
				<view class="hd">
					<view :style="[titleTextStyle]">{{ titleTxtConfig.value }}</view>
				</view>
				<view class="menu-box">
					<view v-for="(item, index) in menuConfig" :key="index" class="menu-item"
						@click="$kss.JumpPath(item.link)">
						<u-image :src="$util.img(item.img)" width="54" height="54" />
						<view class="txt">{{ item.title }}</view>
					</view>
				</view>
			</view>
			<view v-if="styleConfig == 2" class="style-2">
				<view class="menu-box">
					<view v-for="(item, index) in menuConfig" :key="index" class="menu-item"
						@click="$kss.JumpPath(item.link)">
						<u-image :src="$util.img(item.img)" width="54" height="54" />
						<view class="txt">{{ item.title }}</view>
					</view>
				</view>
			</view>
			<view v-if="styleConfig == 3" class="style-3">
				<view class="menu-box">
					<view v-for="(item, index) in menuConfig" :key="index" class="menu-item"
						@click="$kss.JumpPath(item.link)">
						<u-image :src="$util.img(item.img)" width="40" height="40" />
						<view class="txt">{{ item.title }}</view>
						<view class="arrow"><u-icon name="arrow-right" size="28" color="#999" /></view>
					</view>
				</view>
			</view>
		</view>
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'MenusBox',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {

			};
		},
		computed: {
			styleConfig() {
				return this.getAttr('styleConfig.tabVal', 0)
			},
			titleTxtConfig() {
				return this.getAttr('titleTxtConfig', {})
			},
			rightBtnConfig() {
				return !this.getAttr('rightBtnConfig.tabVal', 0) ? true : false
			},
			rightTextConfig() {
				return this.getAttr('rightTextConfig.value', '')
			},
			linkConfig() {
				return this.getAttr('linkConfig.value', '')
			},
			menuConfig() {
				let menuConfig = this.getAttr('menuConfig.list', [])
				let list = this.$_.filter(menuConfig, item => item.show).map(item => {
					return {
						img: item.img,
						title: item.info[0].value,
						link: item.info[1].value
					}
				})
				return list
			},
			numWidth() {
				if (this.menuConfig.length)
					return `calc(100% / ${this.menuConfig.length})`
				else return `100%`
			},
			titleTextStyle() {
				const re = {
					color: this.titleTxtConfig.color,
				}
				if (this.titleTxtConfig.hasFontSize) {
					re.fontSize = `${this.titleTxtConfig.fontSize}px`
				}
				if (this.titleTxtConfig.hasFontBlod) {
					re.fontWeight = this.titleTxtConfig.fontBlod ? 'bolder' : ''
				}
				return re
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {


			},
		}
	}
</script>
<style lang="scss" scoped scoped>
	.wrap {
		position: relative;

		.style-0 {
			.hd {
				display: flex;
				justify-content: space-between;
				align-items: center;
				padding: 20rpx 20rpx 10rpx 20rpx;

				.title {
					margin: 0;
					padding: 0;
					font-weight: 700;
					font-size: 30rpx;
				}
			}

			.menu-box {
				display: flex;
				flex-wrap: wrap;

				.menu-item {
					position: relative;
					display: flex;
					align-items: center;
					justify-content: center;
					flex-direction: column;
					margin-bottom: 48rpx;
					font-size: 26rpx;
					color: #333;
					width: calc(100% / 4);

					.txt {
						margin-top: 20rpx;
						font-size: 26rpx;
						color: #454545;
					}
				}
			}
		}

		.style-1 {
			.hd {
				display: flex;
				justify-content: space-between;
				align-items: center;
				padding: 20rpx 20rpx 10rpx 20rpx;

				.title {
					margin: 0;
					padding: 0;
					font-weight: 700;
					font-size: 30rpx;
				}
			}

			.menu-box {
				display: flex;
				flex-wrap: wrap;

				.menu-item {
					position: relative;
					display: flex;
					align-items: center;
					justify-content: center;
					flex-direction: column;
					margin-bottom: 48rpx;
					font-size: 26rpx;
					color: #333;
					width: calc(100% / 4);

					.txt {
						margin-top: 20rpx;
						font-size: 26rpx;
						color: #454545;
					}
				}
			}
		}

		.style-2 {
			.menu-box {
				display: grid;
				grid-template-columns: 1fr 1fr 1fr;
				gap: 10px;
				width: 100%;

				.menu-item {
					background: #fff;
					display: flex;
					flex-direction: column;
					/*控制元素上下居中*/
					justify-content: center;
					/*控制元素左右居中*/
					align-items: center;
					height: 110px;
					border-radius: 12px;
					background-color: #fff;
					font-size: 13px;
					line-height: 18px;
					color: #333;

					.txt {
						margin-top: 16px;
					}

					&:active {
						opacity: 0.8;
					}
				}
			}
		}

		.style-3 {
			.menu-box {
				display: flex;
				flex-direction: column;

				.menu-item {
					display: flex;
					align-items: center;
					padding: 14px 10px 14px 16px;

					.txt {
						flex: 1;
						margin-left: 10px;
					}

					.arrow {}

					&:active {
						opacity: 0.8;
					}
				}
			}
		}
	}
</style>