<template>
	<view>
		<u-popup v-model="popupShow" :custom-style="customStyle" mode="bottom" :z-index="9999" safe-area-inset-bottom
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="false"
			@close="close" @open="open">
			<view class="popup-title" v-if="goods">
				<view class="img-box" @click="previewImage($util.img(goodsData.goods_img))">
					<u-image :src="$util.img(goodsData.goods_img)" width="180" height="180">
						<view slot="error" class="error-img-box">
							<u-image :src="$util.img('/statics/diy/no-img.png')" width="100" height="100"></u-image>
						</view>
					</u-image>
					<view class="icon-box">
						<u-icon name="search" />
					</view>
				</view>
				<view class="right">
					<price-symbol :showOldPrice="false" :nowPrice="goodsData.goods_price"
						nowPriceColor="var(--view-theme)" />
					<GoodsStoreNum :goodsType="1" :stockNum="goodsData.stock_num" />
				</view>
				<view class="close-box" @click="popupShow=false">
					<u-icon name='close-circle' size="36" color="#8a8a8a" />
				</view>
			</view>
			<view class="roll-box" v-if="goods">
				<scroll-view scroll-y="true" class="scroll-Y">
					<!-- 商品规格 -->
					<goods-spec v-if="goodsSpecKey.length" :spec-key="goodsSpecKey" :spec-value="goodsSpecValue"
						:selected-spec-value="selectedSpecValue" @change="changeSpec" />
					<!-- 下单模板 -->
					<goods-attach v-if="goods.attach && goods.attach.length" ref="attach" :attach="goods.attach"
						:show-batch-order="goods.is_batch === 1" @attach-value="getAttachValue" />
				</scroll-view>
			</view>
			<view class="quantity-box" v-if="goods">
				<view class="title">数量</view>
				<view class="right" v-if="goods.num_type == 1">
					<u-number-box v-model="quantity" @change="quantityChange" :min="goods.start_count"
						:max="goods.end_count"></u-number-box>
				</view>
				<view class="acea-row row-left" style="flex:1;" v-else-if="goods.num_type == 2">
					<view @click="showNumPicker=true" style="display:flex;flex:0%;justify-content: flex-end;">
						<text style="margin-right: 10rpx;">x {{quantity}}</text>
						<u-icon name="arrow-right" color="#ccc"></u-icon>
					</view>
				</view>
			</view>
			<view class="join-button" @click="addCart">确定</view>
		</u-popup>
		<u-select v-model="showNumPicker" mode="single-column" :list="numList" safe-area-inset-bottom
			@confirm="quantityChange"></u-select>
	</view>
</template>

<script>
	import PriceSymbol from '@/components/price-symbol'
	import GoodsStoreNum from '../GoodsStoreNum'
	import GoodsSpec from '../GoodsSpec'
	import Attach from '@/components/ChooseOrderTplDialog/attach_diy'
	import _ from 'lodash'
	import {
		mapActions
	} from 'vuex'

	export default {
		components: {
			'price-symbol': PriceSymbol,
			GoodsStoreNum,
			GoodsSpec,
			'goods-attach': Attach,
		},
		props: {

		},
		data() {
			return {
				popupShow: false,

				quantity: 1,
				goods: null, // 商品数据
				goodsSpecKey: [], // 商品规格key,规格键列表
				goodsSpecValue: {}, //商品规格value，以规格key组合为键的对象

				selectedSpecValue: {}, //选中规格商品
				orderTplData: null, // 输入的下单模板数据

				showNumPicker: false,
			};
		},
		computed: {
			customStyle() {
				const re = {}
				// #ifndef H5
				re.bottom = '110rpx'
				// #endif
				return re
			},
			goodsData() {
				if (this.goods) {
					let re = _.cloneDeep(this.goods)
					re.goods_id = re.id
					if (this.goodsSpecKey.length) {
						return _.mergeWith(re, this.selectedSpecValue, (ov, sv, key) => {
							// 如果规格中没有设置图片，则使用商品信息中的图片
							if (key == 'goods_img') {
								if (sv)
									return sv
								else
									return ov
							} else
								return sv
						})
					} else {
						return re
					}
				} else {
					return {}
				}
			},
			numList() {
				if (this.goods) {
					const {
						num_type,
						num_count
					} = this.goods
					if (num_type == 2) {
						return this.parseNumCount(num_count)
					} else
						return []
				} else {
					return []
				}
			},
		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			...mapActions(['updateCartGoodsNum', 'updateCartAmountMoney']),
			show(e) {
				if (!_.has(e, 'goods_id')) {
					this.$util.msg('缺少商品id')
					return
				}
				if (!_.has(e, 'num')) {
					this.$util.msg('缺少商品数量')
					return
				}
				this.quantity = e.num
				this.popupShow = true
				this.fetchGoodsSpec(e.goods_id)
			},
			close() {
				this.quantity = 1
				this.goods = null
				this.goodsSpecKey = []
				this.goodsSpecValue = {}
				this.selectedSpecValue = {}
			},
			open() {

			},
			quantityChange: _.throttle(function(e) {
				if (this.goods.num_type == 1) {
					this.quantity = e.value
				} else if (this.goods.num_type = 2) {
					this.quantity = e[0].value
				}
			}, 1000),
			async fetchGoodsSpec(goods_id) {
				const {
					goods,
					goods_spec_key,
					goods_spec_value
				} = await this.$u.api.goodsProductSpec({
					goods_id
				})
				this.goods = goods
				this.goodsSpecKey = goods_spec_key
				this.goodsSpecValue = goods_spec_value
			},
			// 规格改变回调
			changeSpec(e) {
				console.log(e)
				this.selectedSpecValue = e
				// const {
				// 	stock_num,
				// 	goods_img,
				// 	face_value,
				// 	goods_price,
				// } = e
				// this.selectedSpecValue = e
				// this.orderForm.goods_spec_id = e.id
			},
			previewImage(url) {
				uni.previewImage({
					current: 0,
					urls: [url],
					style: {
						zIndex: 10000
					}
				})
			},
			// 当num_type =2 时，使用select组件渲染下单数量，先解析下
			parseNumCount(str) {
				let arr = str.split(',')
				let re = []

				arr.forEach(item => {
					if (item.indexOf('-') != -1) {
						let tmp = item.split('-')
						for (let i = tmp[0]; i <= tmp[1]; i++) {
							re.push({
								value: Number(i),
								label: i
							})
						}
					} else {
						re.push({
							value: Number(item),
							label: item
						})
					}
				})
				return re
			},
			// 返回商品模板的值
			getAttachValue({
				batch_tpl
			}) {
				this.orderTplData = batch_tpl
			},
			addCart: _.throttle(async function() {
				const form_data = {
					goods_id: this.goods.id,
					num: this.quantity
				}
				if (this.goodsSpecKey.length) {
					form_data.goods_sku_id = this.selectedSpecValue.id
				}
				if (this.goods.attach && this.goods.attach.length) {
					form_data.batch_tpl = this.orderTplData
				}
				await this.$u.api.goodsCartSave(form_data)
				this.updateCartGoodsNum()
				this.updateCartAmountMoney()
				this.$util.msg('操作成功')
				this.popupShow = false
			}, 1000),
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		padding: 0 32rpx;
		margin-top: 48rpx;
		position: relative;
		display: flex;
		flex-wrap: wrap;

		.img-box {
			width: 90px;
			height: 90px;
			position: relative;

			.icon-box {
				width: 30rpx;
				height: 30rpx;
				background-color: rgba(0, 0, 0, .4);
				border-radius: 4rpx;
				position: absolute;
				bottom: 8rpx;
				right: 8rpx;
				text-align: center;
				line-height: 22rpx;
				display: flex;
				justify-content: center;
				align-items: center;
				color: #fff;
			}
		}

		.right {
			padding-top: 24rpx;
			padding-left: 24rpx;
			display: flex;
			flex-direction: column;
		}

		.close-box {
			position: absolute;
			right: 30rpx;
			top: -4rpx;
			font-size: 33rpx;
			color: #8a8a8a;
		}
	}

	.roll-box {
		display: flex;
		flex-direction: column;
		margin-top: 36rpx;

		.scroll-Y {
			max-height: 640rpx;
		}
	}

	.quantity-box {
		display: flex;
		align-items: center;
		justify-content: space-between;
		padding: 0 30rpx;
		margin-top: 24rpx;

		.title {
			font-size: 28rpx;
			color: #333;
		}

		.right {}
	}

	.join-button {
		font-size: 28rpx;
		width: 710rpx;
		height: 80rpx;
		border-radius: 40rpx;
		text-align: center;
		line-height: 80rpx;
		color: #fff;
		margin: 74rpx auto 40rpx;
		background-color: var(--view-theme);
	}
</style>