<template>
	<view style="flex: 1;">
		<view class="type-box">
			<view class="left">
				<u-icon name="clock"></u-icon>
				<text>充值方式</text>
			</view>
			<view class="right" v-if="showBatchOrder">
				<u-radio-group v-model="isBatch" active-color="red">
					<u-radio :name="0" label-size="28">
						单个购买
					</u-radio>
					<u-radio :name="1" label-size="28">
						批量下单
					</u-radio>
				</u-radio-group>
			</view>
		</view>
		<!-- 弃用原先使用form来渲染，主要是弃用容器 -->
		<view class="dynamic-form-box">
			<template v-if="!isBatch">
				<view class="form-item" v-for="item,idx in attach" :key="idx">
					<template v-if="item.type=='recharge_account'">
						<u-input type="text" v-model="tplForm[item.key]" :placeholder="item.tip" height="40" />
					</template>
					<template v-else-if="item.type=='text'">
						<mix-input v-model="tplForm[item.key]" :options="item.options" :tip="item.tip" />
					</template>
					<template v-else-if="item.type=='password'">
						<u-input type="password" v-model="tplForm[item.key]" :placeholder="item.tip" />
					</template>
					<template v-else-if="item.type=='select'">
						<view @click="showSel=true" style="width: 100%;color:#999">
							{{tplForm[item.key] || '请选择'}}
						</view>
						<u-select v-model="showSel" mode="single-column" :list="item.options"
							@confirm="selConfirm($event,item.key)"></u-select>
					</template>
					<template v-else-if="item.type=='radio'">
						<u-radio-group v-model="tplForm[item.key]">
							<u-radio v-for="(item, index) in item.options" :key="index" :name="item.name">
								{{item.name}}
							</u-radio>
						</u-radio-group>
					</template>
					<template v-else-if="item.type=='checkbox'">
						<u-checkbox-group @change="checkGroupChange($event,item.key)">
							<u-checkbox v-model="item.checked" v-for="(item, index) in item.options" :key="index"
								:name="item.name">{{item.name}}</u-checkbox>
						</u-checkbox-group>
					</template>
					<template v-else-if="item.type=='cascader'">
						<!-- 小程序超过1024kb即会停止渲染;  未解决 -->
						<cascader :ref="`cascader_${item.key}`" :data="item.options" v-model="tplForm[item.key]" />
					</template>
					<template v-else-if="item.type=='upload'">
						<Upload :data="item.options" v-model="tplForm[item.key]" :tip="item.tip" />
					</template>
				</view>
			</template>
			<template v-else>
				<view class="form-item">
					<u-input v-model="batchOrderContent" type="textarea" :placeholder="placeholder" :auto-height="false"
						:height="70" />
					<view class="tip-box">
						<view class="tip-item">
							1.每行格式为：<text class="mobile">{{inputFormat}}</text>
						</view>
						<view class="tip-item">
							2.每行使用<text class="enter">换行符(回车)</text>间隔
						</view>
					</view>
				</view>
			</template>
		</view>
	</view>
</template>

<script>
	import Cascader from './cascader'
	import MixInput from './mix-input'
	import Upload from './upload'

	import Schema from 'async-validator'
	export default {
		components: {
			'cascader': Cascader,
			'mix-input': MixInput,
			'Upload': Upload,
		},
		props: {
			attach: {
				type: Array,
				default: () => []
			},
			showBatchOrder: {
				type: Boolean,
				default: true
			},
		},
		data() {
			return {
				showSel: false,
				tplForm: {},
				tplRule: {},

				isBatch: 0,
				batchOrderContent: '',
			};
		},
		computed: {
			inputFormat() {
				let arr = this.attach.map(item => item.name)
				return `${arr.join('###')}`
			},
			placeholder() {
				return `${this.inputFormat}  一行一个`
			},
		},
		watch: {
			attach: {
				handler(nv) {
					this.init(nv)
				},
				immediate: true
			},
			tplForm: {
				handler(nv) {
					this.$emit('attach-value', {
						batch_tpl: [nv]
					})
				},
				deep: true,
			},
			batchOrderContent: {
				handler(nv) {
					this.$emit('attach-value', this.getBatchOrderContentData(nv))
				},
			},
			isBatch(nv) {
				if (nv == 0) {
					this.$emit('attach-value', {
						batch_tpl: [this.tplForm]
					})
				} else if (nv == 1) {
					this.$emit('attach-value', this.getBatchOrderContentData(this.batchOrderContent))
				}
			},
		},
		created() {
			if (Object.keys(this.tplForm).length) {
				this.$emit('attach-value', {
					batch_tpl: [this.tplForm]
				})
			}
		},
		mounted() {

		},
		methods: {
			init(attach) {
				// 初始化表单的键,表单的验证规则
				if (!!attach) {
					let form = {}
					let rule = {}
					attach.forEach(item => {
						// 需要整理的数据,重新赋值
						// if (item.options && Object.prototype.toString.call(item.options) == '[object String]') {

						// }
						// 处理options
						if (item.type == 'text') {
							if (item.options)
								item.options = this.formatJson(item.options)
							else
								item.options = {}
						} else if (item.type == 'select') {
							if (item.options) {
								let arr = item.options.split(",")
								item.options = arr.map(i => {
									return {
										value: i,
										label: i
									}
								})
							}
						} else if (item.type == 'radio') {
							if (item.options) {
								let arr = item.options.split(",")
								item.options = arr.map(i => {
									return {
										name: i
									}
								})
							}

						} else if (item.type == 'checkbox') {
							if (item.options) {
								let arr = item.options.split(",")
								item.options = arr.map(i => {
									return {
										name: i,
										checked: false,
									}
								})
							}

						} else if (item.type == 'cascader') {
							if (item.options)
								item.options = this.formatJson(item.options)
							else
								item.options = []
						} else if (item.type == 'upload') {
							if (item.options)
								item.options = this.formatJson(item.options)
							else
								item.options = {}
						}

						// 初始化表单的值
						if (item.type == 'checkbox') {
							if (item.value) {
								item.options.map(op => {
									if (Array.isArray(item.value) && item.value.includes(op.name))
										op.checked = true
									return op
								})
								form[item.key] = item.value
							} else {
								form[item.key] = []
							}
						} else if (item.type == 'cascader') {
							form[item.key] = item.value ? item.value : {
								cascaderLabel: item.name,
								cascaderValues: [],
								cascaderTexts: [],
								formValues: [],
							}
						} else if (item.type == 'upload') {
							form[item.key] = item.value ? item.value : []
						} else {
							form[item.key] = item.value
						}

						// 初始化表单验证规则
						if (item.type == 'select') {
							rule[item.key] = [{
								required: true,
								message: `${item.name}未选择`,
								trigger: ['blur', 'change']
							}]
						} else if (item.type == 'radio') {
							rule[item.key] = [{
								required: true,
								message: `${item.name}未选择`,
								trigger: ['blur', 'change']
							}]
						} else if (item.type == 'checkbox') {
							rule[item.key] = [{
								validator: (rule, value, callback) => {
									return Array.isArray(value) && value.length ? true : false
								},
								message: `${item.name}未选择`,
								trigger: ['blur', 'change']
							}]
						} else if (item.type == 'cascader') {
							// 异步验证cascader组件的表单
							rule[item.key] = [{
								asyncValidator: (rule, value, callback) => {
									const ref = this.$refs[`cascader_${item.key}`][0]
									ref.doValid().then(() => {
										callback()
									})
								}
							}]
							// cascader组件走自己内部的表单验证
						} else if (item.type == 'upload') {
							rule[item.key] = [{
								validator: (rule, value, callback) => {
									return Array.isArray(value) && value.length ? true : false
								},
								message: `${item.name}未选择`,
								trigger: ['blur', 'change']
							}]
						} else {
							// 只要存在vali，就是必填
							if (item.vali) {
								if (item.vali == 'all') {
									rule[item.key] = [{
										required: true,
										message: `${item.name}不能为空`,
										trigger: ['blur', 'change']
									}]
								} else if (item.vali == 'number')
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											pattern: /^[0-9]*$/g,
											// 正则检验前先将值转为字符串
											transform(value) {
												return Number(value);
											},
											message: `${item.name}只能包含数字`
										}
									]
								else if (item.vali == 'qq') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											regexp: /^[1-9][0-9]{4,10}$/,
											message: `${item.name}的格式不正确`
										}
									]
								} else if (item.vali == 'mobile') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											regexp: /^1\d{10}$/,
											message: `${item.name}的格式不正确`,
											trigger: ['blur', 'change']
										}
									]
								} else if (item.vali == 'email') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											type: 'email',
											message: `${item.name}的格式不正确`,
											trigger: ['blur', 'change']
										}
									]
								} else if (item.vali == 'url') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											type: 'url',
											message: `${item.name}的格式不正确`,
											trigger: ['blur', 'change']
										}
									]
								} else if (item.vali == 'qqormobile') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`
										},
										{
											validator: (rule, value, callback) => {
												if (
													/^[1-9][0-9]{4,10}$/.test(value) === true ||
													/^1\d{10}$/.test(value) === true
												) {
													return true
												} else {
													return false
												}
											},
											message: `${item.name}的格式不正确`,
											trigger: ['blur', 'change']
										}
									]
								}
							}
						}
					})
					this.tplForm = Object.assign({}, form)
					this.tplRule = Object.assign({}, rule)
				} else {
					this.tplForm = {}
					this.tplRule = {}
				}
			},
			selConfirm(e, formkey) {
				this.tplForm[formkey] = e[0].value
			},
			checkGroupChange(e, formkey) {
				this.tplForm[formkey] = e
			},
			checkForm() {
				if (this.isBatch) {
					let arr = this.getBatchOrderContentData(this.batchOrderContent).batch_tpl
					let promise_arr = arr.map((item, index) => {
						return new Promise((resolve, reject) => {
							// 创建校验器
							const validator = new Schema(this.tplRule);
							validator.validate(item, (errors, fields) => {
								if (errors) {
									this.$util.msg(`第${index+1}行:${errors[0].message}`)
									reject()
								} else
									resolve()
							})
						})
					})
					if (promise_arr.length)
						return Promise.all(promise_arr)
					else
						return new Promise((resolve, reject) => {
							this.$util.msg(`批量充值内容不能为空！`)
							reject()
						})
				} else {
					return new Promise((resolve, reject) => {
						// 创建校验器
						const validator = new Schema(this.tplRule);
						validator.validate(this.tplForm, (errors, fields) => {
							if (errors) {
								this.$util.msg(errors[0].message)
								reject()
							} else
								resolve()
						})
					})
				}
			},
			formatJson(data) {
				if (typeof data == 'string' && data.constructor == String) {
					return JSON.parse(data)
				} else if (typeof data == 'object' && data.constructor == Object) {
					return data
				}
			},
			getBatchOrderContentData(str) {
				if (!str) {
					return {
						batch_tpl: []
					}
				}
				let rows = str.split('\n')
				let batchOrderData = []
				for (let r of rows) {
					if (r) {
						let coloms = r.split('###')
						let tmp = {}
						this.attach.forEach((item, idx) => {
							tmp[item.key] = coloms[idx]
						})
						batchOrderData.push(tmp)
					}
				}
				return {
					batch_tpl: batchOrderData
				}
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.type-box {
		display: flex;
		justify-content: space-between;
		padding: 38rpx 32rpx 44rpx;
	}

	.dynamic-form-box {
		display: flex;
		flex-direction: column;
		gap: 20rpx;

		.form-item {
			margin: 0px 20rpx;
			padding: 0 20rpx;
			overflow: hidden;
			border-radius: 20rpx;
			background-color: rgb(255, 255, 255);
			border: 2rpx solid hsla(33, 21%, 90%, .78);
		}
	}

	.tip-box {
		position: relative;
		display: flex;
		flex-direction: column;
		margin: 20rpx 0;

		&::before {
			content: '';
			position: absolute;
			width: 98%;
			border-top: 1px solid #e5e5e5;
			top: 0;
			left: 50%;
			transform: translateX(-50%);
		}

		.tip-item {
			.mobile {
				font-size: 36rpx;
				color: red;
			}

			.enter {
				color: red;
			}
		}
	}
</style>