<template>
	<view class="comp-box">
		<u-sticky :h5-nav-height="0">
			<!-- 只能有一个根元素 -->
			<view class="nav-bar">
				<view class="left">
					<view class="nav-btn" @click="$util.back()">
						<u-icon name="arrow-left"></u-icon>
					</view>
				</view>
				<view class="right">
					<view v-if="showCollect" class="nav-btn" @click="updateFavorite">
						<template v-if="goods.is_favorite">
							<text class="iconfont icon-jushoucanggift" style="color: #ff5c2d;"></text>
						</template>
						<template v-else>
							<text class="iconfont icon-jushoucang"></text>
						</template>
					</view>
					<view v-if="showCart" class="nav-btn" @click="$util.on('/pages/cart/index')">
						<text class="iconfont icon-gouwuche"></text>
					</view>
					<view class="nav-btn" @click="handelShare">
						<text class="iconfont icon-fenxiang1"></text>
					</view>
				</view>
			</view>
		</u-sticky>
		<view class="carousel">
			<mix-swiper :list="goodsImgs2" :height="760" borderRadius="0" padding="0" />
			<view class="goods-id-box" @click="paste(goods.id)">ID:{{goods.id}}</view>
		</view>
		<view class="goods">
			<view class="price-box">
				<template v-if="couponLabel && couponLabel.length">
					<view class="coupon-price">
						<text class="title">到手价</text>
						<view class="price-num">
							<text class="symbol">￥</text>
							<text class="num">{{goods.coupon_price}}</text>
						</view>
					</view>
					<view class="sale-price">
						<text class="title">售价</text>
						<view class="price-num">
							<text class="symbol">￥</text>
							<text class="num">{{goods.goods_price}}</text>
						</view>
					</view>
				</template>
				<view class="price-num acea-row row-baseline" v-else>
					<text class="symbol">￥</text>
					<view class="num" style="position: relative;">
						{{goods.goods_price}}
						<text class="ml-20 fs-28" @click="showMemberPrice" v-if="showMemberPriceConfig">会员价</text>
						<MinLevelPrice :price1="goods.goods_price" :price2="goods.min_level_price" :type="4" />
					</view>
				</view>
			</view>
			<view class="coupon-box" v-if="couponLabel && couponLabel.length">
				<view class="coupon-wrap">
					<scroll-view class="scroll-view_H" scroll-x="true">
						<view class="scroll-view-item_H coupon-item" v-for="(item,index) in couponLabel" :key="index">
							{{item.name}}
						</view>
					</scroll-view>
				</view>
				<view class="right" @click="showCouponDetail">查看<u-icon name="arrow-right"></u-icon></view>
			</view>
			<view class="info">
				<view class="name">
					<template v-if="sysconfig.goods.goods_uid_type_show">
						<text class="font-bg-red bt-color" v-if="goods.uid_text_type == 1">商家</text>
						<text class="font-bg-red bt-color2" v-else>自营</text>
					</template>
					{{goods.goods_name}}
				</view>
				<view v-if="showInfoConfig.length" class="count">
					<view v-if="showInfoConfig.includes(0)" class="count-item">
						<text>市场价:</text>
						<text>￥{{goods.face_value}}</text>
					</view>
					<view v-if="showInfoConfig.includes(1)" class="count-item">
						<text>商品编号:</text>
						<text>{{goods.id}}</text>
					</view>
					<view v-if="showInfoConfig.includes(2)" class="count-item">
						<text>库存:</text>
						<text>{{ storeNum }}</text>
					</view>
					<view v-if="showInfoConfig.includes(3) && storeNum!=0" class="count-item">
						<text>已售:</text>
						<text>{{goods.goods_sales}}</text>
					</view>
				</view>
			</view>
			<view class="sale-channel" v-if="userinfo.has_api && goods.from_list && goods.from_list.length">
				<view class="list-box">
					<view class="title">销售渠道：</view>
					<view class="list-wrap">
						<view v-for="(item, index) in goods.from_list" :key="index" class="list-item"
							:class="[item.value ? 'active' : 'deactive']">
							<u-icon name="checkmark-circle" size="28" v-if="item.value"></u-icon>
							<u-icon name="close-circle" size="28" v-else></u-icon>
							<text class="txt">{{ item.label }}</text>
						</view>
					</view>
				</view>
			</view>
			<scroll-view class="scroll-view_H goods-tag" scroll-x="true">
				<view class="scroll-view-item_H goods-tag-item" :style="[item.style]"
					v-for="(item,index) in goodsTagList" :key="index">
					{{item.label}}
				</view>
			</scroll-view>
		</view>
		<CouponDetailPopup ref="coupon-detail-popup" />
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'
	import MixSwiper from '@/components/mix-swiper'

	export default {
		components: {
			'mix-swiper': MixSwiper,
		},
		name: 'GoodsInfo',
		props: {

		},
		mixins: [CompMixin],
		inject: ['getGoods', 'updateFavorite', 'showMemberPrice', 'handelShare', 'getViewGoodsPrice', 'getCouponLabel'],
		data() {
			return {

			};
		},
		computed: {
			showCollect() {
				return !this.getAttr('showCollect.tabVal', 0) ? true : false
			},
			showCart() {
				return !this.getAttr('showCart.tabVal', 0) ? true : false
			},
			showIndicator() {
				return !this.getAttr('showIndicator.tabVal', 0) ? true : false
			},
			showMemberPriceConfig() {
				return !this.getAttr('showMemberPriceConfig.tabVal', 0) ? true : false
			},
			showInfoConfig() {
				return this.getAttr('showInfoConfig.type', [])
			},
			goods() {
				return this.getGoods()
			},
			goodsImgs2() {
				let arr = []
				if (this.goods.goods_video)
					arr.push({
						type: "video",
						url: this.goods.goods_video,
					})
				if (this.goods.goods_imgs.length > 0) {
					this.goods.goods_imgs.forEach(item => {
						arr.push({
							type: 'image',
							url: item
						})
					})
				} else {
					if (this.goods.goods_img) {
						arr.push({
							type: 'image',
							url: this.goods.goods_img
						})
					}
				}
				return arr
			},
			storeNum() {
				const {
					goods_sale_show,
					default_warn_stock_num,
					goods_card_density_display,
					goods_virtual_display,
					goods_normal_display
				} = this.sysconfig.goods

				if (goods_sale_show) {
					return (this.goods.stock_num > 99999 ? 99999 : this.goods.stock_num) + '件'
				} else {
					if (this.goods.stock_num >= default_warn_stock_num) {
						let str = `${this.goods.stock_num}`
						if (
							this.goods.goods_type == 1 &&
							goods_card_density_display === true
						) {
							str = '充足'
						} else if (
							this.goods.goods_type == 2 &&
							goods_virtual_display === true
						) {
							str = '充足'
						} else if (
							this.goods.goods_type == 3 &&
							goods_normal_display === true
						) {
							str = '充足'
						}
						return str
					} else if (
						this.goods.stock_num < default_warn_stock_num &&
						this.goods.stock_num > 0
					) {
						return '正常'
					} else {
						return '断货'
					}
				}
			},
			viewGoodsPrice() {
				return this.getViewGoodsPrice()
			},
			goodsTagList() {
				const re = []
				if (this.goods.can_price && this.goods.can_price - 0) {
					re.push({
						label: `销售限价:${this.goods.can_price}`,
						style: {
							color: '#fff',
							background: 'linear-gradient(135deg, #ff5339, #ff9482)',
						}
					})
				}
				if (this.goods.need_balance - 0) {
					re.push({
						label: `限制余额:${this.goods.need_balance}`,
						style: {
							color: '#fff',
							background: 'linear-gradient(135deg, #ff5339, #ff9482)',
						}
					})
				}
				if (this.sysconfig.goods.show_order_need_time && this.goods.take_up_time) {
					re.push({
						label: `订单耗时:${this.$util.formatSeconds(this.goods.take_up_time)}`,
						style: {
							color: '#fff',
							background: 'linear-gradient(135deg, orange, #f7d22e)',
						}
					})
				}

				return re
			},
			couponLabel() {
				return this.getCouponLabel()
			}
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			paste(val) {
				uni.setClipboardData({
					data: val + '',
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			async init() {


			},
			showCouponDetail() {
				this.$refs['coupon-detail-popup'].show(this.goods)
			},
		}
	}
</script>
<style lang="scss" scoped scoped>
	.comp-box {
		position: relative;

		.nav-bar {
			position: absolute;
			z-index: 3;
			top: 20rpx;
			left: 0;
			right: 0;
			width: 100%;
			padding: 0 20rpx;
			display: flex;
			align-items: center;
			background-color: transparent;
			justify-content: space-between;

			.nav-btn {
				background-color: rgba(102, 101, 99, 0.8);
				width: 60rpx;
				height: 60rpx;
				border-radius: 50%;
				text-align: center;
				line-height: 60rpx;
				color: #fff;

				&+.nav-btn {
					margin-left: 10rpx;
				}

				.iconfont {
					font-size: 28rpx;
				}
			}

			.right {
				display: flex;
				align-items: center;
			}
		}

		.carousel {
			position: relative;
			z-index: 2;

			.goods-id-box {
				position: absolute;
				bottom: 60rpx;
				left: 24rpx;
				z-index: 2;
				color: #fff;
				background: rgba(0, 0, 0, .4);
				display: flex;
				align-items: center;
				justify-content: center;
				padding: 6rpx 12rpx;
				border-radius: 12rpx;
				font-size: 24rpx;

			}
		}

		.goods {
			padding: 0 20rpx;
			background-color: #fff;
			display: flex;
			flex-direction: column;

			.price-box {
				display: flex;
				align-items: baseline;
				margin-top: 26rpx;

				.price-num {
					font-size: 48rpx;
					font-weight: 700;
					color: #ff504b;

					.symbol {
						font-size: 24rpx;
					}
				}

				.coupon-price,
				.sale-price {
					display: flex;
					align-items: baseline;
				}

				.coupon-price {
					color: #ff504b;

					.title {}

					.price-num {
						.symbol {
							font-size: 30rpx;
						}
					}
				}

				.sale-price {
					margin-left: 20rpx;

					.title {
						font-size: 24rpx;
						color: rgba(61, 61, 61, 1);
					}

					.price-num {
						font-size: 24rpx;
						color: rgba(61, 61, 61, 1);
					}
				}
			}

			.coupon-box {
				display: flex;
				align-items: center;
				justify-content: space-between;
				color: #FF2121;
				margin-top: 20rpx;
				gap: 20rpx;

				.coupon-wrap {
					flex: 1;
					overflow: hidden;

					.coupon-item {
						padding: 0 8rpx;
						border-radius: 10rpx;
						background: rgba(255, 33, 33, 0.1);
						font-size: 24rpx;

						&+.coupon-item {
							margin-left: 10rpx;
						}
					}
				}

				.right {
					font-size: 24rpx;
				}
			}

			.info {
				padding: 20rpx 0;

				.name {
					.font-bg-red {
						position: relative;
						top: -1px;
						display: inline-block;
						align-items: center;
						background: #e93424;
						color: #fff;
						font-size: 20rpx;
						text-align: center;
						border-radius: 4rpx;
						padding: 0 4rpx;
						line-height: 28rpx;
						margin-right: 8rpx;
						border: 1px solid #e93424;
					}

					.bt-color {
						background-color: #FE8A56;
						border: 1px solid #FE8A56;
					}

					.bt-color2 {
						background-color: #e93424;
						border: 1px solid #e93424;
					}

					.tag {
						display: inline-block;
						padding: 0 2px;
						text-align: center;
						line-height: 14px;
						margin-right: 4px;
						background-color: #e93424;
						border: 1px solid #e93424;
						color: #fff;
						font-size: 10px;
					}
				}

				.count {
					margin-top: 20rpx;
					display: flex;
					align-items: center;
					justify-content: space-between;
					font-size: 24rpx;
					color: #82848f;

					.count-item {
						display: flex;
					}
				}
			}

			.sale-channel {
				margin-bottom: 20rpx;

				.list-box {
					display: flex;
					flex-wrap: nowrap;
					align-items: center;

					.title {
						white-space: nowrap;
						color: #82848f;
						font-size: 24rpx;
					}

					.list-wrap {
						display: flex;
						flex-wrap: wrap;
						align-items: center;
						margin-left: 10rpx;
						gap: 10rpx;

						.list-item {
							display: flex;
							align-items: center;
							border-radius: 8rpx;
							padding: 0 8rpx;
							line-height: 40rpx;
							font-size: 24rpx;
							user-select: none;
							pointer-events: none;

							.txt {
								margin-left: 8rpx;
							}
						}
					}

					.active {
						color: #26b167;
						background-color: #e2f0eb;
					}

					.deactive {
						color: #f0475c;
						background-color: #f6e5ea;
					}
				}
			}

			.goods-tag {
				margin-bottom: 20rpx;

				.goods-tag-item {
					padding: 0 10rpx;
					font-size: 24rpx;
					border-radius: 10rpx;

					&+.goods-tag-item {
						margin-left: 10rpx;
					}
				}
			}
		}
	}
</style>