<template>
	<view class="comp_box">
		<!-- 背景图片 -->
		<view class="bg-img">
			<image :src="$util.img(bgPic)"></image>
		</view>
		<!-- 搜索 -->
		<view class="my-main">
			<view class="mp-header" :style="[mpHeaderStyle]">
				<status-bar v-if="showStatusBar" />
				<view class="serch-box">
					<view class="serch-wrapper flex">
						<!-- <view class="logo skeleton-rect">
							<image :src="dataConfig.logoConfig.url" mode="heightFix"></image>
						</view> -->
						<navigator url="/pages/search/search" hover-class="none" class="skeleton-rect input"
							:style="[inputStyle]">
							{{ dataConfig.inputConfig.value }}
							<u-icon name="search" class="iconfont"></u-icon>
						</navigator>
					</view>
				</view>
			</view>
		</view>
		<!-- 轮播 -->
		<view class="swiperBg">
			<u-swiper :list="imgUrls" :height="320" :mode="mode" :indicator-pos="indicatorPos" :effect3d="effect3d"
				:autoplay="true" bg-color="none" :border-radius="borderRadio" img-mode="scaleToFill"
				@change="swiperChange" @click="swiperClick"></u-swiper>
		</view>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	import StatusBar from '@/components/my-page-header/status-bar.vue'
	export default {
		name: 'BannerSearch',
		components: {
			'status-bar': StatusBar
		},
		props: {
			isScrolled: {
				type: Boolean,
				default: false
			},
		},
		mixins: [CompMixin],
		data() {
			return {
				bgPic: '',
			}
		},
		watch: {

		},
		computed: {
			showStatusBar() {
				if (this.isScrolled && this.dataConfig.searchConfig.tabVal) {
					return true
				} else {
					return false
				}
			},
			mpHeaderStyle() {
				let style = {}
				if (this.isScrolled && this.dataConfig.searchConfig.tabVal) {
					style.background = `linear-gradient(90deg, #FFFFFF 50%, #FFFFFF 100%)`
					style.position = `fixed`
				}
				return style;
			},
			inputStyle() {
				let style = {};
				if (this.isScrolled && this.dataConfig.searchConfig.tabVal) {
					style.background = `#F5F5F5`;
					style.color = `#BBBBBB`;
				}
				return style;
			},
			// 图片轮播数据
			imgUrls() {
				return this.dataConfig.swiperConfig.list.map(item => {
					return {
						image: this.$util.img(item.img || ''),
						title: item.info[0].value,
						url: item.info[1].value
					}
				})
			},
			// 轮播模式
			mode() {
				let docConfig = this.dataConfig.docConfig || {}
				if (docConfig.tabVal === 0)
					return 'rect'
				else if (docConfig.tabVal === 1)
					return 'dot'
				else if (docConfig.tabVal === 2)
					return 'number'
				else if (docConfig.tabVal === 3)
					return 'none'
				else
					return 'none'
			},
			// 指示器位置
			indicatorPos() {
				let docPosition = this.dataConfig.docPosition || {}
				if (docPosition.tabVal === 0)
					return 'topLeft'
				else if (docPosition.tabVal === 1)
					return 'topCenter'
				else if (docPosition.tabVal === 2)
					return 'topRight'
				else if (docPosition.tabVal === 3)
					return 'bottomLeft'
				else if (docPosition.tabVal === 4)
					return 'bottomCenter'
				else if (docPosition.tabVal === 5)
					return 'bottomRight'
				else
					return 'bottomCenter'
			},
			// 开启3D
			effect3d() {
				let styleConfig = this.dataConfig.styleConfig || {}
				return styleConfig.tabVal == 0 ? false : true
			},
			// 圆角
			borderRadio() {
				let filletImg = this.dataConfig.filletImg || {}
				if (filletImg.type == 0) {
					return filletImg.val * 2
				} else
					return 8
			},
		},
		mounted() {
			this.init()
		},
		methods: {
			init() {
				const {
					swiperConfig
				} = this.dataConfig
				this.bgPic = swiperConfig.list.length ? swiperConfig.list[0].img : ''
			},
			swiperChange(index) {
				this.bgPic = this.dataConfig.swiperConfig.list.length ? this.dataConfig.swiperConfig.list[index].img : ''
			},
			swiperClick(index) {
				this.$kss.JumpPath(this.imgUrls[index].url)
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.comp_box {
		position: relative;
		overflow: hidden;

		.bg-img {
			position: absolute;
			width: 100%;
			height: 100%;
			top: 0;
			z-index: 0;
			filter: blur(0);
			overflow: hidden;

			image {
				width: 100%;
				height: 100%;
				filter: blur(30rpx);
				transform: scale(1.5);
			}
		}

		.my-main {
			transition: background-color .5s ease;

			.mp-header {
				z-index: 99;
				// position: fixed;
				position: relative;
				left: 0;
				top: 0;
				width: 100%;

				&.on {
					position: relative;
				}

				.serch-box {
					height: 100rpx;
				}

				.logo {
					height: 60rpx;
					margin-right: 20rpx;

					image {
						width: 100%;
						height: 100%;
					}
				}

				.serch-wrapper {
					align-items: center;
					padding: 0 22rpx;
					height: 100%;

					&.on {
						padding: 0 22rpx;
					}

					.input {
						flex: 1;
						min-width: 0;
						position: relative;
						display: flex;
						align-items: center;
						height: 60rpx;
						padding: 0 32rpx;
						border-radius: 30rpx;
						background: rgba(255, 255, 255, 0.4);
						font-size: 28rpx;
						color: #FFFFFF;

						.iconfont {
							position: absolute;
							right: 25rpx;
							top: 13rpx;
						}
					}
				}
			}

		}

		.swiperBg {
			z-index: 1;
			margin: 0 20rpx 20rpx 20rpx;
		}

	}
</style>