<template>
	<view>
		<view class="comp-box" :style="[compStyle]" :compCnName="compCnName" :compEnName="compEnName">
			<view class="wrap" :style="[compWrapStyle]">
				<view class="comp-content">
					<view v-if="imgConfig" class="left">
						<u-image :src="img(imgConfig)" width="40" height="40" :border-radius="20" />
					</view>
					<view class="middel">
						<view class="title" :style="[titleStyle]">
							{{ titleConfig.value }}
						</view>
						<view class="title2" :style="[title2Style]">
							{{ title2Config.value }}
						</view>
					</view>
					<view v-if="showRightButton" class="right" @click="$kss.JumpPath(rightLink)">
						<view class="right-text" :style="[rightTextStyle]">
							{{ rightTextConfig.value }}
						</view>
						<u-icon name='arrow-right' :color="rightTextStyle.color" />
					</view>
				</view>
			</view>
		</view>
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'TitleBar',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {

			};
		},
		computed: {
			titleConfig() {
				return this.getAttr('titleConfig', {})
			},
			titleStyle() {
				const re = {
					color: this.titleConfig.color,
					fontSize: `${this.titleConfig.fontSize * 2}rpx`,
					fontWeight: this.titleConfig.fontBlod ?
						'bolder' : 'normal',
				}

				return re
			},
			title2Config() {
				return this.getAttr('title2Config', {})
			},
			title2Style() {
				const re = {
					color: this.title2Config.color,
					fontSize: `${this.title2Config.fontSize * 2}rpx`,
					fontWeight: this.title2Config.fontBlod ?
						'bolder' : 'normal',
				}

				return re
			},
			imgConfig() {
				return this.getAttr('imgConfig.url', '')
			},
			showRightButton() {
				return this.getAttr('showRightButton.tabVal', 0) ? false : true
			},
			rightTextConfig() {
				return this.getAttr('rightTextConfig', {})
			},
			rightTextStyle() {
				const re = {
					color: this.rightTextConfig.color,
					fontSize: `${this.rightTextConfig.fontSize * 2}rpx`,
					fontWeight: this.rightTextConfig.fontBlod ?
						'bolder' : 'normal',
				}

				return re
			},
			rightLink() {
				return this.getAttr('rightLink.value', '')
			},
		},
		options: {
			styleIsolation: 'shared'
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {

			},
		}
	}
</script>
<style lang="scss" scoped scoped>
	.comp-content {
		width: 100%;
		display: flex;
		flex-wrap: nowrap;
		align-items: center;
		justify-content: space-between;

		.left {
			max-width: 80rpx;
			margin-right: 12rpx;
		}

		.middel {
			flex: 1;
			overflow: hidden;
			display: flex;
			align-items: baseline;

			.title {}

			.title2 {
				margin-left: 12rpx;
			}
		}

		.right {
			display: flex;
			align-items: center;
		}
	}
</style>