<template>
	<view :style="[compStyle]">
		<view class="cate-box" v-for="item1,index1 in cateList" :key="index1" :style="{ borderRadius: radius }">
			<view class="hd">
				<view class="title">
					<view style="width: 30rpx;">
						<u-image :src="$util.img(item1.img)" height="30" />
					</view>
					{{item1.name}}
				</view>
				<view v-if="rightBtnConfig" class="right" @click="goMore(item1)">
					{{rightTextConfig}}<u-icon name='arrow-right-double' /></text>
				</view>
			</view>
			<view class="cate-list">
				<view class="cate-item" :style="[compContentStyle]" v-for="item2,index2 in item1.children" :key="index2"
					@click="cateItemClick(item2)">
					<view class="img-box">
						<u-image :src="$util.img(item2.img)" height="70" :border-radius="goodsItemImageRadius" />
					</view>
					<view class="right">
						<view class="name line1">{{item2.name}}</view>
						<view class="buy-btn">立即购买<u-icon name="arrow-right-double"></u-icon></view>
					</view>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {},
		name: 'SZCate',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				cateList: [],
				listx: [],
			};
		},
		computed: {
			titleTxtConfig() {
				return this.dataConfig.titleTxtConfig.value
			},
			imgConfig() {
				return this.getAttr('imgConfig.url', '')
			},
			rightBtnConfig() {
				return !this.dataConfig.rightBtnConfig.tabVal ? true : false
			},
			rightTextConfig() {
				return this.dataConfig.rightTextConfig.value
			},
			linkConfig() {
				return this.dataConfig.linkConfig.value
			},
			// 商品圆角
			goodsItemRadius() {
				const {
					goodsItemRadius
				} = this.dataConfig
				return goodsItemRadius.type ?
					`${goodsItemRadius.valList[0].val * 2}rpx ${goodsItemRadius.valList[1].val*2}rpx ${goodsItemRadius.valList[2].val*2}rpx ${goodsItemRadius.valList[3].val*2}rpx` :
					`${goodsItemRadius.val*2}rpx`
			},
			// 
			radius() {
				const radius = this.getAttr('radius', {})
				return radius.type ?
					`${radius.valList[0].val * 2}rpx ${radius.valList[1].val*2}rpx ${radius.valList[2].val*2}rpx ${radius.valList[3].val*2}rpx` :
					`${radius.val*2}rpx`
			},

			// 组件内容渐变色+圆角
			compContentStyle() {
				return {
					borderRadius: this.goodsItemRadius,
					background: `linear-gradient(90deg, ${ this.getAttr('moduleColor.color[0].item') } 0%, ${this.getAttr('moduleColor.color[1].item')} 100%)`,
				};
			},
			// 是否显示全部分类
			showAllCate() {
				return !this.getAttr('showAllCate.tabVal', 0) ? true : false
			},
			// 显示全部分类时，每个分类显示的二级分类数量
			cateHaslevel2Count() {
				return this.getAttr('cateHaslevel2Count.val', 10)
			},
			goodsItemImageRadius() {
				const goodsItemImageRadius = this.getAttr('goodsItemImageRadius', {})
				if (Reflect.has(goodsItemImageRadius, 'type')) {
					return goodsItemImageRadius.type ?
						`${goodsItemImageRadius.valList[0].val * 2}rpx ${goodsItemImageRadius.valList[1].val*2}rpx ${goodsItemImageRadius.valList[2].val*2}rpx ${goodsItemImageRadius.valList[3].val*2}rpx` :
						`${goodsItemImageRadius.val*2}rpx`
				} else {
					return ''
				}
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {
				if (this.showAllCate) {
					const arr = await this.$u.api.getDiyCateTree({
						level: 2,
						is_recommend: false,
						level2_num: this.cateHaslevel2Count
					})
					this.cateList = arr.filter((item) => {
						if (item.children && item.children.length)
							return item
					})

					const data = []
					this.cateList.map((item, i) => {
						data.push({
							name: `Item ${i}`,
							index: i,
							id: `Item${i}`,
							height: (Math.floor(Math.random() * 100) + 100),
							data: item
						})
					})
					this.listx = data
				} else {
					let obj = {
						name: this.getAttr('titleTxtConfig.value', ''),
						link: this.getAttr('linkConfig.value', ''),
						img: this.getAttr('imgConfig.url', ''),
						children: []
					}
					const classList = this.getAttr('classList', {})
					obj.children = await this.$u.api.getDiyCateIndex({
						ids: classList.classVal,
					})
					this.cateList = []
					this.cateList[0] = obj
				}
			},
			goMore(item) {
				console.log(item)
				uni.setStorageSync('tab-params', {
					cpid: item.id
				})
				this.$Router.pushTab({
					path: '/pages/category/index',
				})
				// if (this.showAllCate) {
				// 	uni.setStorageSync('tab-params', {
				// 		cpid: item.id
				// 	})
				// 	this.$Router.push({
				// 		path: '/pages/category/index',
				// 	})
				// } else {
				// 	this.$kss.JumpPath(this.linkConfig)
				// }
			},
			cateItemClick(item) {
				let {
					jump_var
				} = item
				const [cpid, cid, cgid] = _.split(jump_var, ',')
				this.$kss.JumpPath(this.getUrl('/pages/goods/list', {
					cpid,
					cid,
					cgid
				}))
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.h100 {
		height: 100vh;
	}

	.cate-box {
		background-color: #fff;

		&+.cate-box {
			margin-top: 20rpx;
		}

		.hd {
			display: flex;
			justify-content: space-between;
			align-items: center;
			padding: 20rpx;

			.title {
				color: #333;
				font-weight: bold;
				display: flex;
				font-size: 14px;
				align-items: center;
				gap: 20rpx;
			}

			.right {
				color: gray;
			}
		}

		.cate-list {
			width: 100%;
			height: 100%;
			display: flex;
			flex-wrap: wrap;
			margin-top: -10rpx;

			.cate-item {
				flex: 0;
				flex-basis: calc(calc(100% / 3) - 20rpx);
				display: flex;
				align-items: center;
				justify-content: center;
				gap: 10rpx;
				cursor: pointer;
				background-color: #fff;
				overflow: hidden;
				height: 124rpx;
				border-radius: 10rpx;
				margin: 10rpx;
				box-shadow: 0 10rpx 20rpx rgba(255, 128, 83, .14);
				padding: 10rpx;

				.img-box {
					width: 70rpx;
					background-color: #fff;
				}

				.right {
					display: flex;
					flex-direction: column;
					justify-content: space-between;
					font-size: 24rpx;
					flex: 1;
					overflow: hidden;
					gap: 10rpx;

					.name {
						font-weight: 500;
					}

					.buy-btn {
						font-size: 20rpx;
						font-weight: 400;
						color: #9b9fa8;
						white-space: nowrap;
					}
				}
			}
		}

	}
</style>