<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compContentStyle2]">
			<view class="category-header">
				<view class="category-name" @click="popupShow=!popupShow">
					<view class="t1 line1">{{categoryData.name}}</view>
					<u-icon :name="popupShow?'arrow-down':'arrow-up'" />
				</view>
				<view class="search">
					<u-search placeholder="请输入您想要的商品" disabled :show-action="false" shape="square" />
					<view class="layer" @click="$util.on('/pages/search/search')"></view>
				</view>
				<view class="category-style" @click="styleChange">
					<u-image :src="img('/statics/diy/common/components/CategoryHeader/100/list-icon.svg')" width="36" height="36"
						:fade="false" v-if="listStyle==0" />
					<u-image :src="img('/statics/diy/common/components/CategoryHeader/100/grid-icon.svg')" width="36" height="36"
						:fade="false" v-else-if="listStyle==1" />
				</view>
				<view class="popup-box" v-show="popupShow" @click="popupShow=false">
					<view class="catalogue-box" @click.stop>
						<view class="item" :class="{on:item.id==categoryData.id}" v-for="item,index in categoryList"
							:key="index" @click="change(item)">
							{{item.name}}
						</view>
					</view>
				</view>
			</view>
		</view>
		<view style="padding-top: 108rpx;"></view>
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'
	import _ from 'lodash'

	export default {
		components: {

		},
		name: 'CategoryHeader',
		props: {

		},
		mixins: [CompMixin],
		inject: ['getCategoryData', 'getListStyle', 'setListStyle', 'getCategoryTreeData', 'categoryChange'],
		data() {
			return {
				popupShow: false,
			};
		},
		computed: {
			categoryList() {
				return this.getCategoryTreeData()
			},
			categoryData() {
				const arr = this.getCategoryData()
				return arr[0] || {}
			},
			listStyle() {
				return this.getListStyle()
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {},
			open() {},
			close() {},
			change(item) {
				if (item.id == this.categoryData.id)
					return
				this.categoryChange(item, 0)
				this.popupShow = false
			},
			styleChange() {
				this.setListStyle(Math.abs(this.listStyle - 1))
			}
		}
	}
</script>
<style lang="scss" scoped scoped>
	.comp-box {
		position: relative;
		z-index: 2;
	}

	.wrap {
		position: fixed;
		width: 100%;
		top: var(--status-bar-height);
		/* #ifndef H5 */
		top: calc(var(--status-bar-height) + 10px);
		/* #endif */
		left: 0;
		right: 0;
	}

	.category-header {
		display: flex;
		align-items: center;
		height: 108rpx;
		padding: 0 20rpx;
		gap: 20rpx;
		position: relative;
		z-index: 10;

		.category-name {
			display: flex;
			align-items: center;
			flex-wrap: nowrap;
			font-weight: 550;
			font-size: 30rpx;
			color: #1e2331;
			cursor: pointer;
			gap: 10rpx;
			width: 200rpx;

			&>.t1 {
				white-space: nowrap;
			}

			&>i {
				font-weight: bolder;
			}
		}

		.search {
			flex: 1;
			position: relative;

			.layer {
				position: absolute;
				width: 100%;
				height: 100%;
				background-color: transparent;
				top: 0;
				left: 0;
			}
		}

		.category-style {
			display: flex;
			align-items: center;
			cursor: pointer;
		}
	}

	.popup-box {
		position: absolute;
		top: 100%;
		left: 50%;
		transform: translate(-50%);
		width: 100%;
		height: calc(var(--vh) * 100 - 108rpx - var(--status-bar-height));
		/* #ifndef H5 */
		height: calc(var(--vh) * 100 - 108rpx - calc(var(--status-bar-height) + 10px));
		/* #endif */
		background: rgba(0, 0, 0, .3);
		z-index: 999;
		overflow-y: auto;

		.catalogue-box {
			position: absolute;
			top: 0;
			left: 50%;
			transform: translate(-50%);
			width: 100%;
			min-height: 400rpx;
			display: grid;
			grid-template-columns: repeat(3, auto);
			align-content: start;
			justify-content: center;
			gap: 30rpx;
			padding: 30rpx 0;
			background-color: #fff;
			border-radius: 0 0 20rpx 20rpx;

			.item {
				font-size: 28rpx;
				display: flex;
				align-items: center;
				justify-content: center;
				height: 65rpx;
				width: 210rpx;
				color: #9b9fa8;
				background: #F0F3F7;
				border-radius: 10rpx;
			}

			.on {
				background: rgba(252, 76, 32, .1);
				color: #fd613a;
			}
		}
	}
</style>