<template>
	<view v-if="pageShow" class="page">
		<status-bar />
		<scroll-view enable-back-to-top scroll-y scroll-with-animation class="scroll-y" :style="currentTheme"
			:scroll-top="scrollTop" @scrolltolower="scrolltolower" @scroll="scroll">
			<view class="page-comp-box"
				:class="bgTabVal==2?'fullsize noRepeat':bgTabVal==1?'repeat ysize':'noRepeat ysize'"
				:style="[pageStyle]">
				<block v-for="(item, index) in styleConfig" :key="index">
					<!-- 轮播搜索 -->
					<BannerSearch v-if="item.name == 'BannerSearch'" :dataConfig="item" :isScrolled="isScrolled" />
					<!-- 导航组 -->
					<Menus v-if="item.name == 'Menus'" :dataConfig="item" />
					<!-- 新闻公告 -->
					<News v-if="item.name == 'News'" :dataConfig="item" />
					<!-- 广告 -->
					<Ad v-if="item.name == 'Ad'" :dataConfig="item" />
					<!-- 图片魔方 -->
					<PictureCube v-if="item.name == 'PictureCube'" :dataConfig="item" />
					<!-- 新品发布 -->
					<NewGoods v-if="item.name == 'NewGoods'" :dataConfig="item" :pageConfig="pageConfig" />
					<!-- 近期降价 -->
					<ReducePrice v-if="item.name == 'ReducePrice'" :dataConfig="item" />
					<ReducePriceV2 v-if="item.name == 'ReducePriceV2'" :dataConfig="item" />
					<!-- 分类商品 -->
					<CateGoods v-if="item.name == 'CateGoods'" :dataConfig="item" />
					<!-- 商品列表 -->
					<GoodsList v-if="item.name == 'GoodsList'" :dataConfig="item" />
					<GoodsListV2 v-if="item.name == 'GoodsListV2'" :dataConfig="item" />
					<!-- 仿商战-分类 -->
					<SZCate v-if="item.name == 'SZCate'" :dataConfig="item" />
					<!-- 仿商战-轮播搜索 -->
					<SZBannerSearch v-if="item.name == 'SZBannerSearch'" :dataConfig="item" />
					<!-- 弹框 -->
					<SystemNoticeDialog v-if="item.name=='SystemNoticeDialog'" :dataConfig="item" />

					<!-- 用户信息 -->
					<UserInfoBox v-if="item.name=='UserInfoBox'" :dataConfig="item" :pageConfig="pageConfig" />
					<!-- 订单中心 -->
					<OrderBox v-if="item.name=='OrderBox'" :dataConfig="item" :pageConfig="pageConfig" />
					<!-- 导航块 -->
					<MenusBox v-if="item.name=='MenusBox'" :dataConfig="item" />
					<!-- 按钮 -->
					<BlockButton v-if="item.name=='Button'" :dataConfig="item" />
					<!-- 开通分站 -->
					<VipBanner v-if="item.name == 'VipBanner'" :dataConfig="item" />
					<!-- 开通供货商 -->
					<MerchantBanner v-if="item.name == 'MerchantBanner'" :dataConfig="item" />
					<!-- 退出登录按钮 -->
					<LogoutButton v-if="item.name == 'LogoutButton'" :dataConfig="item" />
					<!-- 版权 -->
					<CopyRight v-if="item.name == 'CopyRight'" :dataConfig="item" />
					<!-- 红包 -->
					<RedBag v-if="item.name=='RedBag'" :dataConfig="item" />
					<!-- 悬浮菜单 -->
					<FabMenu v-if="item.name=='FabMenu'" :dataConfig="item" />
					<!-- 商品信息 -->
					<GoodsInfo v-if="item.name=='GoodsInfo'" :dataConfig="item" />
					<!-- 等级提升 -->
					<LevelUp v-if="item.name=='LevelUp'" :dataConfig="item" />
					<!-- 商品组合条 -->
					<GoodsCombBar v-if="item.name=='GoodsCombBar'" :dataConfig="item" />
					<!-- 商家信息 -->
					<MerchantInfo v-if="item.name=='MerchantInfo'" :dataConfig="item" />
					<!-- 商品详情 -->
					<GoodsDetail v-if="item.name=='GoodsDetail'" :dataConfig="item" />
					<!-- 购买按钮组 -->
					<BuyButton v-if="item.name=='BuyButton'" :dataConfig="item" />
					<!-- 商品分类头 -->
					<CategoryHeader v-if="item.name=='CategoryHeader'" :dataConfig="item" />
					<!-- 商品二级分类 -->
					<CategoryChildList v-if="item.name=='CategoryChildList'" :dataConfig="item" />
					<!-- 分类商品列表 -->
					<CategoryGoodsList v-if="item.name=='CategoryGoodsList'" :dataConfig="item" />
					<!-- 活动弹框 -->
					<ActivityDialog v-if="item.name=='ActivityDialog'" :dataConfig="item" :pageConfig="pageConfig" />
					<!-- 公众号关注 -->
					<OfficialAccountAttention v-if="item.name=='OfficialAccountAttention'" :dataConfig="item"
						:pageConfig="pageConfig" />
					<!-- 辅助空白 -->
					<BlankBox v-if="item.name=='BlankBox'" :dataConfig="item" />
					<!-- 辅助空白 -->
					<AuxiliarylLine v-if="item.name=='AuxiliarylLine'" :dataConfig="item" />
					<!-- 富文本 -->
					<RichText v-if="item.name=='RichText'" :dataConfig="item" />
					<!-- 分类1 -->
					<Category1 v-if="item.name=='Category1'" :dataConfig="item" />
					<!-- 分类2 -->
					<Category2 v-if="item.name=='Category2'" :dataConfig="item" />
					<!-- 标题栏 -->
					<TitleBar v-if="item.name=='TitleBar'" :dataConfig="item" />
				</block>
			</view>
			<!-- 回到顶部 -->
			<BackTop :scrollTop="oldScrollTop" v-if="isToTop" :dataConfig="toTopConfig" @goTop="goTop" />
			<slot name="comp"></slot>
		</scroll-view>
		<!-- 底部tabbar -->
		<PageFooter v-if="isShowFoot" />
	</view>
</template>

<script>
	import {
		mapActions,
		mapGetters,
		mapMutations
	} from 'vuex'
	import page from './mixins/page.js'
	import StatusBar from '@/components/my-page-header/status-bar.vue'


	import Ad from "./lib/Ad"
	import BannerSearch from "./lib/BannerSearch"
	import CateGoods from "./lib/CateGoods"
	import GoodsList from "./lib/GoodsList"
	import GoodsListV2 from './lib/GoodsListV2'
	import Menus from "./lib/Menus"
	import NewGoods from "./lib/NewGoods"
	import News from "./lib/News"
	import PictureCube from "./lib/PictureCube"
	import ReducePrice from "./lib/ReducePrice"
	import ReducePriceV2 from "./lib/ReducePriceV2"
	import SZBannerSearch from "./lib/SZBannerSearch"
	import SZCate from "./lib/SZCate"
	import SystemNoticeDialog from "./lib/SystemNoticeDialog"
	import UserInfoBox from "./lib/UserInfoBox"
	import OrderBox from './lib/OrderBox'
	import MenusBox from './lib/MenusBox'
	import BlockButton from './lib/BlockButton'
	import VipBanner from './lib/VipBanner'
	import MerchantBanner from './lib/MerchantBanner'
	import LogoutButton from './lib/LogoutButton'
	import CopyRight from './lib/CopyRight'
	import RedBag from './lib/RedBag'
	import FabMenu from './lib/FabMenu'

	import GoodsInfo from './lib/GoodsInfo'
	import LevelUp from './lib/LevelUp'
	import GoodsCombBar from './lib/GoodsCombBar'
	import MerchantInfo from './lib/MerchantInfo'
	import GoodsDetail from './lib/GoodsDetail'
	import BuyButton from './lib/BuyButton'

	import CategoryHeader from './lib/CategoryHeader'
	import CategoryChildList from './lib/CategoryChildList'
	import CategoryGoodsList from './lib/CategoryGoodsList'

	import ActivityDialog from './lib/ActivityDialog'
	import OfficialAccountAttention from './lib/OfficialAccountAttention'
	import BlankBox from './lib/BlankBox'
	import AuxiliarylLine from './lib/AuxiliarylLine'
	import RichText from './lib/RichText'

	import Category1 from './lib/Category1'
	import Category2 from './lib/Category2'

	import TitleBar from './lib/TitleBar'

	import PageFooter from "@/components/pageFooter/index.vue"
	import BackTop from "@/components/back-top/index.vue"


	export default {
		name: 'KssPage',
		components: {
			'status-bar': StatusBar,

			Ad,
			BannerSearch,
			CateGoods,
			GoodsList,
			GoodsListV2,
			Menus,
			NewGoods,
			News,
			PictureCube,
			ReducePrice,
			ReducePriceV2,
			SZBannerSearch,
			SZCate,
			SystemNoticeDialog,
			UserInfoBox,
			OrderBox,
			MenusBox,
			BlockButton,
			VipBanner,
			MerchantBanner,
			LogoutButton,
			CopyRight,
			RedBag,
			FabMenu,
			GoodsInfo,
			LevelUp,
			GoodsCombBar,
			MerchantInfo,
			GoodsDetail,
			BuyButton,
			CategoryHeader,
			CategoryChildList,
			CategoryGoodsList,
			ActivityDialog,
			OfficialAccountAttention,
			BlankBox,
			AuxiliarylLine,
			RichText,
			Category1,
			Category2,
			TitleBar,

			PageFooter,
			BackTop,
		},
		mixins: [page],
		props: {

		},
		data() {
			return {

			};
		},
		computed: {

		},
		mounted() {


		},
		methods: {

		}
	}
</script>

<style lang="scss" scoped scoped>
	.page {}

	.ysize {
		background-size: 100%;
	}

	.fullsize {
		background-size: 100% 100%;
	}

	.repeat {
		background-repeat: repeat;
	}

	.noRepeat {
		background-repeat: no-repeat;
	}

	.scroll-y {
		-webkit-overflow-scrolling: touch;
		padding-bottom: constant(safe-area-inset-bottom);
		/* 兼容 iOS < 11.2 */
		padding-bottom: env(safe-area-inset-bottom);
		/* 兼容 iOS >= 11.2 */
		height: calc(var(--vh) * 100 - 110rpx - var(--status-bar-height));
		/* #ifndef H5 */
		// 除了H5，计算高度都要减去状态栏高度+(10px 可多可少，根据实际情况定)
		height: calc(var(--vh) * 100 - 110rpx - calc(var(--status-bar-height) + 10px));
		/* #endif */
	}

	.page-comp-box {
		min-height: 100%;
	}
</style>