<template>
	<view>
		<u-popup v-model="popupShow" :custom-style="customStyle" mode="bottom" :z-index="100" safe-area-inset-bottom
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="false"
			@close="close" @open="open">
			<view class="popup-title">
				<view class="left">
					购物车<text class="count">(共{{goodsList.length || 0}}件商品)</text>
				</view>
				<view class="right" @click="handelEmpty">
					<u-icon name="trash" />
					清空
				</view>
			</view>
			<view class="roll-box">
				<scroll-view scroll-y="true" class="scroll-Y">
					<!-- 商品列表 -->
					<view class="goods-item" v-for="(item,index) in goodsList" :key="index">
						<view class="img-box">
							<u-image :src="item.goods.goods_img" width="200" height="200" border-radius="16">
								<view slot="error" class="error-img-box">
									<u-image :src="$util.img('/statics/diy/no-img.png')" width="100"
										height="100"></u-image>
								</view>
							</u-image>
						</view>
						<view class="right">
							<view class="top">
								<view class="goods-title line2">{{item.goods.goods_name}}</view>
								<view>
									<view class="goods-spec" v-if="item.goods_sku_id">
										<view class="spec-wrap">
											<view class="line1">
												{{item.goods.suk}}
											</view>
											<u-icon name="arrow-down" />
										</view>
									</view>
								</view>
								<view>
									<view class="order-tpl" v-if="item.batch_tpl && item.batch_tpl.length">
										<view class="tpl-wrap">
											<view class="line1">
												{{getTplStr(item)}}
											</view>
											<u-icon name="arrow-down" />
										</view>
									</view>
								</view>
							</view>
							<view class="bottom">
								<price-symbol :showOldPrice="false" :nowPrice="item.goods.goods_price"
									nowPriceColor="var(--view-theme)" />
								<NumberBox v-if="item.goods.num_type == 1" v-model="item.num"
									:startCount="item.goods.start_count" :endCount="item.goods.end_count"
									@minimum="handelRemoveGoods(item,index)"
									@change="stepQuantityChange(item,index,$event)" />
								<view class="acea-row" style="flex:1;flex-wrap: nowrap;white-space: nowrap;"
									v-else-if="item.goods.num_type == 2">
									<view @click="chooseNum(item)"
										style="display:flex;flex:0%;justify-content: flex-end;">
										<text style="margin-right: 10rpx;">x {{item.num}}</text>
										<u-icon name="arrow-right" color="#ccc"></u-icon>
									</view>
								</view>
							</view>
						</view>
					</view>
				</scroll-view>
			</view>
		</u-popup>
		<u-select v-model="showNumPicker" mode="single-column" :default-value="[currNumIndex]" :list="numList"
			safe-area-inset-bottom @confirm="selectQuantityChange"></u-select>
	</view>
</template>

<script>
	import PriceSymbol from '@/components/price-symbol'
	import NumberBox from '../JoinCartButton/NumberBox'
	import {
		mapActions
	} from 'vuex'
	import _ from 'lodash'

	export default {
		components: {
			'price-symbol': PriceSymbol,
			NumberBox
		},
		props: {
			value: {
				type: Boolean,
				default: false,
			}
		},
		data() {
			return {
				goodsList: [],

				currCartGoods: null,
				showNumPicker: false,
				numList: [],
			};
		},
		computed: {
			customStyle() {
				const re = {}
				re.bottom = '110rpx'
				return re
			},
			popupShow: {
				get() {
					return this.value
				},
				set(val) {
					this.$emit('input', val)
				}
			},
			currNumIndex() {
				if (this.currCartGoods) {
					return this.numList.findIndex(item => item.value === this.currCartGoods.num)
				} else {
					return 0
				}
			},
		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			...mapActions(['updateCartGoodsNum', 'updateCartAmountMoney']),
			close() {
				this.currCartGoods = null
				this.showNumPicker = false
				this.numList = []
			},
			open() {
				this.fetchData()
			},
			async fetchData() {
				const data = await this.$u.api.goodsCart({
					only_goods: 1
				})
				this.goodsList = data
			},
			async handelEmpty() {
				const ids = this.goodsList.map(item => item.id)
				await this.$u.api.goodsCartDelete({
					ids
				})
				await this.updateCartGoodsNum()
				await this.updateCartAmountMoney()
				this.$util.msg('操作成功')
				this.popupShow = false
			},
			async handelRemoveGoods(row, index) {
				await this.$u.api.goodsCartDelete({
					ids: row.id
				})
				this.goodsList.splice(index, 1)
				await this.updateCartGoodsNum()
				await this.updateCartAmountMoney()
				this.$util.msg('操作成功')
			},
			chooseNum(cartGoods) {
				this.currCartGoods = cartGoods
				const {
					num_count
				} = cartGoods.goods
				this.numList = this.parseNumCount(num_count)
				this.showNumPicker = !this.showNumPicker
			},
			parseNumCount(str) {
				let arr = str.split(',')
				let re = []

				arr.forEach(item => {
					if (item.indexOf('-') != -1) {
						let tmp = item.split('-')
						for (let i = tmp[0]; i <= tmp[1]; i++) {
							re.push({
								value: Number(i),
								label: i
							})
						}
					} else {
						re.push({
							value: Number(item),
							label: item
						})
					}
				})
				return re
			},
			async selectQuantityChange(e) {
				this.currCartGoods.num = e[0].value
				await this.$u.api.goodsCartNum({
					id: this.currCartGoods.id,
					num: e[0].value
				})
				await this.updateCartGoodsNum()
				await this.updateCartAmountMoney()
				this.$util.msg('操作成功')
			},
			stepQuantityChange: _.throttle(async function(row, index, e) {
				await this.$u.api.goodsCartNum({
					id: row.id,
					num: e
				})
				await this.updateCartGoodsNum()
				await this.updateCartAmountMoney()
				this.$util.msg('操作成功')
			}, 1000),
			getTplStr(row) {
				const batch_tpl = row.batch_tpl
				const attach = row.goods.attach
				const re = []


				batch_tpl.forEach(item => {
					let tmp = {}
					for (let key in item) {
						tmp.value = item[key]
						attach.forEach(item2 => {
							if (item2.key === key)
								tmp.label = item2.name
						})
					}
					re.push(`${tmp.label}:${tmp.value}`)
				})
				return re.join(',')
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		margin-bottom: 32rpx;
		align-items: center;
		justify-content: space-between;
		display: flex;
		flex-wrap: wrap;
		padding: 40rpx 32rpx 0;

		.left {
			font-size: 32rpx;
			color: #333;
			font-weight: 500;

			.count {
				padding-left: 8rpx;
				color: #999;
				font-size: 12px;
			}
		}

		.right {
			font-size: 24rpx;
			color: #666;
			display: flex;
			flex-wrap: wrap;
			align-items: baseline;
			gap: 8rpx;
		}
	}

	.roll-box {
		display: flex;
		flex-direction: column;
		margin-top: 36rpx;
		padding: 0 32rpx 0;

		.scroll-Y {
			max-height: 800rpx;
			margin-bottom: 146rpx;

			.goods-item {
				margin-bottom: 16px;
				display: flex;

				.img-box {
					width: 100px;
					height: 100px;
					border-radius: 8px;
					position: relative;
					overflow: hidden;
				}

				.right {
					display: flex;
					flex-direction: column;
					margin-left: 10px;
					justify-content: space-between;
					flex: 1;
					overflow: hidden;

					.top {
						width: 100%;

						.goods-title {
							color: #333;
							line-height: 20px;
							font-size: 14px;
						}

						.goods-spec,
						.order-tpl {
							max-width: 230px;
							font-size: 11px;
							padding: 0 6px;
							margin-top: 6px;
							color: #999;
							height: 19px;
							text-align: center;
							line-height: 19px;
							border-radius: 10px;
							background-color: #f5f5f5;
							display: inline-block;

							.spec-wrap,
							.tpl-wrap {
								display: flex;

								.line1 {
									margin-right: 6px;
								}
							}
						}
					}

					.bottom {
						display: flex;
						justify-content: space-between;
						align-items: center;
						margin-top: 10px;
					}
				}
			}
		}
	}
</style>