<template>
	<view class="spec-box">
		<view class="spec-list" v-for="item,index in specKey" :key="index">
			<span class="attr-name">{{ item.attr_name }}：</span>
			<view class="radio-list">
				<view class="radio-item " :class="{checked:selectedIndex[index] == index2,'radio-img-item':item.t == 2}"
					@click="handelClick(index,index2)" v-for="item2,index2 in item.attr_values" :key="index2">
					<template v-if="item.t == 1">
						<div class="name">{{item2.name}}</div>
					</template>
					<template v-else-if="item.t == 2">
						<div class="img">
							<u-image width="60rpx" height="60rpx" border-radius="10rpx" :src="item2.img"></u-image>
							<div class="txt line1">{{item2.name}}</div>
						</div>
					</template>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			specKey: {
				type: Array,
				default: () => {
					return []
				}
			},
			specValue: {
				type: Object,
				default: () => {
					return {}
				}
			},
			// 选中的商品规格值，不是商品规格键的值
			selectedSpecValue: {
				type: Object,
				default: () => {
					return {}
				}
			},
		},
		data() {
			return {
				selectedIndex: [],
			};
		},
		computed: {
			currSpecValue() {
				return this.getSpecValue()
			},
		},
		watch: {
			specKey: {
				handler(nv) {
					if (this.selectedSpecValue.suk) {
						let arr = this.selectedSpecValue.suk.split(',')
						// let arr = ['d','g']
						arr.forEach((item, index) => {
							let idx = this.specKey[index].attr_values.findIndex(attr => attr.name == item)
							if (idx != -1) {
								this.selectedIndex[index] = idx
							} else {
								this.selectedIndex[index] = 0
							}
						})
					} else {
						this.selectedIndex = nv.map(() => {
							return 0
						})
					}
					this.$emit('change', this.getSpecValue())
				},
				immediate: true,
			},
		},
		created() {

		},
		mounted() {

		},
		methods: {
			preview(url) {
				uni.previewImage({
					urls: [url],
					current: url,
				})
			},
			handelClick(index, index2) {
				this.$set(this.selectedIndex, index, index2)
				this.$emit('change', this.getSpecValue())
			},
			// 获取规格键
			getSpecKey() {
				let arr = []
				this.selectedIndex.forEach((item, index) => {
					if (item == -1) arr.push('')
					else arr.push(this.specKey[index].attr_values[item].name)
				})
				return arr
			},
			// 获取规格值
			getSpecValue() {
				let arr = this.getSpecKey()
				if (arr.join(',') in this.specValue)
					return this.specValue[arr.join(',')]
				else
					return {}
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.spec-box {
		display: flex;
		flex-direction: column;
		gap: 20rpx;
		margin-top: 36rpx;
		padding: 0 30rpx;

		.curr-spec {
			display: flex;
			align-items: flex-start;
			border-bottom: 1rpx solid #ccc;
			gap: 10rpx;
			padding-bottom: 20rpx;

			.img {
				position: relative;

				.icon {
					position: absolute;
					right: 5px;
					top: 5px;
					width: 20px;
					height: 20px;
					line-height: 20px;
					background-color: rgba(0, 0, 0, 0.4);
					border-radius: 2px;
					text-align: center;
					color: #fff;
					cursor: pointer;
				}
			}

			.goods-info {
				.goods-price {
					color: red;

					.symbol {
						font-size: 24rpx;
						font-weight: bold;
						margin-right: 3px;
					}

					.num {
						font-size: 40rpx;
						font-weight: bold;
					}
				}
			}
		}

		.spec-list {
			display: flex;
			flex-direction: column;
			gap: 10rpx;

			.attr-name {
				font-size: 28rpx;
				color: #333333;
			}
		}
	}

	.radio-list {
		display: flex;
		align-items: center;
		flex-wrap: wrap;
		gap: 20rpx;
		flex: 1;

		.radio-item {
			border: 2rpx solid #d3d3d3;
			font-size: 24rpx;
			position: relative;
			border-radius: 10rpx;
			cursor: pointer;
			user-select: none;
			display: flex;
			align-items: center;
			white-space: nowrap;

			.name {
				border: 1rpx solid rgba(0, 0, 0, 0);
				cursor: pointer;
				padding: 8rpx 20rpx;
			}

			.img {
				border: 1rpx solid rgba(0, 0, 0, 0);
				border-radius: 6rpx;
				font-size: 24rpx;
				position: relative;
				cursor: pointer;
				user-select: none;
				display: flex;
				align-items: center;
				justify-content: center;
				overflow: hidden;
				gap: 10rpx;
			}
		}

		.radio-img-item {
			padding: 4rpx;
			background-color: #F7F8FA;
			min-width: 200rpx;
		}

		.checked {
			border: 1px solid var(--view-theme, #ee0a24);
			color: var(--view-theme, #ee0a24);
			background-color: #fff;
		}
	}
</style>