<template>
	<view>
		<template v-if="regBagData.status == 1">
			<!-- money:金额  rbagmodelshow:红包弹框是否显示 options:红包参数设置 @onOpenRedBag:打开红包弹框事件 @onOpen：打开红包事件 @onConfirm：确认收款事件 -->
			<cc-red-bag :money="moneyStr" :rbagmodelshow="isShowModel" :options="redBagConfig" :btnOtion="btnOtion"
				:animate="animate" :animateStyle="animateStyle" @onOpenRedBag="onOpenRedBag" @onOpen="onOpen"
				@onConfirm="onConfirm"></cc-red-bag>
		</template>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	import CcRedBag from '@/components/cc-red-bag'

	export default {
		name: 'RedBag',
		components: {
			'cc-red-bag': CcRedBag
		},
		mixins: [CompMixin],
		data() {
			return {
				regBagData: {},

				moneyStr: '',
				isShowModel: false,
				redBagConfig: {
					userImg: '', //用户头像
					userName: '', //用户名称
					money: 0, //红包金额
					coverTitle: '恭喜发财', //红包封面标题
					openTitle: '恭喜您获得', //打开红包后的标题文本
					openTips: '已存入钱包，可直接体现', //打开红包后的提示文本
					btnText: "查看我的钱包", //打开红包后的按钮文本
				}
			};
		},
		computed: {
			animate() {
				const list = this.getAttr('animation.list', [])
				const activeValue = this.getAttr('animation.activeValue', '')

				const animation = list.find(
					(item) => item.value == activeValue
				)
				console.log(activeValue)
				if (!animation) return ''

				let value = animation.value
				let re = ''
				switch (value) {
					case 1:
						re = 'donghua1'
						break
					case 2:
						re = 'donghua2'
						break
					case 3:
						re = 'donghua3'
						break
				}
				return re
			},
			animateStyle() {
				const re = {
					zIndex: this.getAttr('zIndex.val', 0),
				}
				if (this.getAttr('left.val'))
					re.left = `${this.getAttr('left.val') * 2}rpx`
				if (this.getAttr('top.val'))
					re.top = `${this.getAttr('top.val') * 2}rpx`
				if (this.getAttr('right.val'))
					re.right = `${this.getAttr('right.val') * 2}rpx`
				if (this.getAttr('bottom.val'))
					re.bottom = `${this.getAttr('bottom.val') * 2}rpx`

				return re
			},
			btnOtion() {
				const re = {
					src: this.getAttr('imgConfig.url', ''),
					width: this.getAttr('width.val', 0),
					height: this.getAttr('height.val', 0),
				}

				return re
			},
		},
		mounted() {
			this.fetchData()
		},
		methods: {
			async fetchData() {
				const res = await this.$u.api.getRedPacket()
				this.regBagData = {
					...res
				}
				if (res.status == 1) {
					this.redBagConfig.userImg = res.img
					this.redBagConfig.userName = res.title
					this.redBagConfig.coverTitle = res.desc
				}
			},
			//  打开红包弹框
			onOpenRedBag() {
				this.isShowModel = true
			},
			// 获取可领红包
			async sendRedPacket() {
				const {
					price
				} = await this.$u.api.sendRedPacket({
					id: this.regBagData.id
				})
				this.moneyStr = price
				this.redBagConfig.money = price
			},

			// 生成0-100随机金额 并保留两位小数
			createRandom() {
				// 生成0-100随机小数
				var min = 0;
				var max = 100;
				return (min + Math.random() * (max - min)).toFixed(2) + '';
			},
			// 打开红包
			onOpen() {
				this.$u.throttle(this.sendRedPacket, 500)
			},

			// 点击确认收款按钮事件
			onConfirm(e) {
				this.fetchData()
				console.log("点击确认收款按钮事件");
				this.$util.on('/pages/ucenter_sub/moneylist')
			},
		}
	};
</script>

