<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compContentStyle2]">
			<view class="category-goods-list">
				<view class="category-wrap">
					<view class="goods-filter">
						<view class="filter-item" :class="{on:activeFilter == index}" v-for="(item,index) in filterList"
							:key="index" @click="filterClick(item,index)">
							<view class="filter-item-title">
								<view>{{item.label}}</view>
								<view class="sort-icon" v-if="item.type == 1">
									<u-icon :name="item.index == 1?'arrow-up':'arrow-down'" />
								</view>
							</view>
						</view>
					</view>
					<view class="category-box" v-if="categoryList.length > 1">
						<view class="category-item" :class="{on:item.id ==categoryData.id}"
							v-for="(item,index) in categoryList" :key="index" @click="change(item)">{{item.name}}</view>
					</view>
				</view>
				<template v-if="listStyle == 0">
					<view class="goods-list" v-if="goodsList.length">
						<view class="goods-item" v-for="item,index in goodsList" :key="index"
							@click="$util.on(`pages/goods/detail?id=${item.id}`)">
							<u-image mode="widthFix" :src="img(item.goods_img)" width="180" height="180"
								:border-radius="20" />
							<view class="info">
								<view class="name line2">{{item.goods_name}}</view>
								<view class="uid">
									商品编号：
									<span>{{item.id}}</span>
								</view>
								<view class="fun">
									<view class="money" style="position: relative;">
										<view class="now-money">
											<span class="symbol">￥</span>
											<span class="num">{{item.goods_price}}</span>
										</view>
										<view class="old-money">
											<span class="symbol">￥</span>
											<span class="num">{{item.face_value}}</span>
										</view> 
									</view>
									<BuyButton :goods-type="item.goods_type" size="small" :status="item.status"
										:stock-num="item.stock_num" />
								</view>
							
								<view class="">
									<MinLevelPrice :price1="item.goods_price" :price2="item.min_level_price" :type="5" />
								</view>
							</view>
						</view>
					</view>
				</template>
				<template v-else-if="listStyle == 1">
					<view class="goods-list2" v-if="goodsList.length">
						<view class="goods-item" v-for="item,index in goodsList" :key="index"
							@click="$util.on(`pages/goods/detail?id=${item.id}`)">
							<u-image mode="widthFix" :src="img(item.goods_img)" width="100%" height="345"
								border-radius="20rpx 20rpx 0 0" />
							<view class="name line1">{{item.goods_name}}</view>
							<view class="price-box">
								<view class="old-money">
									<span class="symbol">￥</span>
									<span class="num">{{item.face_value}}</span>
								</view>
								<view class="now-money">
									<span class="symbol">￥</span>
									<span class="num">{{item.goods_price}}</span>
								</view>
							</view>
							<view class="goods-id">
								<view class="tag">{{item.goods_type_text}}</view>
								<view>商品编号:{{item.id}}</view>
							</view>
							
								<MinLevelPrice :price1="item.goods_price" :price2="item.min_level_price" :type="6" />
							
						</view>
					</view>
				</template>
				<u-empty text="暂无数据" mode="list" v-if="!goodsList.length"></u-empty>
				<u-loadmore :status="loading" icon-type="circle" @loadmore="loadMoreData" v-show="goodsList.length"
					bg-color="#F5F7FA" />
			</view>
		</view>
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'
	import _ from 'lodash'

	export default {
		components: {

		},
		name: 'CategoryGoodsList',
		props: {

		},
		mixins: [CompMixin],
		inject: ['getListStyle', 'setSortType', 'getCategoryData', 'categoryChange', 'getGoodsList', 'filterChange',
			'getLoading', 'loadMoreData'
		],
		data() {
			return {
				filterList: [{
					label: '默认',
					type: 0
				}, {
					label: '新品排序',
					value: 2,
					type: 0
				}, {
					label: '价格排序',
					type: 1,
					value: [3, 4],
					index: 0,
				}, {
					label: '销量排序',
					type: 1,
					value: [5, 6],
					index: 0,
				}],
				activeFilter: 0,
			};
		},
		computed: {
			categoryList() {
				const arr = _.cloneDeep(this.getCategoryData())
				let list = []
				if (arr[1] && arr[1].children) {
					list = arr[1].children
					list.unshift({
						name: '全部'
					})
				}
				return list
			},
			categoryData() {
				const arr = this.getCategoryData()
				return arr[2] || {}
			},
			goodsList() {
				return this.getGoodsList()
			},
			loading() {
				return this.getLoading()
			},
			listStyle() {
				return this.getListStyle()
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {},
			change(item) {
				if (item.id == this.categoryData.id)
					return
				this.categoryChange(item, 2)
			},
			filterClick(item, index) {
				if (item.type == 1) {
					this.activeFilter = index
					item.index = Math.abs(item.index - 1)
					// 请求加载商品列表
					this.filterChange(this.getSortType())
				} else {
					if (index == this.activeFilter) {
						return
					} else {
						// 请求加载商品列表
						this.activeFilter = index
						this.filterChange(this.getSortType())
					}
				}
			},
			getSortType() {
				const item = this.filterList[this.activeFilter]
				if (item.type == 1) {
					return item.value[item.index]
				} else {
					return item.value
				}
			},
		}
	}
</script>
<style lang="scss" scoped scoped>
	.category-goods-list {
		display: flex;
		flex-direction: column;

		.category-wrap {
			width: 100%;
			background-color: #fff;
			display: flex;
			flex-direction: column;
			gap: 20rpx;
			padding: 20rpx 0;
			border-radius: 10rpx 10rpx 0 0;
		}

		.goods-filter {
			width: 100%;
			display: flex;
			align-items: center;
			justify-content: space-between;
			padding: 0 20rpx;

			.filter-item {
				display: flex;
				align-items: center;
				gap: 8rpx;
				color: #aaa;

				.filter-item-title {
					display: flex;
					align-items: center;
					justify-content: center;

					.sort-icon {
						margin-left: 6rpx;
					}
				}
			}

			.on {
				color: #f84d43;
			}
		}

		.category-box {
			width: 100%;
			overflow-x: auto;
			white-space: nowrap;
			padding: 0 20rpx;

			.category-item {
				display: inline-block;
				padding: 10rpx 20rpx;
				color: #fff;
				border-radius: 10rpx;
				background-color: #9b9fa8;

				&+.category-item {
					margin-left: 20rpx;
				}
			}

			.on {
				color: #fff;
				background-color: #ff5f01;
			}
		}

		.goods-list {
			display: flex;
			flex-direction: column;
			gap: 12rpx;
			background-color: rgba(245, 247, 250, 1);

			.goods-item {
				display: flex;
				gap: 20rpx;
				background-color: #fff;
				padding: 20rpx;
				border-radius: 20rpx;

				&:first-child {
					border-top-left-radius: 0;
					border-top-right-radius: 0;
				}

				.info {
					flex: 1;
					display: flex;
					flex-direction: column;
					align-items: flex-start;
					justify-content: center;
					padding: 8rpx 0;
					overflow: hidden;

					.name {
						flex: 1;
						color: #191e2e;
						font-weight: 600;
						font-size: 28rpx;
						flex-shrink: 0;
					}

					.uid {
						font-size: 24rpx;
					}

					.fun {
						display: flex;
						width: 100%;
						justify-content: space-between;

						.money {
							display: flex;
							align-items: baseline;

							.now-money {
								font-weight: 700;
								color: #f84d43;

								.symbol {
									font-size: 24rpx;
								}

								.num {
									font-size: 36rpx;
								}
							}

							.old-money {
								font-weight: 400;
								color: #d2d5dd;
								text-decoration: line-through;
								margin-left: 20rpx;

								.symbol {
									font-size: 24rpx;
								}

								.num {
									font-size: 24rpx;
								}
							}
						}

						.btn-buy {
							width: 124rpx;
							height: 50rpx;
							border-radius: 6rpx;
							font-size: 24rpx;
							padding: 0;
						}

						.btn-orage {
							line-height: 50rpx;
							background-color: #fd4d20;
							border-radius: 6rpx;
						}
					}
				}
			}
		}

		.goods-list2 {
			display: flex;
			flex-wrap: wrap;
			gap: 18rpx;
			background-color: #f5f7fa;
			padding: 10rpx 16rpx;

			.goods-item {
				width: calc(50% - 10rpx);
				background-color: #fff;
				border-radius: 20rpx;
				display: flex;
				flex-direction: column;
				gap: 10rpx;
				padding-bottom: 20rpx;

				.name {
					padding: 20rpx;
					width: 100%;
					font-weight: 600;
					font-size: 28rpx;
				}

				.price-box {
					display: flex;
					justify-content: space-between;
					padding: 0 20rpx;
					align-items: center;

					.now-money {
						font-weight: 700;
						color: #f84d43;

						.symbol {
							font-size: 24rpx;
						}

						.num {
							font-size: 36rpx;
						}
					}

					.old-money {
						font-weight: 400;
						color: #d2d5dd;
						text-decoration: line-through;
						margin-left: 20rpx;

						.symbol {
							font-size: 24rpx;
						}

						.num {
							font-size: 24rpx;
						}
					}
				}

				.goods-id {
					padding: 0 20rpx;
					color: #9b9fa8;
					font-size: 20rpx;
					display: flex;
					align-items: center;
					justify-content: space-between;

					.tag {
						display: flex;
						align-items: center;
						justify-content: center;
						font-size: 18rpx;
						color: #fff;
						background-color: #1890ff;
						height: 30rpx;
						padding: 0 10rpx;
						box-sizing: border-box;
						border-radius: 5rpx;
					}
				}
			}
		}
	}
</style>