<template>
	<u-popup v-model="showLayer" mode="center" :closeable="false" border-radius="10" :z-index="1000" width="600rpx">
		<view v-if="styleConfig == 0" class="style1">
			<view class="content-box"
				:style="{backgroundImage:`url(${$util.img('/statics/uni/img/index/home_mark_bg.png')})`}">
				<view class="box-wrap" :style="[compStyle]">
					<view class="title">{{ inputConfig }}</view>
					<view class="content">
						<scroll-view :scroll-y="true" class="html-box" show-scrollbar>
							<u-parse :html="richText"></u-parse>
						</scroll-view>
					</view>
					<view class="bottom">
						<u-button :ripple="true" ripple-bg-color="#fa5a4b" :custom-style="customStyle"
							@click="closeHandle">知道了</u-button>
					</view>
				</view>
			</view>
		</view>
	</u-popup>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	export default {
		name: 'SystemNoticeDialog',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				showLayer: false,
				customStyle: {
					'background-image': 'linear-gradient(90deg, #fa5a4b, #ff9b7a)',
					'border-color': '#fa5a4b',
					'background-color': '#fa5a4b',
					'color': '#fff',
					'display': 'inline-block',
					'border-radius': '40rpx',
					'width': '300rpx',
				},
			}
		},
		options: {
			styleIsolation: 'shared'
		},
		computed: {
			styleConfig() {
				return this.getAttr('styleConfig.tabVal', 0)
			},
			inputConfig() {
				return this.getAttr('inputConfig.value', '')
			},
			richText() {
				let rich_text = this.$util.replaceImg(this.getAttr('richText.val'))
				return rich_text
			},
			md5() {
				return this.getAttr('richText.md5')
			},
			showConfig() {
				return !this.getAttr('showConfig.tabVal', 0) ? true : false
			},
			closeConfig() {
				return this.getAttr('closeConfig.tabVal', 0)
			},
		},
		watch: {
			showConfig: {
				handler(nv) {
					this.showLayer = nv
				},
				immediate: false
			}
		},
		mounted() {
			this.init()
		},
		methods: {
			init() {
				if (this.showConfig) {
					if (this.closeConfig === 0) {
						const data = this.getCacheData(this.md5)
						if (!data) {
							this.showLayer = true
						} else {
							if (!this.isIn24Hours(data.crate_date)) {
								this.showLayer = true
							}
						}
					} else if (this.closeConfig === 1) {

						this.showLayer = this.showConfig
					}
				}
			},
			getCacheData(md5) {
				const arr = uni.getStorageSync('system-notice-dialog-cache')
				if (arr && Array.isArray(arr)) {
					return arr.find(item => item.md5 == md5)
				}
			},
			setCacheData(md5, value) {
				let arr = uni.getStorageSync('system-notice-dialog-cache')
				if (!arr)
					arr = []

				if (Array.isArray(arr)) {
					let find = arr.findIndex(item => item.md5 === md5)
					if (find != -1) {
						arr.splice(find, 1, value)
					} else {
						arr.push(value)
					}
					// 清理不在24小时内数据
					const new_arr = arr.filter(item => {
						if (this.isIn24Hours(item.crate_date)) {
							return item
						}
					})
					uni.setStorageSync('system-notice-dialog-cache', new_arr)
				}
			},
			isIn24Hours(time) {
				let t = Date.now() - time
				if (t >= 0 && t <= 24 * 3600 * 1000)
					return true
				else
					return false
			},
			closeHandle() {
				if (this.closeConfig === 0)
					this.setCacheData(this.md5, {
						md5: this.md5,
						crate_date: Date.now()
					})

				setTimeout(() => {
					this.showLayer = false
				}, 500)
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.u-mode-center-box {
			background-color: transparent !important;
		}
	}

	/*滚动条整体粗细样式*/
	::-webkit-scrollbar {
		/*高宽分别对应横竖滚动条的尺寸*/
		width: 8px;
		height: 8px;
	}

	/*滚动条里面小方块*/
	::-webkit-scrollbar-thumb {
		border-radius: 10px !important;
		box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.2) !important;
		/* 颜色 */
		background: #b6b6b6 !important;
		/* 线性渐变背景 */
		background-image: linear-gradient(45deg,
				#ffbd61 25%,
				#ffbd61 25%,
				#ff8800 25%,
				#ff8800 50%,
				#ffbd61 50%,
				#ffbd61 75%,
				#ff8800 75%,
				#ff8800 100%) !important;
	}

	/*滚动条轨道*/
	::-webkit-scrollbar-track {
		border-radius: 10px !important;
		box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.2) !important;
		background: #ededed !important;
	}

	.style1 {


		.content-box {
			background-repeat: no-repeat;
			background-position: 0 0;
			background-size: 100% auto;
			height: 1000rpx;
			padding-top: 180rpx;
			overflow: hidden;

			.box-wrap {
				display: flex;
				flex-direction: column;
				border-bottom-left-radius: 20rpx;
				border-bottom-right-radius: 20rpx;
				height: 100%;
				width: 100%;

				.title {
					text-align: center;
					font-weight: 700;
					margin-bottom: 20rpx;
				}

				.content {
					flex: 1;
					padding: 0 20rpx;
					overflow-y: auto;

					.html-box {
						height: 100%;
					}
				}

				.bottom {
					padding: 20px 0;
					text-align: center;
				}
			}
		}
	}
</style>