<template>
	<view class="number-box">
		<view class="reduce-item" @click="decrease">
			<u-icon name='minus' />
		</view>
		<view class="text-item">{{count}}</view>
		<view class="add-item">
			<u-icon name='plus' @click="increase" />
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			// 购物车数量
			value: {
				type: Number,
				default: 0,
			},
			startCount: {
				type: Number,
				default: 0
			},
			endCount: {
				type: Number,
				default: 100
			},
			step: {
				type: Number,
				default: 1
			}
		},
		computed: {
			count: {
				get() {
					return this.value
				},
				set(val) {
					this.$emit('input', val)
				},
			}
		},
		methods: {
			decrease() {
				const new_val = this.count - this.step
				if (new_val < this.startCount) {
					this.$emit('minimum')
					return
				}
				this.count = this.count - this.step
				this.$emit('change', new_val)
			},
			increase() {
				const new_val = this.count + this.step
				if (new_val > this.endCount) {
					this.$emit('maximum')
					this.$util.msg(`最大购买数量为${this.endCount}`)
					return
				}
				this.count = this.count + this.step
				this.$emit('change', new_val)
			}
		},
	}
</script>

<style scoped lang="scss" scoped>
	.number-box {
		display: flex;
		align-items: center;

		.reduce-item {
			width: 48rpx;
			height: 48rpx;
			color: #333;
			border-radius: 30rpx;
			background-color: #f5f5f5;
			display: flex;
			justify-content: center;
			align-items: center;
		}

		.text-item {
			padding: 0 20rpx;
			color: #333;
			font-size: 30rpx;
		}

		.add-item {
			width: 48rpx;
			height: 48rpx;
			color: #fff;
			border-radius: 30rpx;
			background-color: var(--view-theme);
			display: flex;
			justify-content: center;
			align-items: center;
		}
	}
</style>