<template>
	<view class="btn-group" :class="[btnGroupSize]">
		<template v-if="goodsStatus == 2">
			<view class="btn-item pause-item all-circle">
				暂停销售</view>
		</template>
		<template v-else-if="!goodsStockNum">
			<view class="btn-item sellout-item all-circle">已售罄</view>
		</template>
		<template v-else>
			<view class="btn-item cart-item" v-if="showCartButton && sysconfig.addon && sysconfig.addon.goodsentity"
				@click="joinCart">
				加入购物车
			</view>
			<view class="btn-item buy-item" :class="{ 'all-circle': showCartButton === false }" @click="doBuy">
				立即购买
			</view>
		</template>
	</view>
</template>

<script>
	import {
		mapGetters
	} from 'vuex'
	export default {
		components: {

		},
		props: {
			// 
			size: {
				type: String,
				default: 'normal'
			},
			// 是否显示购物车按钮
			showCartButton: {
				type: Boolean,
				default: true,
				required: true,
			},
			// 商品状态
			goodsStatus: {
				type: Number,
				default: 0,
				required: true,
			},
			// 商品库存
			goodsStockNum: {
				type: Number,
				default: 0,
				required: true,
			}
		},
		data() {
			return {

			}
		},
		computed: {
			...mapGetters(['sysconfig']),
			btnGroupSize() {
				if (this.size == '' || this.size == 'normal')
					return ''
				else
					return `btn-group-size-${this.size}`
			},
		},
		methods: {
			joinCart() {
				this.$emit('joinCart')
			},
			doBuy() {
				this.$emit('doBuy')
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	// 定义scss变量
	$border-radius: 52rpx;
	$small-border-radius: 25rpx;

	@mixin btn-group($size: normal) {
		display: flex;
		flex-wrap: nowrap;
		align-items: center;
		font-size: 28rpx;

		@if $size ==small {
			font-size: 24rpx;

			.btn-item {
				height: 58rpx;
				width: 180rpx;
			}
		}

		// @else if $size ==large {
		// 	padding: 15px 30px;
		// 	font-size: 18px;
		// }
	}

	.btn-group {
		@include btn-group(normal);

		.btn-item {
			cursor: pointer;
			display: flex;
			align-items: center;
			justify-content: center;
			height: 78rpx;
			width: 230rpx;
			color: #fff;
		}

		.cart-item {
			border-radius: $border-radius 0 0 $border-radius;
			background-image: linear-gradient(90deg, #fdba00, #ffaa00);
		}

		.buy-item {
			border-radius: 0 $border-radius $border-radius 0;
			background-image: linear-gradient(90deg, #fe8a56, #ff504b);
		}

		.pause-item,
		.sellout-item {
			color: #909399;
			border-radius: 0 $border-radius $border-radius 0;
			background: #dfdfdf;
			width: 50%;
			border: 1px solid #dfdfdf;
		}

		.all-circle {
			border-radius: $border-radius;
			width: 100%;
		}
	}

	.btn-group-size-small {
		@include btn-group(small);
	}
</style>