<template>
	<view :style="[compStyle]" v-if="goodsList && goodsList.length>0">
		<view class="goods-box">
			<view class="hd">
				<view class="title">{{ titleTxtConfig }}</view>
				<view v-if="rightBtnConfig" class="right" @click="$kss.JumpPath(linkConfig)">
					{{rightTextConfig}}<text class="iconfont icon-jinrujiantou"></text>
				</view>
			</view>
			<view class="scroll-box">
				<scroll-view class="scroll-view_H goods-list" :scroll-x="true" :scroll-left="scrollLeft"
					@scroll="onScroll" @touchstart="onTouchStart" @touchend="onTouchEnd" @touchcancel="onTouchCancel"
					@scrolltoupper="onUpper" @scrolltolower="onLower">
					<view v-for="(item, index) in goodsList" :key="index" class="goods-item"
						:style="{ borderRadius: itemRadius }" @click="itemClick(item)">
						<u-image :src="item.goods_img" :border-radius="goodsItemRadius" height="164rpx" width="164rpx"
							mode="aspectFit" />
						<view class="info">
							<view v-if="checkboxInfo.includes(0)" class="name line1">
								{{ item.goods_name }}
							</view>
							<view v-if="checkboxInfo.includes(1)" class="price-box">
								<text class="t1">最新</text>
								<view class="price">
									<text>￥</text>
									<text>{{ item.price }}</text>
								</view>
							</view>
						</view>
						<view class="bom-btn">
							<text class="iconfont icon-31jiangjia"></text>
							<view class="price">
								<text>￥</text>
								<text>{{ item.pricecha }}</text>
							</view>
						</view>
					</view>
				</scroll-view>
			</view>
		</view>
	</view>
</template>

<script>
	import CompMixin from '../mixins/comp.js'
	import _ from 'lodash'

	export default {
		components: {

		},
		name: 'ReducePrice',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				goodsList: [],

				scrollLeft: 0,
				isDragging: false,
				scrollTimer: null,
				direction: 'right',
				lastScrollLeft: 0
			};
		},
		computed: {
			newsStyle() {
				return {
					padding: `${this.dataConfig.topConfig.val * 2}rpx ${this.dataConfig.prConfig.val * 2}rpx ${this.dataConfig.bottomConfig.val * 2}rpx`,
					marginTop: `${this.dataConfig.mtConfig.val * 2}rpx`,
					background: this.dataConfig.bgColor.color[0].item,
				}
			},
			titleTxtConfig() {
				return this.dataConfig.titleTxtConfig.value
			},
			rightBtnConfig() {
				return !this.dataConfig.rightBtnConfig.tabVal ? true : false
			},
			rightTextConfig() {
				return this.dataConfig.rightTextConfig.value
			},
			linkConfig() {
				return this.dataConfig.linkConfig.value
			},
			goodsItemRadius() {
				const {
					goodsItemRadius
				} = this.dataConfig
				return goodsItemRadius.type ?
					`${goodsItemRadius.valList[0].val * 2}rpx ${goodsItemRadius.valList[1].val*2}rpx ${goodsItemRadius.valList[2].val*2}rpx ${goodsItemRadius.valList[3].val*2}rpx` :
					`${goodsItemRadius.val*2}rpx`
			},
			// 商品容器圆角
			itemRadius() {
				const {
					radius
				} = this.dataConfig
				return radius.type ?
					`${radius.valList[0].val * 2}rpx ${radius.valList[1].val*2}rpx ${radius.valList[2].val*2}rpx ${radius.valList[3].val*2}rpx` :
					`${radius.val*2}rpx`
			},
			//
			checkboxInfo() {
				const {
					checkboxInfo
				} = this.dataConfig
				return checkboxInfo.type
			}
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		beforeUnmount() {
			this.stopAutoScroll();
		},
		methods: {
			async init() {
				this.goodsList = await this.$u.api.getDiyDownPrice({
					limit: this.getAttr('numberConfig.val', 10)
				})

				this.startAutoScroll()
			},
			itemClick(row) {
				this.$kss.JumpPath(`/pages/goods/detail?id=${row.goods_id}`)
			},
			startAutoScroll() {
				this.scrollTimer = setInterval(() => {
					if (!this.isDragging) {
						if (this.direction == 'right') {
							this.scrollLeft += 1
						} else if (this.direction == 'left') {
							this.scrollLeft -= 1
						}
					}
				}, 50)
			},
			stopAutoScroll() {
				clearInterval(this.scrollTimer)
			},
			onScroll(e) {
				if (this.isDragging) {
					this.scrollLeft = e.detail.scrollLeft
				}
			},
			onTouchStart() {
				this.isDragging = true
				this.stopAutoScroll()
			},
			onTouchEnd() {
				this.isDragging = false
				this.startAutoScroll()
			},
			onTouchCancel() {
				this.isDragging = false;
				this.startAutoScroll();
			},
			onUpper: _.debounce(function() {
				if (!this.isDragging)
					this.direction = 'right'
			}, 500),
			onLower: _.debounce(function() {
				if (!this.isDragging)
					this.direction = 'left'
			}, 500),
		}
	}
</script>

<style lang="scss" scoped scoped>
	.goods-box {
		.hd {
			display: flex;
			justify-content: space-between;
			align-items: center;
			padding: 20rpx 0;

			.title {
				color: #333;
				font-weight: bold;
			}

			.right {
				color: gray;
			}
		}

		.scroll-box {
			width: 100%;

			.scroll-view_H {
				white-space: nowrap;
				width: 100%;
			}

			.goods-list {
				.goods-item {
					display: inline-block;
					width: 168rpx;
					box-shadow: 0 4rpx 12rpx 4rpx rgba(0, 0, 0, 0.03);
					position: relative;
					overflow: hidden;
					border-radius: 16rpx;
					background-color: #fff;
					position: relative;

					&+.goods-item {
						margin-left: 20rpx;
					}

					.info {
						.name {
							padding: 8rpx 0;
						}

						.price-box {
							display: flex;
							align-items: center;
							margin-top: 6rpx;
							justify-content: space-around;

							.t1 {
								background-color: rgba(233, 51, 35, 0.1);
								color: #e93323;
								display: flex;
								align-items: center;
								justify-content: center;
								width: 54rpx;
								height: 30rpx;
								margin-right: 6rpx;
								border-radius: 4rpx;
								font-size: 18rpx;
							}

							.price {
								color: #e93323;
								font-size: 24rpx;
								font-weight: 700;
							}
						}
					}

					.bom-btn {
						display: flex;
						align-items: center;
						justify-content: space-between;
						width: 100%;
						height: 24px;
						border-radius: 0 0 8px 8px;
						color: #fff;
						font-size: 12px;
						background-color: #38b616;
						padding: 0 10px;
					}
				}
			}
		}
	}
</style>