<template>
	<view class="animate-box" :style="[animateStyle]">
		<view class="animate-wrap" :class="[animateName]">
			<slot></slot>
		</view>
	</view>
</template>

<script>
	export default {
		name: 'MyAnimation',
		props: {
			animate: {
				type: String,
				required: true,
			},
			animateStyle: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {}
		},
		computed: {
			animateName() {
				return `animate-${this.animate}`
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.animate-box {
		position: fixed;

		.animate-wrap {
			display: inline-block;
		}

		.animate-donghua1 {
			animation-name: donghua1;
		}

		.animate-donghua2 {
			animation-name: donghua2;
		}

		.animate-donghua3 {
			animation-name: donghua3;
		}
	}

	.animate-box [class*='animate-'] {
		animation-duration: 1.1s;
		animation-iteration-count: infinite;
		animation-direction: alternate;
		animation-fill-mode: both;
	}

	@keyframes donghua1 {
		0% {
			transform: rotate(6deg);
		}

		100% {
			transform: rotate(36deg);
		}
	}

	@keyframes donghua2 {
		0% {
			transform: translateX(-10px);
		}

		100% {
			transform: translateX(10px);
		}
	}

	@keyframes donghua3 {
		0% {
			transform: translateY(-10px);
		}

		100% {
			transform: translateY(10px);
		}
	}
</style>