<template>
	<view class="comp-box" :style="[compStyle]">
		<view v-if="styleConfig == 0" class="style-0">
			<view class="user-card" :style="{backgroundImage:`url(${$util.img('/statics/uni/img/user/user01.png')})`}">
				<view class="user-info">
					<u-image v-if="token" class="avatar" :src="userData.userinfo.headurl_img" width="124" height="124"
						border-radius="50%" @click="$util.on('/pages/ucenter_sub/info')" />
					<u-image v-else class="avatar" :src="$util.img('/statics/uni/img/user/logo.png')" width="124"
						height="124" border-radius="50%" @click="$util.on('/pages/ucenter_sub/info')" />
					<view class="info" @click="$util.on('/pages/ucenter_sub/info')">
						<template v-if="token">
							<view class="login-name">{{userData.userinfo.company}}</view>
							<my-animation animate="flicker" :borderRadius="24">
								<view v-if="userinfoConfig == 0" class="mobile">
									{{$kss.maskPhone(userData.userinfo.mobile)}}
								</view>
								<view v-else-if="userinfoConfig == 1" class="id">ID:{{userData.userinfo.id}}</view>
								<view v-else-if="userinfoConfig == 2" class="level-name" @click.stop.prevent>
									{{userData.userinfo.level_name}}
									<template v-if="userinfo.is_renew">
										<view class="flex-1" @click="$util.on('/pages/ucenter_sub/upgrade/renew')">
											<view v-if="userinfo.is_expire">会员过期</view>
											<view v-else>{{userinfo.expire_time}}</view>
										</view>
									</template>
								</view>
								<view v-else-if="userinfoConfig == 3" class="nick-name">
									{{userData.userinfo.company}}
								</view>
							</my-animation>

						</template>
						<template v-else>
							<view>登录/注册</view>
						</template>
					</view>
					<view class="set-btn" @click="$util.on('/pages/ucenter_sub/info')">
						<my-animation animate="twinkle"><text class="iconfont icon-shezhi"></text></my-animation>
					</view>
				</view>
				<view class="user-level"
					:style="{backgroundImage:`url(${$util.img('/statics/uni/img/user/grade.png')})`}">
					<view class="t1">提升等级 解锁更多权益</view>
					<view class="t2" @click.native="$util.on('/pages/ucenter_sub/upgrade/index')">
						<text>{{userData.can_up_level?'去激活':'无需升级'}}</text>
						<u-icon name="arrow-right"></u-icon>
					</view>
				</view>
			</view>
			<view class="num-wrapper">
				<view v-for="(item, index) in numList" :key="index" class="num-item" :style="{ width: numWidth }"
					@click="$kss.JumpPath(item.path)">
					<view class="num">{{ item.value || 0 }}</view>
					<view class="txt">{{ item.name }}</view>
				</view>
			</view>
		</view>
		<view v-else-if="styleConfig == 1" class="style-1">
			<view class="user-card">
				<view class="top">
					<view class="user-info">
						<u-image v-if="token" class="avatar" :src="userData.userinfo.headurl_img" width="150"
							height="150" border-radius="50%" @click="$util.on('/pages/ucenter_sub/info')" />
						<u-image v-else class="avatar" :src="$util.img('/statics/uni/img/user/logo.png')" width="150"
							height="150" border-radius="50%" @click="$util.on('/pages/ucenter_sub/info')" />
						<view class="info" @click="$util.on('/pages/ucenter_sub/info')">
							<template v-if="token">
								<view class="login-name">{{userData.userinfo.company}}</view>
								<my-animation animate="flicker" :borderRadius="24">
									<view v-if="userinfoConfig == 0" class="mobile">
										{{$kss.maskPhone(userData.userinfo.mobile)}}
									</view>
									<view v-else-if="userinfoConfig == 1" class="id">ID:{{userData.userinfo.id}}</view>
									<view v-else-if="userinfoConfig == 2" class="level-name" @click.stop.prevent>
										{{userData.userinfo.level_name}}
										<template v-if="userinfo.is_renew">
											<view class="flex-1" @click="$util.on('/pages/ucenter_sub/upgrade/renew')">
												<view v-if="userinfo.is_expire">会员过期</view>
												<view v-else>{{userinfo.expire_time}}</view>
											</view>
										</template>
									</view>
									<view v-else-if="userinfoConfig == 3" class="nick-name">
										{{userData.userinfo.company}}
									</view>
								</my-animation>
							</template>
							<template v-else>
								<view>登录/注册</view>
							</template>
						</view>
						<view class="set-btn" @click="$util.on('/pages/ucenter_sub/info')">
							<my-animation animate="twinkle">
								<text class="iconfont icon-shezhi"></text>
							</my-animation>
						</view>
					</view>
				</view>
				<view class="bottom">
					<view class="account">
						<view class="level-box">
							<view class="left" @click.native="$util.on('/pages/ucenter_sub/upgrade/index')">
								<template v-if="token">
									<u-image :src="userData.userinfo.level_img" width="60" height="60"
										@click="$util.on('/pages/ucenter_sub/upgrade/index')" />
									<span class="level-name">{{userData.userinfo.level_name}}</span>
								</template>
							</view>
							<view class="right" @click.native="$util.on('/pages/ucenter_sub/upgrade/index')">
								<template v-if="userData.can_up_level">
									<view class="t1">
										<text>我要升级</text>
										<u-icon name="arrow-right"></u-icon>
									</view>
									<view class="t2">提升等级享受更低折扣</view>
								</template>
								<template v-else>
									<view class="t1">
										<text>无需升级</text>
									</view>
									<view class="t2"></view>
								</template>

							</view>
						</view>
						<view class="num-box">
							<view v-for="(item, index) in numList" :key="index" class="num-item"
								:style="{ width: numWidth }" @click="$kss.JumpPath(item.path)">
								<view class="num">{{ item.value }}</view>
								<view class="txt">{{ item.name }}</view>
							</view>
						</view>
						<view class="recharg-button" @click="$util.on('/pages/ucenter_sub/recharge')">立即充值</view>
					</view>
				</view>
			</view>
		</view>
		<view v-else-if="styleConfig == 2" class="style-2">
			<view class="user-card" :style="{backgroundImage:`url(${$util.img('/statics/diy/my_bg_1.png')})`}">
				<view class="user-info">
					<view class="user-avatar">
						<template v-if="token">
							<view class="avatar-border" :style="[avatarBorderStyle]"
								@click="$util.on('/pages/ucenter_sub/info')"></view>
							<u-image class="avatar" :src="userData.userinfo.headurl_img" width="124" height="124"
								border-radius="50%" />
						</template>
						<template v-else>
							<u-image class="avatar" :src="$util.img('/statics/uni/img/user/logo.png')" width="124"
								height="124" border-radius="50%" @click="$util.on('/pages/ucenter_sub/info')" />
						</template>
					</view>
					<view class="info" @click="$util.on('/pages/ucenter_sub/info')">
						<template v-if="token">
							<view class="login-name">{{userData.userinfo.company}}</view>
							<view v-if="userinfoConfig == 0" class="mobile">{{$kss.maskPhone(userData.userinfo.mobile)}}
							</view>
							<view v-else-if="userinfoConfig == 1" class="id">ID:{{userData.userinfo.id}}</view>
							<view v-else-if="userinfoConfig == 2" class="level-name acea-row row-middle gap-10"
								@click.stop.prevent>
								{{userData.userinfo.level_name}}
								<template v-if="userinfo.is_renew">
									<view class="flex-1" @click="$util.on('/pages/ucenter_sub/upgrade/renew')">
										<view v-if="userinfo.is_expire">会员过期</view>
										<view v-else>{{userinfo.expire_time}}</view>
									</view>
								</template>
							</view>
							<view v-else-if="userinfoConfig == 3" class="nick-name">
								{{userData.userinfo.company}}
							</view>
						</template>
						<template v-else>
							<view>登录/注册</view>
						</template>
					</view>
					<view class="yxzx-btn" @click="$util.on('/pages/ucenter_sub/info')">用户中心</view>
				</view>
				<view class="num-wrapper"
					:style="{backgroundImage:`url(${$util.img('/statics/diy/my_money_bg.png')})`}">
					<view v-for="(item, index) in numList" :key="index" class="num-item" :style="{ width: numWidth }"
						@click="$kss.JumpPath(item.path)">
						<view class="num">{{ item.value || 0 }}</view>
						<view class="txt">
							<template v-if="item.id == 0">账户余额(元)</template>
							<template v-else-if="item.id == 1">佣金余额(元)</template>
							<template v-else>{{ item.name }}</template>
						</view>
					</view>
				</view>
			</view>
		</view>
		<!-- <u-popup v-model="show" mode="top" :mask="false" closeable close-icon-color="#fff">
			<view class="bg-red c-white p-20" @click="goRenew">会员已经到期，前往续费！</view>
		</u-popup> -->
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'
	import MyAnimation from '@/components/my-animation'

	export default {
		components: {
			'my-animation': MyAnimation
		},
		name: 'UserInfoBox',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				userData: {
					userinfo: {},
					favorite_num: 0,
					see_goods_num: 0,
					can_up_level: false,
				},

				show: false
			};
		},
		computed: {
			styleConfig() {
				return this.getAttr('styleConfig.tabVal', 0)
			},
			userinfoConfig() {
				return this.getAttr('userinfoConfig.tabVal', 0)
			},
			numConfig() {
				return this.getAttr('numConfig.type', [0, 1, 2, 3])
			},
			numList() {
				let arr = [{
						id: 0,
						name: '余额',
						value: this.userData.userinfo.balance,
						path: '/pages/ucenter_sub/moneylist'
					},
					{
						id: 1,
						name: '佣金',
						value: this.userData.userinfo.commission_money,
						path: '/pages/ucenter_sub/wallet'
					},
					{
						id: 2,
						name: '收藏',
						value: this.userData.favorite_num,
						path: '/pages/buyer/favorite'
					},
					{
						id: 3,
						name: '足迹',
						value: this.userData.see_goods_num,
						path: '/pages/ucenter_sub/footmark'
					},
					{
						id: 4,
						name: '冻结',
						value: this.userinfo.freez_money,
						path: '/pages/ucenter_sub/moneylist'
					},
				]
				return this.$_.filter(arr, (o) => {
					if (this.numConfig.includes(o.id)) return o
				})
			},
			numWidth() {
				if (this.numConfig.length)
					return `calc(100% / ${this.numConfig.length})`
				else return `100%`
			},
			avatarBgConfig() {
				return this.getAttr('avatarBgConfig.list', [])
			},
			avatarBorderStyle() {
				const levelBg = this.avatarBgConfig.find(item => this.userData.userinfo.level_id == item.level_id)
				if (levelBg && levelBg.src) {
					const re = {
						backgroundImage: `url(${this.$util.img(levelBg.src)})`,
						backgroundSize: 'cover'
					}
					return re
				}
				// let img = `/statics/diy/avatar_border/img_putong_${this.userData.userinfo.level_index}.svg`
				else {
					return {}
				}
			},
		},
		watch: {

		},
		created() {
			uni.$on(`page-show-${this.pageConfig.id}`, () => {
				this.init()
			})
		},
		mounted() {
			// setTimeout(() => {
			// 	if (this.userinfo.is_expire)
			// 		this.show = true
			// }, 2000)
		},
		methods: {
			async init() {
				const res = await this.$u.api.getDiyUserInfo()
				this.userData = res
			},
			goRenew() {
				this.show = false
				this.$Router.push({
					path: '/pages/ucenter_sub/upgrade/renew'
				})
			}
		}
	}
</script>
<style lang="scss" scoped scoped>
	.style-0 {
		.user-card {
			position: relative;
			width: 100%;
			height: 360rpx;
			padding: 88rpx 28rpx;
			background-size: 100% auto;
			background-color: #1a1a1a;

			.user-info {
				display: flex;
				gap: 20rpx;

				.avatar {
					width: 124rpx;
					height: 124rpx;
					border-radius: 50%;
					overflow: hidden;
				}

				.info {
					flex: 1;
					color: #fff;
					padding-top: 20rpx;
					overflow: hidden;

					.login-name {
						color: #fff;
						font-size: 32rpx;
					}

					.level-name {
						display: inline-block;
						color: #6c2a09;
						padding: 0 22rpx;
						border-radius: 20rpx;
						background: linear-gradient(90deg, #ffebc0, #ffc479);
					}

					.nick-name {}
				}

				.set-btn {
					align-self: flex-start;
					margin-top: 14rpx;
					margin-right: 20rpx;
					color: #f1d3a8;

					.iconfont {
						font-size: 44rpx !important;
					}
				}
			}

			.user-level {
				position: absolute;
				background-repeat: no-repeat;
				background-size: 100% 100%;
				width: 100%;
				height: 86rpx;
				bottom: -2rpx;
				left: 0;
				z-index: 30;
				padding: 0 58rpx 0 140rpx;
				display: flex;
				align-items: center;
				justify-content: space-between;
				color: #fff;
			}
		}

		.num-wrapper {
			background-color: #fff;
			display: flex;
			align-items: center;
			justify-content: space-between;
			color: #333;
			margin: -8rpx 30rpx 0 30rpx;
			border-radius: 0px 0px 16rpx 16rpx;
			height: 166rpx;

			.num-item {
				width: calc(100% / 4);
				overflow: hidden;
				display: flex;
				align-items: center;
				justify-content: center;
				flex-direction: column;

				.num {
					font-size: 36rpx;
					font-weight: 700;
				}

				.txt {
					margin-top: 8rpx;
					font-size: 26rpx;
					color: #555;
				}
			}
		}
	}

	.style-1 {
		.user-card {
			position: relative;
			overflow: hidden;
			z-index: 0;

			&:before {
				content: '';
				width: 100%;
				height: 440rpx;
				position: absolute;
				left: -25%;
				top: 0;
				width: 150%;
				border-radius: 0 0 100% 100%;
				z-index: -1;
				background: #ffb4b4;
				background-image: url(http://kezhang.11km.cn/static/m/2023.02/center-top-bg-8394ff13.png);
			}

			.top {
				padding: 108rpx 26rpx 0px;

				.user-info {
					z-index: 20;
					position: relative;
					display: flex;

					.avatar {
						width: 150rpx;
						height: 150rpx;
						background-color: rgb(238, 238, 238);
						color: rgb(102, 102, 102);
						border: 8rpx solid rgb(232, 202, 177);
						border-radius: 50%;
					}

					.info {
						flex: 1;
						display: flex;
						flex-direction: column;
						justify-content: space-between;
						margin-left: 48rpx;
						padding: 16rpx 0;
						overflow: hidden;

						.login-name {
							font-size: 38rpx;
							font-weight: 700;
							color: #fff;
						}

						.mobile,
						.id,
						.level-name,
						.nick-name {
							align-self: flex-start;
							font-size: 28rpx;
							color: rgba(255, 255, 255, 0.6);
							color: rgb(108, 42, 9);
							border-radius: 24rpx;
							background: linear-gradient(90deg,
									rgb(255, 235, 192),
									rgb(255, 196, 121));
							padding: 4rpx 26rpx;
						}
					}

					.set-btn {
						color: rgb(241, 211, 168);

						.iconfont {
							font-size: 60rpx;
						}
					}
				}
			}

			.bottom {
				padding: 48rpx 26rpx 0px;

				.account {
					border-radius: 12rpx;
					padding: 24rpx;
					background: #ffffff;

					.level-box {
						display: flex;
						padding-bottom: 20rpx;
						border-bottom: 2rpx solid #ebedf0;

						.left {
							flex: 1;
							display: flex;
							gap: 10rpx;
							align-items: center;

							.level-name {
								font-size: 26rpx;
							}
						}

						.right {
							display: flex;
							flex-direction: column;
							text-align: right;
							font-size: 24rpx;

							.t1 {
								color: #666666;
							}

							.t2 {
								color: #fa2c19;
							}
						}
					}

					.num-box {
						background-color: #fff;
						display: flex;
						align-items: center;
						justify-content: space-between;
						color: #333;
						border-radius: 0px 0px 16rpx 16rpx;
						height: 166rpx;
						margin-top: 20rpx;

						.num-item {
							width: calc(100% / 4);
							overflow: hidden;
							display: flex;
							align-items: center;
							justify-content: center;
							flex-direction: column;

							.num {
								font-size: 36rpx;
								font-weight: 700;
							}

							.txt {
								margin-top: 8rpx;
								font-size: 26rpx;
								color: #555;
							}
						}
					}

					.recharg-button {
						margin-top: 20rpx;
						display: flex;
						height: 72rpx;
						align-items: center;
						justify-content: center;
						white-space: nowrap;
						border-radius: 50rpx;
						border: 2rpx solid;
						border-color: #fa2c19;
						color: #fa2c19;
					}
				}
			}
		}
	}

	.style-2 {
		.user-card {
			background: linear-gradient(66deg, #fffcfb 0%, #fff6f3 100%);
			background-size: cover;
			opacity: 0.9;
			position: relative;
			width: 100%;
			padding: 40rpx 28rpx 0;

			.user-info {
				display: flex;
				align-items: center;
				gap: 20rpx;
				padding: 0 20rpx;

				.user-avatar {
					width: 124rpx;
					height: 124rpx;
					position: relative;

					.avatar {
						width: 124rpx;
						height: 124rpx;
						border-radius: 50%;
						overflow: hidden;
					}

					.avatar-border {
						position: absolute;
						z-index: 2;
						top: 50%;
						left: 50%;
						transform: translate(-50%, -50%) scale(1.1);
						width: 124rpx;
						height: 124rpx;
						background-size: cover;
					}
				}

				.info {
					flex: 1;
					display: flex;
					flex-direction: column;
					gap: 20rpx;
					overflow: hidden;

					.login-name {
						font-weight: 600;
						color: #1e2331;
						font-size: 34rpx;
					}

					.mobile,
					.id,
					.level-name,
					.nick-name {
						color: #985010;
						font-size: 18rpx;
					}
				}

				.yxzx-btn {
					width: 144rpx;
					height: 68rpx;
					background: linear-gradient(180deg, #3e3e4e 0%, #181823 100%);
					box-shadow: 0 3rpx 8rpx rgba(24, 24, 35, 0.28);
					border-radius: 32rpx;
					display: flex;
					align-items: center;
					justify-content: center;
					font-weight: 500;
					font-size: 24rpx;
					color: #f7c994;
				}
			}

			.num-wrapper {
				margin-top: 30rpx;
				display: flex;
				width: 100%;
				align-items: center;
				justify-content: space-between;
				height: 156rpx;
				background-color: transparent;
				border-radius: 30rpx 30rpx 0 0;
				background-position: top;
				background-size: 100%;

				.num-item {
					width: calc(100% / 4);
					overflow: hidden;
					display: flex;
					align-items: center;
					justify-content: center;
					flex-direction: column;
					gap: 8rpx;

					.num {
						font-weight: 500;
						color: #fff;
						font-size: 38rpx;
					}

					.txt {
						font-weight: 400;
						color: #f7c994;
						font-size: 24rpx;
					}
				}
			}
		}
	}

	::v-deep {
		.u-close--top-right {
			top: 50%;
			transform: translateY(-50%);
		}
	}
</style>