<template>
	<view :style="[compStyle]">
		<view class="cate-tab-box">
			<u-tabs :list="cateList" is-scroll :bold="false" :show-bar="false" bg-color="transparent" :duration="0"
				:current="pCateCurrent" @change="pCateChange"
				:active-item-style="{background:'#fe564b',color:'#fff'}"></u-tabs>
		</view>
		<view class="menu-box" v-if="menuList.length">
			<view class="menu-list">
				<view class="menu-item" :class="{on:cCateCurrent == index && showGoodsConfig}"
					v-for="item,index in menuList" :key="index" @click="menuClick(item,index)">
					<u-image width="100" height="100" border-radius="20" :src="$util.img(item.img)"
						mode="aspectFit"></u-image>
					<text class="name line1">{{item.name}}</text>
				</view>
				<view class="menu-item more" @click="moreBtnClick" v-if="moreBtnConfig">
					<view class="more-icon"><u-icon name="more-dot-fill" /></view>
					<text>更多</text>
				</view>
			</view>
		</view>
		<view class="goods-box" v-if="showGoodsConfig">
			<view class="goods-list" v-if="showGoodsStyleConfig == 0">
				<view class="goods-item" v-for="item,index in goodsList" :key="index"
					@click="$kss.JumpPath(`/pages/goods/detail?id=${item.id}`)">
					<u-image width="100%" :height="340" :src="item.goods_img" :border-radius="20"
						mode="widthFix"></u-image>
					<text class="name line2">{{item.goods_name}}</text>
					<view class="bottom">
						<view class="sale">
							<text>￥</text>
							{{item.face_value}}
						</view>
						<view class="price">
							<text>￥</text>
							{{item.goods_price}}
						</view>
						<view class="btn"
							:class="{'buy-now-card':item.goods_type == 1 && !sysconfig.change_site_info,'buy-now':item.goods_type!=1 || sysconfig.change_site_info,'no-stock':item.stock_num==0}">
							<template v-if="item.stock_num">
								<template v-if="item.goods_type == 1 && !sysconfig.change_site_info">提取卡密</template>
								<template v-else>立即购买</template>
							</template>
							<template v-else>
								暂停销售
							</template>
						</view>
					</view>
				</view>
			</view>
			<view class="goods-list2" v-else-if="showGoodsStyleConfig == 1">
				<view v-for="item,index in goodsList" :key="index" class="goods-item" :style="{ borderRadius: radius }"
					@click="$kss.JumpPath(`/pages/goods/detail?id=${item.id}`)">
					<u-image :width="200" :height="200" :src="item.goods_img" :border-radius="goodsItemRadius"
						mode="widthFix"></u-image>
					<view class="right">
						<view class="name line2">
							{{item.goods_name}}
						</view>
						<view class="bottom">
							<view class="code">商品编号：{{item.id}}</view>
							<view class="price">
								<view class="sale">
									<text>￥</text>
									{{item.goods_price}}
								</view>
								<view class="cost">
									<text>￥</text>
									{{item.face_value}}
								</view>
							</view>
							<view class="btn"
								:class="{'buy-now-card':item.goods_type == 1 && !sysconfig.change_site_info,'buy-now':item.goods_type!=1 || sysconfig.change_site_info,'no-stock':item.stock_num==0}">
								<template v-if="item.stock_num">
									<template v-if="item.goods_type == 1 && !sysconfig.change_site_info">提取卡密</template>
									<template v-else>立即购买</template>
								</template>
								<template v-else>
									暂停销售
								</template>
							</view>
						</view>
					</view>
				</view>
			</view>
			<u-loadmore :status="loadStatus" @loadmore="loadMoreData" class="loadingicon"></u-loadmore>
		</view>
	</view>
</template>

<script>
	import {
		throttle
	} from '@/common/validate.js';
	import CompMixin from '../mixins/comp.js'
	export default {
		name: 'CateGoods',
		components: {

		},
		props: {

		},
		mixins: [CompMixin],
		data() {
			const that = this
			return {
				cateList: [],
				pCateCurrent: -1,
				menuList: [],
				cCateCurrent: -1,

				queryForm: {
					cpid: '',
					cid: '',
					page: 1,
					limit: 10,
					is_count: 1,
				},
				total: 0,
				goodsList: [],
				loadStatus: 'loadmore',

				scrollFn: throttle(function() {
					that.loadMoreData()
				}, 200)
			}
		},
		computed: {
			newsStyle() {
				return {
					padding: `${this.dataConfig.topConfig.val * 2}rpx ${this.dataConfig.prConfig.val * 2}rpx ${this.dataConfig.bottomConfig.val * 2}rpx`,
					marginTop: `${this.dataConfig.mtConfig.val * 2}rpx`,
					background: this.dataConfig.bgColor.color[0].item,
				}
			},
			showGoodsStyleConfig() {
				return this.dataConfig.showGoodsStyleConfig.tabVal
			},
			radius() {
				const radius = this.dataConfig.radius
				return radius.type ?
					`${radius.valList[0].val*2}rpx ${radius.valList[1].val*2}rpx ${radius.valList[2].val*2}rpx ${radius.valList[3].val*2}rpx` :
					`${radius.val*2}rpx`
			},
			goodsItemRadius() {
				const goodsItemRadius = this.dataConfig.goodsItemRadius
				return goodsItemRadius.type ?
					`${goodsItemRadius.valList[0].val*2}rpx ${goodsItemRadius.valList[1].val*2}rpx ${goodsItemRadius.valList[2].val*2}rpx ${goodsItemRadius.valList[3].val*2}rpx` :
					`${goodsItemRadius.val*2}rpx`
			},
			moreBtnConfig() {
				return !this.dataConfig.moreBtnConfig.tabVal ? true : false
			},
			showGoodsConfig() {
				return !this.dataConfig.showGoodsConfig.tabVal ? true : false
			},
		},
		async mounted() {
			await this.init()

			uni.$on('scrolltolower', this.scrollFn);
		},
		beforeDestroy() {
			uni.$off('scrolltolower', this.scrollFn);
		},
		methods: {
			async init() {
				this.$u.api.getDiyCateTree().then(res => {
					this.cateList = res
					if (res.length) {
						this.pCateCurrent = 0
						if (res[0].children.length) {
							this.menuList = res[0].children
							if (this.menuList.length) {
								this.cCateCurrent = 0
								this.queryForm.cid = this.menuList[this.cCateCurrent].id
								this.queryForm.cpid = this.menuList[this.cCateCurrent].pid
								this.loadGoods()
							}
						} else {
							this.loadStatus = 'nomore'
							this.goodsList = []
						}
					}
				})
			},
			pCateChange(index) {
				this.pCateCurrent = index

				this.menuList = []
				this.cCateCurrent = -1
				if (this.cateList[index].children.length) {
					this.menuList = this.cateList[index].children
					if (this.menuList.length) {
						this.cCateCurrent = 0
						this.queryForm.cid = this.menuList[this.cCateCurrent].id
						this.queryForm.cpid = this.menuList[this.cCateCurrent].pid
						this.reloadGoods()
					}
				} else {
					this.loadStatus = 'nomore'
					this.goodsList = []
				}
			},
			menuClick(row, index) {
				if (this.showGoodsConfig) {
					if (this.queryForm.cid == row.id)
						return
					this.cCateCurrent = index

					this.queryForm.cid = row.id
					this.queryForm.cpid = row.pid
					this.reloadGoods()
				} else {
					this.$kss.JumpPath(`/pages/goods/list?id=${row.id}&cpid=${row.pid}&title=${row.name}`)
				}
			},
			async loadGoods() {
				if (!this.showGoodsConfig)
					return
				if (this.loadStatus == 'nomore')
					return
				this.loadStatus = 'loading'
				const {
					list,
					total
				} = await this.$u.api.getDiyGoodsList(this.queryForm)
				this.total = total
				if (list.length) {
					this.goodsList = this.goodsList.concat(list)
					this.loadStatus = 'loadmore'
				} else {
					this.loadStatus = 'nomore'
				}
			},
			loadMoreData() {
				this.queryForm.page++
				this.loadGoods()
			},
			reloadGoods() {
				this.goodsList = []
				this.queryForm.page = 1
				this.loadStatus = 'loadmore'
				this.loadGoods()
			},
			// 跳转分类页面
			moreBtnClick() {
				this.$kss.JumpPath(`/pages/category/index`)
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.u-tab-item {
			height: 52rpx !important;
			font-size: 26rpx !important;
			line-height: 50rpx !important;
			border-radius: 52rpx;
		}
	}

	.btn {
		position: absolute;
		right: 10rpx;
		bottom: 10rpx;
		height: 50rpx;
		line-height: 50rpx;
		border-radius: 30rpx;
		font-size: 24rpx;
		padding: 0 20rpx;
	}

	.buy-now-card {
		color: #0eab0f;
		border: 1px solid #0eab0f;
	}

	.buy-now {
		border-color: #FF564D;
		background: #FF564D;
		color: #fff;
	}

	.no-stock {
		background-color: #ccc;
		border: 1px solid #ccc;
		color: #fff;
	}

	.menu-box {
		background-color: #fff;
		// padding: 28rpx 28rpx 14rpx 28rpx;
		border-radius: 16rpx;
		margin-top: 10rpx;

		.menu-list {
			display: flex;
			flex-wrap: wrap;
			align-items: center;

			.menu-item {
				width: calc(100% / 5 - 20rpx);
				margin-left: 10rpx;
				margin-right: 10rpx;
				display: flex;
				align-items: center;
				flex-direction: column;
				padding: 8rpx;
				overflow: hidden;
				margin-bottom: 20rpx;

				.name {
					width: 100%;
					text-align: center;
					font-size: 24rpx;
				}
			}

			.on {
				border-radius: 20rpx;
				box-shadow: rgba(0, 0, 0, 0.06) 0 4rpx 8rpx 0 inset;
			}

			.more {
				.more-icon {
					width: 100rpx;
					height: 100rpx;
					border-radius: 50%;
					background-color: #f8f8f8;
					display: flex;
					align-items: center;
					justify-content: center;
					font-size: 40rpx;
					color: #ccc;
				}
			}
		}
	}

	.goods-box {
		margin-top: 10rpx;

		.goods-list {
			display: flex;
			flex-wrap: wrap;
			overflow: hidden;
			justify-content: space-between;
			gap: 20rpx;

			.goods-item {
				width: calc(99% / 2 - 10rpx);
				position: relative;
				background-color: #fff;
				border-radius: 20rpx;
				padding: 16rpx;
				display: flex;
				flex-direction: column;
				overflow: hidden;

				.name {
					flex: 1;
					margin-top: 10rpx;
					color: #303133;
					width: 100%;
				}

				.bottom {
					margin-top: 20rpx;

					.sale {
						color: #afafaf;
						text-decoration: line-through;
					}

					.price {
						color: #fa3534;
						font-weight: 700;
					}

					.buy-btn {
						position: absolute;
						bottom: 20rpx;
						right: 20rpx;
					}
				}
			}
		}

		.goods-list2 {
			display: flex;
			flex-direction: column;
			gap: 10px;

			.goods-item {
				display: flex;
				flex-direction: row;
				flex-wrap: nowrap;
				gap: 20rpx;
				background-color: #fff;
				padding: 10rpx 0;
				overflow: hidden;

				.right {
					flex: 1;
					display: flex;
					flex-direction: column;
					justify-content: space-between;

					.name {}

					.bottom {
						position: relative;

						.code {
							font-size: 26rpx;
							color: #999;
						}

						.price {
							display: flex;
							align-items: baseline;
							gap: 20rpx;

							.sale {
								font-size: 30rpx;
								font-weight: 700;
								color: #fa3534;
							}

							.cost {
								color: #afafaf;
								font-size: 22rpx;
								text-decoration: line-through;
							}
						}

					}
				}
			}
		}
	}
</style>