<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compWrapStyle]">
			<u-navbar :is-back="false" :background="{background:'#F5F5F5'}" :z-index="10">
				<u-search placeholder="请输入商品名称" :show-action="false" margin="0 32rpx" bg-color="#fff" height="58"
					:input-style="{fontSize:'24rpx'}" />
				<view class="search-mask" @click="searchClick"></view>
			</u-navbar>
			<view>
				<view class="cateBox">
					<!-- 左侧列表 -->
					<scroll-view class="cate-left" scroll-y="true" :scroll-top="verticalNavTop" scroll-with-animation>
						<view class="cate-left-list" v-for="(item,index) in data" :key="index"
							@click="tapselect(index)">
							<!-- activeItem为选中状态 -->
							<view class="cate-left-item" :class="{activeItem:currentTab==index}">
								<view class="top-ra" v-if="currentTab==index"><text></text></view>
								<label></label><text class="line1">{{item.name}}</text>
								<view class="bottom-ra" v-if="currentTab==index"><text></text></view>
							</view>
						</view>
					</scroll-view>

					<view class="main">
						<!-- 右侧二级分类 -->
						<template v-if="categoryLevel===1">
							<view class="child-block-box" v-if="twoCategoryList.length">
								<view class="child-block-wrap">
									<scroll-view class="scroll-view_H" scroll-x="true"
										:scroll-into-view="'two-cate-'+twoCategoryIndex" scroll-with-animation>
										<view class="scroll-view-item_H" v-for="item,index in twoCategoryList"
											:key="index" :id="'two-cate-'+index"
											@click="handelTwoCategoryChange(item,index)">
											<view class="scroll-view-item_H-wrap line1"
												:class="{active:twoCategoryIndex==index}">
												{{item.name}}
											</view>
										</view>
									</scroll-view>
									<view class="bnt-con" @click="showCategoryPopup=true">
										<u-icon name="arrow-down" />
									</view>
								</view>
							</view>
							<view style="height: 96rpx;" v-if="twoCategoryList.length"></view>
						</template>
						<!-- 右侧列表 -->
						<scroll-view ref="rightScrollV" class="cate-right" scroll-y="true" @scroll="mainScroll"
							:scroll-into-view="'cate-'+mainCur" scroll-with-animation>
							<template v-if="categoryLevel === 1">
								<view class="card">
									<template v-if="currTwoCategory.children && currTwoCategory.children.length">
										<view class="title" @click="cateItemClick(currTwoCategory)">
											<text>{{currTwoCategory.name}}</text>
											<u-icon name="arrow-right" color="#999" />
										</view>
										<view class="grid-box">
											<view class="grid-item"
												v-for="(child,childindex) in currTwoCategory.children" :key="childindex"
												@click="cateItemClick(child)">
												<u-image :src="$util.img(child.img)" height="130" width="130"
													border-radius="12" />
												<view class="txt line1">{{child.name}}</view>
											</view>
										</view>
									</template>
									<template v-else>
										<u-empty mode="list"></u-empty>
									</template>
								</view>
							</template>
							<template v-else>
								<view v-for="(item,index) in data" :key="index" :id="'cate-'+index" class="card">
									<view class="title" @click="cateItemClick(item)">
										<text>{{item.name}}</text>
										<u-icon name="arrow-right" color="#999" />
									</view>
									<view class="grid-box">
										<view class="grid-item" v-for="(child,childindex) in item.children"
											:key="childindex" @click="cateItemClick(child)">
											<u-image :src="$util.img(child.img)" height="130" width="130"
												border-radius="12" />
											<view class="txt line1">{{child.name}}</view>
										</view>
									</view>
								</view>
							</template>

							<view style="height: 260px;"></view>
						</scroll-view>
					</view>
				</view>
			</view>
			<ChildCategoryPopup v-model="showCategoryPopup" :list="twoCategoryList"
				:activeIndex.sync="twoCategoryIndex" />
		</view>
	</view>
</template>


<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'Category1',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				// 列表数组 navtitle:标题 shop:展示列表
				data: [],
				currentTab: 0, // 左侧索引
				mainCur: 0, // 右侧索引
				verticalNavTop: 0,
				list: [{}],

				showCategoryPopup: false,
				twoCategoryIndex: 0, //二级分类索引
			};
		},
		computed: {
			categoryLevel() {
				return this.getAttr('categoryLevel.tabVal', 0)
			},
			// 二级分类列表
			twoCategoryList() {
				return this.data[this.currentTab] ? this.data[this.currentTab].children : []
			},
			// 当前二级分类
			currTwoCategory() {
				return this.twoCategoryList[this.twoCategoryIndex] ? this.twoCategoryList[this.twoCategoryIndex] : {}
			},
		},
		watch: {
			// 由于改了浏览器地址参数，导致vue-router返回直接刷新页面，所以不能修改
			currentTab(nv) {
				// const cate = this.data[nv]
				// if (cate) {
				// 	this.$util.changeURLArg('cpid', cate.id || '')
				// }

			},
			twoCategoryIndex(nv) {
				// const cate = this.twoCategoryList[nv]
				// if (cate) {
				// 	this.$util.changeURLArg('cid', cate.id || '')
				// }
			},
		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {
				await this.fetchData()

				const {
					cpid, // 上级分类id
					cid, // 分类id
				} = this.$Route.query

				if (this.categoryLevel === 1) {
					const categoryData = this.$util.initCategoryData(this.data, [cpid, cid])
					if (categoryData[0])
						this.currentTab = this.data.findIndex(item => item.id === categoryData[0].id)
					if (categoryData[1])
						this.twoCategoryIndex = this.twoCategoryList.findIndex(item => item.id === categoryData[1].id)
				} else {
					const categoryData = this.$util.initCategoryData(this.data, [cpid])
					if (categoryData[0]) {
						this.currentTab = this.data.findIndex(item => item.id === categoryData[0].id)
						// 设置右边滑动
						this.mainCur = this.currentTab
						this.verticalNavTop = (this.currentTab - 1) * 48
					}
					this.getHeight()
				}
			},
			async fetchData() {
				const {
					category_list
				} = await this.$u.api.category()
				this.data = category_list
			},
			cateItemClick(item) {
				if (item && item.is_jump_url == 1) {
					this.$util.on(item.jump_url)
					return
				}
				const {
					id,
					pid,
					name
				} = item
				this.$Router.push({
					path: '/pages/goods/list',
					query: {
						id,
						cpid: pid,
						title: name
					}
				})

				// uni.showModal({
				// 	title: '点击条目',
				// 	content: '点击条目数据 = ' + JSON.stringify(item)
				// })
			},

			//点击左侧按钮
			tapselect(index) {
				if (this.data[index] && this.data[index].is_jump_url == 1) {
					this.$util.on(this.data[index].jump_url)
					return
				}

				// 左边侧边栏点击了
				this.currentTab = index;
				// 判断是否三级分类
				if (!this.categoryLevel) {
					// 设置右边滑动
					this.mainCur = index;
					this.verticalNavTop = (index - 1) * 48;
				}

				this.twoCategoryIndex = 0
			},
			//右侧滚动
			mainScroll(e) {
				// 判断是否三级分类
				if (this.categoryLevel)
					return
				console.log("在滑动")
				let scrollTop = e.detail.scrollTop + 10
				for (let i = 0; i < this.list.length; i++) {
					if (scrollTop > this.list[i].top && scrollTop < this.list[i].bottom) {
						this.currentTab = i
						// this.mainCur = i;
						this.verticalNavTop = (i - 1) * 48
						return true
					}
				}
			},
			//获取右侧每项的top和bottom,里面需获取对应dom元素的高度，所以只能在mounted生命周期里调用
			getHeight() {
				var top = 0;
				var bottom = 0;
				var temp = 0;
				for (let i = 0; i < this.data.length; i++) {
					let view = uni.createSelectorQuery().select("#cate-" + i)

					// #ifdef  MP-WEIXIN
					view = uni.createSelectorQuery().in(this).select("#cate-" + i);
					//	#endif

					view.fields({
						size: true
					}, data => {
						top = temp;
						bottom = temp + data.height;
						this.list[i] = {
							top: top,
							bottom: bottom
						};
						temp = bottom;
					}).exec();
				}
				// console.log(this.list)
			},
			searchClick() {
				this.$util.on('/pages/search/search')
			},
			handelTwoCategoryChange(row, index) {
				if (row && row.is_jump_url == 1) {
					this.$util.on(row.jump_url)
					return
				}
				if (this.twoCategoryIndex == index)
					return
				this.twoCategoryIndex = index
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.search-mask {
		position: absolute;
		width: 100%;
		height: 100%;
		left: 0;
		top: 0;
	}

	.cateBox {
		position: absolute;
		/* top: 120rpx; */
		top: 88rpx;
		bottom: 0;
		// background: #fff;
		width: 100%;
		display: flex;

		.cate-left {
			width: 168rpx;
			height: 100%;
			background: #fff;

			.cate-left-item {
				height: 96rpx;
				display: flex;
				align-items: center;
				font-size: 26rpx;
				color: #666;
			}

			.cate-left-item.activeItem {
				background: #F5F5F5;
				color: var(--view-theme);
				position: relative;

				.top-ra {
					width: 16px;
					height: 16px;
					background-color: #f5f5f5;
					position: absolute;
					right: 0;
					top: -16px;

					uni-text {
						position: absolute;
						top: 0;
						right: 0;
						width: 100%;
						height: 100%;
						background-color: #fff;
						display: inline-block;
						border-radius: 0 0 12px 0;
					}
				}

				.bottom-ra {
					width: 16px;
					height: 16px;
					background-color: #f5f5f5;
					position: absolute;
					right: 0;
					bottom: -16px;

					uni-text {
						position: absolute;
						top: 0;
						right: 0;
						width: 100%;
						height: 100%;
						background-color: #fff;
						display: inline-block;
						border-radius: 0 12px 0 0;
					}
				}
			}

			/*
			*/

			.cate-left-item label {
				width: 3px;
				border-radius: 4rpx;
				height: 24px;
				float: left;
				background: #f4f4f4;
			}

			.cate-left-item.activeItem label {
				background: var(--view-theme);
			}

			.cate-left-item text {
				width: 196rpx;
				font-size: 28rpx;
				display: block;
				text-align: center;
			}
		}





		/* 右侧*/
		.main {
			flex: 1;
			height: 100%;
			overflow: hidden;
			padding: 0 10px;
			position: relative;
			background-color: #f5f5f5;

			.child-block-box {
				position: absolute;
				padding: 0 20rpx 0 24rpx;
				left: 0;
				top: 0;
				width: 100%;

				.child-block-wrap {
					margin: 24rpx 0 16rpx 0;
					display: flex;

					.scroll-view_H {
						flex: 1;
						overflow: hidden;
					}

					.scroll-view-item_H {
						margin-right: 16rpx;

						.scroll-view-item_H-wrap {
							color: rgba(51, 51, 51, 1);
							background: rgba(255, 255, 255, 1);
							width: 144rpx;
							height: 56rpx;
							font-size: 24rpx;
							border-radius: 30rpx;
							display: block;
							line-height: 52rpx;
							text-align: center;
							border: 2rpx solid #fff;
						}

						.active {
							color: var(--view-theme);
							background: var(--view-minorColorT);
							border: 2rpx solid var(--view-theme);
						}
					}

					.bnt-con {
						position: relative;
						margin-left: 16rpx;
						width: 56rpx;
						height: 56rpx;
						border-radius: 30rpx;
						background-color: #fff;
						display: flex;
						align-items: center;
						justify-content: center;

						&::before {
							position: absolute;
							content: "";
							width: 6rpx;
							height: 80rpx;
							background: radial-gradient(rgba(0, 0, 0, .082) 0, transparent 100%);
							left: -22rpx;
						}
					}
				}
			}
		}

		.cate-right {
			height: calc(100% - env(safe-area-inset-bottom));
		}

		.card {
			width: 100%;
			background-color: #fff;
			border-radius: 8px;
			padding: 16px 12px;
			margin-bottom: 10px;

			.title {
				font-size: 14px;
				font-weight: 500;
				color: #333;
				line-height: 20px;
			}

			.grid-box {
				display: grid;
				grid-template-columns: repeat(3, 1fr);
				grid-template-rows: auto;
				grid-row-gap: 16px;
				grid-column-gap: 25px;
				margin-top: 10px;

				.grid-item {
					display: flex;
					align-items: center;
					justify-content: center;
					flex-wrap: wrap;
					overflow: hidden;

					.txt {
						font-size: 12px;
						color: #333;
						line-height: 17px;
						margin-top: 6px;
						text-align: center;
					}
				}
			}
		}



		.cate-right-title .line {
			position: absolute;
			height: 2rpx;
			width: 300rpx;
			background: orange;
			top: 39rpx;
			left: 50%;
			margin-left: -150rpx;
		}

		.cate-right-title text {
			background: #fff;
			padding: 0 10px;
			position: relative;
			color: #999;
		}

		.cate-right-list {
			height: auto;
			overflow: hidden;
		}

		.cate-right-item {
			width: 33.33%;
			float: left;
			margin-top: 20rpx;
		}

		.cate-right-item image {
			width: 160rpx;
			height: 160rpx;
			display: block;
			margin: 0 auto;
		}

		.cate-right-item text {
			display: block;
			text-align: center;
			font-size: 24rpx;
		}
	}
</style>