<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		name: 'PictureCube',
		props: {
			isSortType: {
				type: String | Number,
				default: 0
			}
		},
		mixins: [CompMixin],
		data() {
			return {
				picList: this.dataConfig.picStyle.picList,
				style: this.dataConfig.styleConfig.tabVal,
				bgStyle: 0,
				slider: 0,
				widthC: '',
				imageH: 0,
			};
		},
		computed: {
			filletImg() {
				let borderRadius = `${this.dataConfig.filletImg.val * 2}rpx`;
				if (this.dataConfig.filletImg.type) {
					borderRadius =
						`${this.dataConfig.filletImg.valList[0].val * 2}rpx ${this.dataConfig.filletImg.valList[1].val * 2}rpx ${this.dataConfig.filletImg.valList[2].val * 2}rpx ${this.dataConfig.filletImg.valList[3].val * 2}rpx`;
				}
				return {
					'border-radius': borderRadius,
				}
			},
			imgGap() {
				return {
					borderWidth: `${this.dataConfig.imgConfig.val*2}rpx`,
				}
			},
			imgBorderRadius() {
				let borderRadius = `${this.dataConfig.filletImg.val * 2}rpx`;
				if (this.dataConfig.filletImg.type) {
					borderRadius =
						`${this.dataConfig.filletImg.valList[0].val * 2}rpx ${this.dataConfig.filletImg.valList[1].val * 2}rpx ${this.dataConfig.filletImg.valList[2].val * 2}rpx ${this.dataConfig.filletImg.valList[3].val * 2}rpx`;
				}
				return borderRadius
			},
		},
		mounted() {
			uni.getSystemInfo({
				success: (res) => {
					this.imageH = res.windowWidth
				}
			})
			if (this.style == 10) {
				uni.getImageInfo({
					src: this.picList[0].image,
					success: (image) => {
						this.imageH = image.height * this.imageH / image.width
					}
				})
			}
		},
		created() {},
		methods: {
			//替换安全域名
			setDomain: function(url) {
				url = url ? url.toString() : '';
				//本地调试打开,生产请注销
				if (url.indexOf("https://") > -1) return url;
				else return url.replace('http://', 'https://');
			},
			goDetail(url) {
				this.$kss.JumpPath(url.link)
			}
		}
	}
</script>

