<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compWrapStyle]">
			<view class="comp-content" :style="[contentStyle]"></view>
		</view>
	</view>
</template>


<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'AuxiliarylLine',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {

			};
		},
		computed: {
			lineStyle() {
				const tab_val = this.getAttr('lineStyle.tabVal', 0)
				if (tab_val == 0)
					return 'dashed'
				else if (tab_val == 1)
					return 'solid'
				else if (tab_val == 2)
					return 'dotted'
				else
					return 'solid'
			},
			lineColor() {
				return this.getAttr('lineColor.color[0].item', '#f5f5f5')
			},
			lineWidth() {
				return this.getAttr('lineWidth.val', 1)
			},
			contentStyle() {
				const re = {
					borderBottomWidth: `${this.lineWidth * 2}rpx`,
					borderBottomColor: this.lineColor,
					borderBottomStyle: this.lineStyle,
				}
				return re
			},
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {

			},
		}
	}
</script>

