<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compContentStyle2]">
			<view class="hd">
				<text class="title" :style="[titleTextStyle]">{{ titleTxtConfig.value }}</text>
				<view v-if="rightBtnConfig" class="right" :style="[rightTextStyle]" @click="$kss.JumpPath(linkConfig)">
					{{ rightTextConfig }}
					<u-icon name="arrow-right"></u-icon>
				</view>
			</view>
			<view class="content">
				<view v-for="(item, index) in menuConfig" :key="index" class="item" :style="{ width: numWidth }"
					@click="$kss.JumpPath(item.link)">
					<view class="badge-wrap">
						<u-badge type="error" v-if="!item.numHidden" :count="getCount(item.id)" is-center></u-badge>
						<u-image :src="$util.img(item.img)" width="48" height="48" />
					</view>
					<view class="txt">{{ item.title }}</view>
				</view>
			</view>
		</view>
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'OrderBox',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				statusNumList: [],
			};
		},
		computed: {
			titleTxtConfig() {
				return this.getAttr('titleTxtConfig', {})
			},
			rightBtnConfig() {
				return !this.getAttr('rightBtnConfig.tabVal', 0) ? true : false
			},
			rightTextConfig() {
				return this.getAttr('rightTextConfig.value', '')
			},
			linkConfig() {
				return this.getAttr('linkConfig.value', '')
			},
			menuConfig() {
				let menuConfig = this.getAttr('menuConfig.list', [])
				let list = this.$_.filter(menuConfig, item => item.show).map(item => {
					return {
						img: item.img,
						numHidden: item.numHidden,
						title: item.info[0].value,
						id: item.info[1].value,
						link: item.info[2].value
					}
				})
				return list
			},
			numWidth() {
				if (this.menuConfig.length)
					return `calc(100% / ${this.menuConfig.length})`
				else return `100%`
			},
			titleTextStyle() {
				const re = {
					color: this.titleTxtConfig.color,
				}
				if (this.titleTxtConfig.hasFontSize) {
					re.fontSize = `${this.titleTxtConfig.fontSize * 2}rpx`
				}
				if (this.titleTxtConfig.hasFontBlod) {
					re.fontWeight = this.titleTxtConfig.fontBlod ? 'bolder' : ''
				}
				return re
			},
			rightTextStyle() {
				const re = {
					color: this.rightTextConfig.color
				}
				if (this.rightTextConfig.hasFontSize) {
					re.fontSize = `${this.rightTextConfig.fontSize * 2}rpx`
				}
				if (this.rightTextConfig.hasFontBlod) {
					re.fontWeight = this.rightTextConfig.fontBlod ? 'bolder' : ''
				}
				return re
			},
		},
		watch: {

		},
		mounted() {
			console.log(`组件OrderBox:`, `监听page-show-${this.pageConfig.id}事件`)
			uni.$on(`page-show-${this.pageConfig.id}`, () => {
				this.init()
			})
		},
		methods: {
			async init() {
				const status = this.menuConfig.map(item => item.id)
				const res = await this.$u.api.getDiyOrderListStatus({
					status
				})
				this.statusNumList = res
			},
			getCount(statu) {
				let find = this.statusNumList.find(item => item.value == statu)
				return find ? find.num : 0
			},
		}
	}
</script>
<style lang="scss" scoped scoped>
	.wrap {
		position: relative;

		.hd {
			display: flex;
			justify-content: space-between;
			align-items: center;
			padding: 20rpx 20rpx 10rpx 20rpx;

			.title {
				margin: 0;
				padding: 0;
				font-weight: 700;
				font-size: 30rpx;
			}

			.right {
				color: #666;
				font-size: 26rpx;
			}
		}

		.content {
			display: flex;
			flex-wrap: wrap;

			.item {
				display: flex;
				flex-direction: column;
				justify-content: center;
				align-items: center;
				width: calc(100% / 5);
				height: 144rpx;
				position: relative;

				.badge-wrap {
					position: relative;
				}

				.txt {
					margin-top: 6rpx;
					font-size: 26rpx;
					color: #454545;
				}
			}
		}
	}
</style>