<template>
	<u-back-top :scrollTop="scrollTop" :icon-style="iconStyle" :top="dataConfig.top" :bottom="dataConfig.bottom"
		:right="dataConfig.right" @click.native="btnClick">
		<u-image :src="$util.img(dataConfig.img)" width="80" height="80"></u-image>
	</u-back-top>
</template>

<script>
	export default {
		name: "BackTop",
		props: {
			scrollTop: {
				type: Number,
				default: 0
			},
			dataConfig: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				iconStyle: {
					fontSize: '32rpx',
					color: '#2979ff'
				}
			};
		},
		options: {
			styleIsolation: 'shared'
		},
		methods: {
			btnClick() {
				this.$emit('goTop')
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.u-back-top {
		background-color: transparent !important;
	}
</style>