<template>
	<view class="comp-box" :style="[compStyle]">
		<view class="wrap" :style="[compWrapStyle]">
			<u-navbar :is-back="false" :background="{background:'#fff'}" :z-index="10" :border-bottom="false">
				<u-search placeholder="请输入商品名称" :show-action="false" margin="0 32rpx" bg-color="#F5F5F5" height="58"
					:input-style="{fontSize:'24rpx'}" />
				<view class="search-mask" @click="searchClick"></view>
			</u-navbar>
			<view>
				<view class="cateBox">
					<!-- 左侧列表 -->
					<scroll-view class="cate-left" scroll-y="true" :scroll-top="verticalNavTop" scroll-with-animation>
						<view class="cate-left-list" v-for="(item,index) in data" :key="index"
							@click="tapselect(index)">
							<!-- activeItem为选中状态 -->
							<view class="cate-left-item" :class="{activeItem:currentTab==index}">
								<label></label><text class="line1">{{item.name}}</text>
							</view>
						</view>
					</scroll-view>

					<view class="main">
						<!-- 右侧二级分类 -->
						<view class="child-block-box" v-if="twoCategoryList.length">
							<view class="child-block-wrap">
								<scroll-view class="scroll-view_H" scroll-x="true"
									:scroll-into-view="'two-cate-'+twoCategoryIndex" scroll-with-animation>
									<view class="scroll-view-item_H" v-for="item,index in twoCategoryList" :key="index"
										:id="'two-cate-'+index" @click="handelTwoCategoryChange(item,index)">
										<view class="scroll-view-item_H-wrap line1"
											:class="{active:twoCategoryIndex==index}">
											{{item.name}}
										</view>
									</view>
								</scroll-view>
								<view class="bnt-con" @click="showCategoryPopup=true">
									<u-icon name="arrow-down" />
								</view>
							</view>
						</view>
						<view style="height: 96rpx;" v-if="twoCategoryList.length"></view>
						<!-- 右侧列表 -->
						<scroll-view ref="rightScrollV" class="cate-right" scroll-y="true" @scroll="mainScroll"
							:scroll-into-view="'cate-'+mainCur" scroll-with-animation @scrolltolower="getGoodsList">
							<view v-for="(item,index) in goodsList" :key="index" class="goods-item"
								@click="$util.on(`/pages/goods/detail?id=${item.id}`)">
								<view class="goods-img">
									<u-image :src="item.goods_img" width="540" height="540"
										border-radius="20rpx 20rpx 0 0">
										<view slot="error" class="error-img-box">
											<u-image :src="$util.img('/statics/diy/no-img.png')" width="240"
												height="180"></u-image>
										</view>
									</u-image>
								</view>
								<view class="goods-bottom">
									<view class="hd line2">
										<text class="tag">{{item.uid_text}}</text>
										{{item.goods_name}}
									</view>
									<view class="flex-between-center mt-20">
										<view class="flex-y-center flex-wrap flex-1">
											<view class="price-box">
												<price-symbol :showOldPrice="false" :nowPrice="item.goods_price"
													nowPriceColor="var(--view-theme)" />
											</view>
											<view class="sale-num">已售{{item.goods_sales}}</view>
										</view>
										<JoinCartButton :goods-id="item.id" :count="item.cart_num"
											:num-type="item.num_type" :num-count="item.num_count"
											:start-count="item.start_count" :end-count="item.end_count"
											@join="handelJoin" />
									</view>
								</view>
							</view>
							<u-loadmore :status="loadStatus" icon-type="circle" @loadmore="getGoodsList" />
							<view style="height: 200rpx;"></view>
						</scroll-view>
					</view>
				</view>
			</view>

			<CartBox v-show="showCart" @show-detail="showCardPopup=!showCardPopup" @settle="handelSettle" />
			<ChildCategoryPopup v-model="showCategoryPopup" :list="twoCategoryList" :activeIndex.sync="twoCategoryIndex"
				@change="reloadGoodsList" />
			<ProductPopup ref="product-popup" />
			<CartPopup v-model="showCardPopup" />
		</view>
	</view>
</template>


<script>
	import CompMixin from '../mixins/comp.js'
	import PriceSymbol from '@/components/price-symbol'
	import _ from 'lodash'
	import {
		mapGetters
	} from 'vuex'

	export default {
		components: {
			'price-symbol': PriceSymbol
		},
		name: 'Category1',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				// 列表数组 navtitle:标题 shop:展示列表
				data: [],
				currentTab: -1, // 左侧索引
				mainCur: -1, // 右侧索引
				verticalNavTop: 0,
				list: [{}],

				showCategoryPopup: false,
				twoCategoryIndex: 0, //二级分类索引

				goodsList: [], //商品列表
				loadStatus: 'loadmore',
				queryForm: {
					page: 1,
					limit: 10,
					cpid: '',
					cid: '',
					is_count: 1,
					has_cart: 1,
				},

				showCardPopup: false,
			};
		},
		computed: {
			...mapGetters(['cartGoodsIds']),
			showCart() {
				return this.getAttr('showCart.tabVal', 0) ? false : true
			},
			// 二级分类列表
			twoCategoryList() {
				let re = [{
					name: '全部商品'
				}]

				if (this.currentTab == -1) {
					return re
				} else {
					if (this.data[this.currentTab]) {
						return [...re, ...this.data[this.currentTab].children]
					} else {
						return [{
							name: '全部商品'
						}]
					}
				}
			},
			// 当前二级分类
			currTwoCategory() {
				return this.twoCategoryList[this.twoCategoryIndex] ? this.twoCategoryList[this.twoCategoryIndex] : {}
			},
		},
		watch: {
			// 由于改了浏览器地址参数，导致vue-router返回直接刷新页面，所以不能修改
			currentTab(nv) {
				const cate = this.data[nv]
				// if (cate) {
				// 	this.$util.changeURLArg('cpid', cate.id || '')
				// }
				this.queryForm.cpid = cate.id
			},
			twoCategoryIndex(nv) {
				const cate = this.twoCategoryList[nv]
				// if (cate) {
				// 	this.$util.changeURLArg('cid', cate.id || '')
				// }

				this.queryForm.cid = cate.id
			},
		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {
				await this.fetchData()

				const {
					cpid, // 上级分类id
					cid, // 分类id
				} = this.$Route.query

				const categoryData = this.$util.initCategoryData(this.data, [cpid, cid])
				if (categoryData[0] && categoryData[0].id == cpid) {
					this.currentTab = this.data.findIndex(item => item.id === categoryData[0].id)
					this.queryForm.cpid = cpid
				} else {
					this.currentTab = 0
					this.queryForm.cpid = this.data[0].id
				}

				if (categoryData[1] && categoryData[1].id == cid) {
					this.twoCategoryIndex = this.twoCategoryList.findIndex(item => item.id === categoryData[1].id)
					this.queryForm.cid = cid
				} else {
					this.twoCategoryIndex = 0
					this.queryForm.cid = this.twoCategoryList[0].id
				}

				await this.getGoodsList()
			},
			async fetchData() {
				const {
					category_list
				} = await this.$u.api.category()
				this.data = category_list
			},
			async getGoodsList() {
				const {
					list
				} = await this.$u.api.getDiyGoodsList(this.queryForm)
				if (list.length === 0) {
					this.loadStatus = 'nomore'
				} else {
					if (this.goodsList.length > 0) {
						this.goodsList = this.goodsList.concat(list)

					} else {
						this.goodsList = list
					}

					if (list.length < this.queryForm.limit) {
						this.loadStatus = 'nomore'
					} else {
						this.loadStatus = 'loadmore'
					}

					this.queryForm.page++
				}
			},
			reloadGoodsList() {
				this.$nextTick(() => {
					this.queryForm.page = 1
					this.loadStatus = 'loadmore'
					this.goodsList = []
					this.getGoodsList()
				})
			},
			//点击左侧按钮
			tapselect(index) {
				// 左边侧边栏点击了
				if (this.data[index] && this.data[index].is_jump_url == 1) {
					this.$util.on(this.data[index].jump_url)
					return
				}

				if (this.currentTab == index)
					return
				this.currentTab = index;
				this.twoCategoryIndex = 0
				this.reloadGoodsList()
			},
			//右侧滚动
			mainScroll(e) {

			},
			searchClick() {
				this.$util.on('/pages/search/search')
			},
			handelTwoCategoryChange(row, index) {
				if (row && row.is_jump_url == 1) {
					this.$util.on(row.jump_url)
					return
				}
				if (this.twoCategoryIndex == index)
					return
				this.twoCategoryIndex = index
				this.reloadGoodsList()
			},
			// 加入购物
			handelJoin(e) {
				this.$refs['product-popup'].show(e)
			},
			handelSettle() {
				this.$Router.push({
					path: `/pages/goods/create_order`,
					query: {
						cart_ids: this.cartGoodsIds.join(',')
					}
				})
			},
		}
	}
</script>

<style lang="scss" scoped scoped>
	.search-mask {
		position: absolute;
		width: 100%;
		height: 100%;
		left: 0;
		top: 0;
	}

	.flex-between-center {
		display: flex;
		justify-content: space-between;
		align-items: center;
	}

	.flex-wrap {
		flex-wrap: wrap;
	}

	.flex-1 {
		flex: 1
	}

	.flex-y-center {
		display: flex;
		align-items: center;
	}

	.mt-20 {
		margin-top: 20rpx;
	}

	.cateBox {
		position: absolute;
		/* top: 120rpx; */
		top: 88rpx;
		bottom: 0;
		// background: #fff;
		width: 100%;
		display: flex;

		.cate-left {
			width: 168rpx;
			height: 100%;
			background: #F5F5F5;

			.cate-left-item {
				height: 96rpx;
				display: flex;
				align-items: center;
				font-size: 26rpx;
				color: #666;
			}

			.cate-left-item.activeItem {
				background: #fff;
				color: var(--view-theme);
				position: relative;

				.top-ra {
					width: 16px;
					height: 16px;
					background-color: #f5f5f5;
					position: absolute;
					right: 0;
					top: -16px;

					uni-text {
						position: absolute;
						top: 0;
						right: 0;
						width: 100%;
						height: 100%;
						background-color: #fff;
						display: inline-block;
						border-radius: 0 0 12px 0;
					}
				}

				.bottom-ra {
					width: 16px;
					height: 16px;
					background-color: #f5f5f5;
					position: absolute;
					right: 0;
					bottom: -16px;

					uni-text {
						position: absolute;
						top: 0;
						right: 0;
						width: 100%;
						height: 100%;
						background-color: #fff;
						display: inline-block;
						border-radius: 0 12px 0 0;
					}
				}
			}

			/*
			*/

			.cate-left-item label {
				width: 3px;
				border-radius: 4rpx;
				height: 24px;
				float: left;
				background: #f4f4f4;
			}

			.cate-left-item.activeItem label {
				background: var(--view-theme);
			}

			.cate-left-item text {
				width: 196rpx;
				font-size: 28rpx;
				display: block;
				text-align: center;
			}
		}





		/* 右侧*/
		.main {
			flex: 1;
			height: 100%;
			overflow: hidden;
			padding: 0 10px;
			position: relative;
			background-color: #fff;

			.child-block-box {
				position: absolute;
				padding: 0 20rpx 0 24rpx;
				left: 0;
				top: 0;
				width: 100%;

				.child-block-wrap {
					margin: 24rpx 0 16rpx 0;
					display: flex;

					.scroll-view_H {
						flex: 1;
						overflow: hidden;
					}

					.scroll-view-item_H {
						margin-right: 16rpx;

						.scroll-view-item_H-wrap {
							color: rgba(51, 51, 51, 1);
							background: rgba(255, 255, 255, 1);
							width: 144rpx;
							height: 56rpx;
							font-size: 24rpx;
							border-radius: 30rpx;
							display: block;
							line-height: 52rpx;
							text-align: center;
							border: 2rpx solid #fff;
						}

						.active {
							color: var(--view-theme);
							background: var(--view-minorColorT);
							border: 2rpx solid var(--view-theme);
						}
					}

					.bnt-con {
						position: relative;
						margin-left: 16rpx;
						width: 56rpx;
						height: 56rpx;
						border-radius: 30rpx;
						background-color: #fff;
						display: flex;
						align-items: center;
						justify-content: center;

						&::before {
							position: absolute;
							content: "";
							width: 6rpx;
							height: 80rpx;
							background: radial-gradient(rgba(0, 0, 0, .082) 0, transparent 100%);
							left: -22rpx;
						}
					}
				}
			}
		}

		.cate-right {
			height: calc(100% - 96rpx - env(safe-area-inset-bottom));
		}

		.goods-item {
			margin-bottom: 40rpx;

			.goods-img {
				position: relative;
				border-radius: 20rpx 20rpx 0 0;
			}

			.goods-bottom {
				padding: 16rpx 24rpx 24rpx 24rpx;

				.hd {
					width: 100%;
					color: #333;
					line-height: 40rpx;
					font-size: 28rpx;

					.tag {
						position: relative;
						top: -4rpx;
						display: inline-block;
						height: 30rpx;
						padding: 0 6rpx;
						border-radius: 6rpx;
						margin-right: 8rpx;
						background: var(--view-theme);
						vertical-align: middle;
						font-size: 18rpx;
						line-height: 30rpx;
						color: #fff;
					}
				}

				.sale-num {
					font-size: 22rpx;
					padding-left: 12rpx;
					color: #8e8e8e;
				}
			}
		}

		.cate-right-title .line {
			position: absolute;
			height: 2rpx;
			width: 300rpx;
			background: orange;
			top: 39rpx;
			left: 50%;
			margin-left: -150rpx;
		}

		.cate-right-title text {
			background: #fff;
			padding: 0 10px;
			position: relative;
			color: #999;
		}

		.cate-right-list {
			height: auto;
			overflow: hidden;
		}

		.cate-right-item {
			width: 33.33%;
			float: left;
			margin-top: 20rpx;
		}

		.cate-right-item image {
			width: 160rpx;
			height: 160rpx;
			display: block;
			margin: 0 auto;
		}

		.cate-right-item text {
			display: block;
			text-align: center;
			font-size: 24rpx;
		}
	}
</style>