<template>
	<!-- 新闻播报 -->
	<view class="comp-box" :style="[compStyle]" :compCnName="compCnName" :compEnName="compEnName">
		<view class="news" v-if="dataConfig.styleConfig.tabVal == 1" :style="[newsWrapperStyle]">
			<view class="acea-row row-between-wrapper news-top">
				<view v-if="dataConfig.titleConfig.tabVal" :style="[titleStyle]">{{ dataConfig.titleTxtConfig.value }}
				</view>
				<image v-else :src="dataConfig.imgConfig.url" mode="aspectFit" class="image"></image>
				<view v-if="!dataConfig.buttonConfig.tabVal" class="more" @click="moreTab(linkConfig)"
					:style="[moreStyle]">
					更多<u-icon name="arrow-right" class="iconfont"></u-icon>
				</view>
			</view>
			<view class="news-bottom">
				<view v-for="(item, index) in listConfig" :key="index" class="acea-row row-middle item"
					:style="[itemStyle]" @click="moreTab(item.link)">
					<view class="number">{{ index + 1 }}</view>
					<view class="text">{{ item.title }}</view>
				</view>
			</view>
		</view>
		<view class="news-scroll acea-row row-middle" :style="[newsWrapperStyle]"
			v-else-if="dataConfig.styleConfig.tabVal == 0">
			<view class="news-left">
				<view class="text" v-if="dataConfig.titleConfig.tabVal" :style="[titleStyle]">
					{{ dataConfig.titleTxtConfig.value }}
				</view>
				<image class="image" :src="dataConfig.imgConfig.url" mode="aspectFit" v-else></image>
			</view>
			<view class="news-center" :style="[itemStyle]">
				<view v-if="dataConfig.rollConfig.tabVal" @click="moreTab(dataConfig.listConfig.list[0].chiild[0].val)">
					<uniNoticeBar scrollable single showGetMore background-color="transparent"
						:color="dataConfig.newsColor.color[0].item" :speed="50"
						:text="dataConfig.listConfig.list[0].chiild[0].val"></uniNoticeBar>
				</view>
				<swiper v-else class="swiper" :indicator-dots="indicatorDots" :autoplay="autoplay" interval="2500"
					:duration="duration" vertical="true" circular="true">
					<swiper-item v-for="(item,index) in listConfig" :key="index">
						<view @click="moreTab(item.link)">{{ item.title }}</view>
					</swiper-item>
				</swiper>
			</view>
			<u-icon v-if="!dataConfig.buttonConfig.tabVal" name="arrow-right" class="iconfont"
				:style="[moreStyle]"></u-icon>
		</view>
		<view class="" :style="[newsWrapperStyle]" v-else-if="dataConfig.styleConfig.tabVal == 2">
			<view class="news-card">
				<view class="hd">
					<view class="left">
						<u-image :src="img(imgUrl)" v-if="imgUrl" height="36" width="36" />
					</view>
					<view class="center" :style=[customTitleStyle]>
						{{customTitleConfig.value || '商城头条'}}
					</view>
					<view class="right">
						<view class="right-btn" :style="[moreStyle]" v-if="buttonConfig" @click="moreTab(linkConfig)">
							<text>更多</text>
							<u-icon name="arrow-right" />
						</view>
					</view>
				</view>
				<view class="news-list">
					<view v-for="(item, index) in listConfig" :key="index" class="new-item" :style="[itemStyle]"
						@click="moreTab(item.link)">
						<view class="number">{{ index + 1 }}</view>
						<view class="text line1">{{ item.title }}</view>
					</view>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	import uniNoticeBar from '@/components/uniNoticeBar/uni-notice-bar.vue';
	import CompMixin from '../mixins/comp.js'
	import _ from 'lodash'

	export default {
		components: {
			uniNoticeBar
		},
		name: 'News',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				indicatorDots: false,
				autoplay: true,
				duration: 500,
			};
		},
		computed: {
			newsStyle() {
				return {
					padding: `${this.dataConfig.topConfig.val * 2}rpx ${this.dataConfig.prConfig.val * 2}rpx ${this.dataConfig.bottomConfig.val * 2}rpx`,
					marginTop: `${this.dataConfig.mbConfig.val * 2}rpx`,
					background: this.dataConfig.bottomBgColor.color[0].item,
				};
			},
			newsWrapperStyle() {
				let borderRadius = `${this.dataConfig.fillet.val * 2}rpx`;
				if (this.dataConfig.fillet.type) {
					borderRadius =
						`${this.dataConfig.fillet.valList[0].val * 2}rpx ${this.dataConfig.fillet.valList[1].val * 2}rpx ${this.dataConfig.fillet.valList[2].val * 2}rpx ${this.dataConfig.fillet.valList[3].val * 2}rpx`;
				}
				return {
					borderRadius,
					background: `linear-gradient(90deg, ${this.dataConfig.moduleColor.color[0].item} 0%, ${this.dataConfig.moduleColor.color[1].item} 100%)`,
				};
			},
			moreStyle() {
				return {
					color: this.dataConfig.bntColor.color[0].item,
				};
			},
			titleStyle() {
				let obj = {
					color: '',
					background: '',
				}
				if (this.dataConfig.toneConfig.tabVal) {
					obj.color = this.dataConfig.titleColor.color[0].item
					obj.background =
						`linear-gradient(90deg,${this.dataConfig.titleBgColor.color[0].item} 0%,${this.dataConfig.titleBgColor.color[1].item} 100%)`
				} else {
					obj.color = '#fff'
					obj.background = 'var(--view-theme)'
				}

				return obj
			},
			itemStyle() {
				return {
					color: this.dataConfig.newsColor.color[0].item,
				};
			},
			linkConfig() {
				return this.dataConfig.linkConfig.value ? this.dataConfig.linkConfig.value :
					'/pages/extension/news_list/index'
			},
			listConfig() {
				const list = this.getAttr('listConfig.list', [])
				let arr = []
				list.forEach(item => {
					if (item.show) {
						arr.push({
							title: item.chiild[0].val,
							link: item.chiild[1].val
						})
					}
				})
				return arr
			},
			imgUrl() {
				return this.getAttr('imgConfig.url', '')
			},
			customTitleConfig() {
				return this.getAttr('customTitleConfig', {})
			},
			buttonConfig() {
				return this.getAttr('buttonConfig.tabVal', 0) ? false : true
			},
			customTitleStyle() {
				const re = {
					color: this.customTitleConfig.color
				}
				if (this.customTitleConfig.hasFontSize) {
					re.fontSize = `${this.customTitleConfig.fontSize}px`
				}
				if (this.customTitleConfig.hasFontBlod) {
					re.fontWeight = this.customTitleConfig.fontBlod ? 'bolder' : ''
				}
				return re
			},
		},
		methods: {
			moreTab(url) {
				this.$kss.JumpPath(url);
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.comp-box {
		border-top: 1px solid #f4f4f4;
		border-bottom: 1px solid #f4f4f4;
	}

	.news-scroll {
		height: 88rpx;
		padding: 0 20rpx;
		background: #FFFFFF;
	}

	.news-left {
		margin-right: 16rpx;
		border-right: 1px solid #ddd;

		.text {
			height: 40rpx;
			padding: 0 12rpx;
			border-radius: 8rpx;
			background: #FCEAE9;
			font-weight: 500;
			font-size: 26rpx;
			line-height: 40rpx;
			color: #E93323;
		}

		.image {
			display: block;
			width: 120rpx;
			height: 48rpx;
		}
	}

	.news-scroll .news-center {
		flex: 1;
		min-width: 0;
		height: 36rpx;
		font-size: 26rpx;
		line-height: 36rpx;
		color: #333333;
	}

	.news-scroll .swiper {
		height: 36rpx;
	}

	.news-scroll .iconfont {
		margin-left: 16rpx;
		font-size: 24rpx;
	}

	.news {
		padding: 32rpx 24rpx;
		background: #FFFFFF;
	}

	.news-top {
		font-weight: 500;
		font-size: 32rpx;
		line-height: 36rpx;
		color: #333333;

		.image {
			display: block;
			width: 140rpx;
			height: 36rpx;
		}

		.more {
			font-weight: 400;
			font-size: 24rpx;
			color: #999999;
		}

		.iconfont {
			font-size: 24rpx;
		}
	}

	.news-bottom {
		margin-top: 32rpx;

		.item {
			font-size: 28rpx;
			line-height: 40rpx;
			color: #282828;

			+.item {
				margin-top: 24rpx;
			}

			&:nth-child(1) {
				.number {
					color: #E93323;
				}
			}

			&:nth-child(2) {
				.number {
					color: #FF7300;
				}
			}

			&:nth-child(3) {
				.number {
					color: #FFC300;
				}
			}
		}

		.number {
			width: 30rpx;
			font-family: SemiBold;
			font-size: 30rpx;
			color: #999999;
		}

		.text {
			flex: 1;
			overflow: hidden;
			white-space: nowrap;
			text-overflow: ellipsis;
		}
	}

	.news-card {
		padding: 0 12px 16px 12px;

		.hd {
			display: flex;
			align-items: center;
			padding: 20rpx 10rpx;

			.left {
				min-width: 80rpx;
			}

			.center {
				flex: 1;
				overflow: hidden;
				text-align: center;
			}

			.right {
				min-width: 80rpx;

				.right-btn {
					// color: rgb(153, 153, 153);
				}
			}
		}

		.news-list {
			display: grid;
			grid-template-columns: repeat(2, 1fr);
			gap: 6px;

			.new-item {
				display: flex;
				align-items: center;
				gap: 10rpx;
				// width: 100%;
				overflow: hidden;

				&:nth-child(1) {
					.number {
						color: #E93323;
					}
				}

				&:nth-child(2) {
					.number {
						color: #FF7300;
					}
				}

				&:nth-child(3) {
					.number {
						color: #FFC300;
					}
				}

				.text {
					flex: 1;

				}
			}
		}
	}
</style>