<template>
	<view class="uni-cursor-point">
		<view v-if="popMenu && (leftBottom||rightBottom||leftTop||rightTop) && content.length > 0" :class="{
        'uni-fab--leftBottom': leftBottom,
        'uni-fab--rightBottom': rightBottom,
        'uni-fab--leftTop': leftTop,
        'uni-fab--rightTop': rightTop
      }" class="uni-fab" :style="nvueBottom">
			<view :class="{
          'uni-fab__content--left': horizontal === 'left',
          'uni-fab__content--right': horizontal === 'right',
          'uni-fab__content--flexDirection': direction === 'vertical',
          'uni-fab__content--flexDirectionStart': flexDirectionStart,
          'uni-fab__content--flexDirectionEnd': flexDirectionEnd,
		  'uni-fab__content--other-platform': !isAndroidNvue
        }" :style="{ width: boxWidth, height: boxHeight, backgroundColor: styles.backgroundColor }"
				class="uni-fab__content" elevation="5">
				<view v-if="flexDirectionStart || horizontalLeft" class="uni-fab__item uni-fab__item--first" />
				<view v-for="(item, index) in content" :key="index" :class="{ 'uni-fab__item--active': isShow }"
					class="uni-fab__item" @click="_onItemClick(index, item)">
					<image :src="item.active ? item.selectedIconPath : item.iconPath" class="uni-fab__item-image"
						mode="aspectFit" />
					<text class="uni-fab__item-text"
						:style="{ color: item.active ? styles.selectedColor : styles.color }">{{ item.text }}</text>
				</view>
				<view v-if="flexDirectionEnd || horizontalRight" class="uni-fab__item uni-fab__item--first" />
			</view>
		</view>
		<view :class="{
		  'uni-fab__circle--leftBottom': leftBottom,
		  'uni-fab__circle--rightBottom': rightBottom,
		  'uni-fab__circle--leftTop': leftTop,
		  'uni-fab__circle--rightTop': rightTop,
		  'uni-fab__content--other-platform': !isAndroidNvue
		}" class="uni-fab__circle uni-fab__plus" :style="{ 'background-color': styles.buttonColor, 'bottom': nvueBottom }"
			@click="_onClick">
			<view class="pictrue">
				<image :src="buttonImageSrc" style="width:100%;height:100%;" :style="[buttonImageStyle]">
				</image>
			</view>
		</view>
	</view>
</template>

<script>
	let platform = 'other'
	// #ifdef APP-NVUE
	platform = uni.getSystemInfoSync().platform
	// #endif

	/**
	 * Fab 悬浮按钮
	 * @description 点击可展开一个图形按钮菜单
	 * @tutorial https://ext.dcloud.net.cn/plugin?id=144
	 * @property {Object} pattern 可选样式配置项
	 * @property {Object} horizontal = [left | right] 水平对齐方式
	 * 	@value left 左对齐
	 * 	@value right 右对齐
	 * @property {Object} vertical = [bottom | top] 垂直对齐方式
	 * 	@value bottom 下对齐
	 * 	@value top 上对齐
	 * @property {Object} direction = [horizontal | vertical] 展开菜单显示方式
	 * 	@value horizontal 水平显示
	 * 	@value vertical 垂直显示
	 * @property {Array} content 展开菜单内容配置项
	 * @property {Boolean} popMenu 是否使用弹出菜单
	 * @event {Function} trigger 展开菜单点击事件，返回点击信息
	 * @event {Function} fabClick 悬浮按钮点击事件
	 */
	export default {
		name: 'fabV2',
		emits: ['fabClick', 'trigger'],
		props: {
			pattern: {
				type: Object,
				default () {
					return {}
				}
			},
			horizontal: {
				type: String,
				default: 'left'
			},
			vertical: {
				type: String,
				default: 'bottom'
			},
			direction: {
				type: String,
				default: 'horizontal'
			},
			content: {
				type: Array,
				default () {
					return []
				}
			},
			show: {
				type: Boolean,
				default: false
			},
			popMenu: {
				type: Boolean,
				default: true
			}
		},
		data() {
			return {
				fabShow: false,
				isShow: false,
				isAndroidNvue: platform === 'android',
				styles: {
					color: '#3c3e49',
					selectedColor: '#007AFF',
					backgroundColor: '#fff',
					buttonColor: '#007AFF',
					iconColor: '#fff',
					icon: 'plusempty'
				}
			}
		},
		computed: {
			contentWidth(e) {
				return ((this.content.length + 1) * 45 + 15) * 2 + 'rpx'
			},
			contentWidthMin() {
				return '90rpx'
			},
			// 动态计算宽度
			boxWidth() {
				return this.getPosition(3, 'horizontal')
			},
			// 动态计算高度
			boxHeight() {
				return this.getPosition(3, 'vertical')
			},
			// 计算左下位置
			leftBottom() {
				return this.getPosition(0, 'left', 'bottom')
			},
			// 计算右下位置
			rightBottom() {
				return this.getPosition(0, 'right', 'bottom')
			},
			// 计算左上位置
			leftTop() {
				return this.getPosition(0, 'left', 'top')
			},
			rightTop() {
				return this.getPosition(0, 'right', 'top')
			},
			flexDirectionStart() {
				return this.getPosition(1, 'vertical', 'top')
			},
			flexDirectionEnd() {
				return this.getPosition(1, 'vertical', 'bottom')
			},
			horizontalLeft() {
				return this.getPosition(2, 'horizontal', 'left')
			},
			horizontalRight() {
				return this.getPosition(2, 'horizontal', 'right')
			},
			// 计算 nvue bottom
			nvueBottom() {
				const safeBottom = uni.getSystemInfoSync().windowBottom;
				// #ifdef APP-NVUE
				return 30 + safeBottom
				// #endif
				// #ifndef APP-NVUE
				return 30
				// #endif
			},
			buttonImageSrc() {
				return this.pattern.buttonImage.value
			},
			buttonImageStyle() {
				const transform = this.pattern.buttonImage.transform
				const re = {}

				let arr = []
				if (transform.rotate) {
					arr.push(`rotate(${transform.rotate}deg)`)
				}
				if (transform.scale) {
					const {
						x,
						y
					} = transform.scale
					arr.push(`scale(${x},${y})`)
				}
				if (transform.translate) {
					const {
						x,
						y
					} = transform.translate
					arr.push(`translate(${x}px,${y}px)`)
				}
				if (transform.skew) {
					const {
						x,
						y
					} = transform.skew
					arr.push(`skew(${x}deg,${y}deg)`)
				}
				re.transform = arr.join(' ')

				return re
			},
		},
		watch: {
			pattern: {
				handler(val, oldVal) {
					this.styles = Object.assign({}, this.styles, val)
				},
				deep: true
			}
		},
		created() {
			this.isShow = this.show
			if (this.top === 0) {
				this.fabShow = true
			}
			// 初始化样式
			this.styles = Object.assign({}, this.styles, this.pattern)
		},
		methods: {
			_onClick() {
				this.$emit('fabClick')
				if (!this.popMenu) {
					return
				}
				this.isShow = !this.isShow
			},
			open() {
				this.isShow = true
			},
			close() {
				this.isShow = false
			},
			/**
			 * 按钮点击事件
			 */
			_onItemClick(index, item) {
				if (!this.isShow) {
					return
				}
				this.$emit('trigger', {
					index,
					item
				})
			},
			/**
			 * 获取 位置信息
			 */
			getPosition(types, paramA, paramB) {
				if (types === 0) {
					return this.horizontal === paramA && this.vertical === paramB
				} else if (types === 1) {
					return this.direction === paramA && this.vertical === paramB
				} else if (types === 2) {
					return this.direction === paramA && this.horizontal === paramB
				} else {
					return this.isShow && this.direction === paramA ? this.contentWidth : this.contentWidthMin
				}
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	$uni-shadow-base: 0 1px 5px 2px rgba($color: #000000, $alpha: 0.3) !default;

	.uni-fab {
		position: fixed;
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		justify-content: center;
		align-items: center;
		z-index: 10;
		border-radius: 45px;
		// box-shadow: $uni-shadow-base;
	}

	.uni-cursor-point {
		/* #ifdef H5 */
		cursor: pointer;
		/* #endif */
	}

	.uni-fab--active {
		opacity: 1;
	}

	.uni-fab--leftBottom {
		left: calc(30rpx + var(--window-left, 0));
		bottom: calc(160rpx + var(--window-bottom, 0));
	}

	.uni-fab--leftTop {
		left: 30rpx;
		top: 60rpx;
		/* #ifdef H5 */
		left: calc(30rpx + var(--window-left));
		top: calc(60rpx + var(--window-top));
		/* #endif */
		// padding: 10px;
	}

	.uni-fab--rightBottom {
		right: calc(30rpx + var(--window-right, 0));
		bottom: calc(160rpx + var(--window-bottom, 0));
	}

	.uni-fab--rightTop {
		right: 30rpx;
		top: 60rpx;
		/* #ifdef H5 */
		right: calc(30rpx + var(--window-right));
		top: calc(60rpx + var(--window-top));
		/* #endif */
		// padding: 10px;
	}

	.uni-fab__circle {
		position: fixed;
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		justify-content: center;
		align-items: center;
		width: 90rpx;
		height: 90rpx;
		background-color: #3c3e49;
		border-radius: 90rpx;
		z-index: 11;
		// box-shadow: $uni-shadow-base;
	}

	.uni-fab__circle--leftBottom {
		left: calc(30rpx + var(--window-left, 0));
		bottom: calc(160rpx + var(--window-bottom, 0));
	}

	.uni-fab__circle--leftTop {
		left: 15px;
		top: 30px;
		/* #ifdef H5 */
		left: calc(15px + var(--window-left));
		top: calc(30px + var(--window-top));
		/* #endif */
	}

	.uni-fab__circle--rightBottom {
		right: calc(30rpx + var(--window-right, 0));
		bottom: calc(160rpx + var(--window-bottom, 0));
	}

	.uni-fab__circle--rightTop {
		right: 30rpx;
		top: 60rpx;
		/* #ifdef H5 */
		right: calc(30rpx + var(--window-right));
		top: calc(60rpx + var(--window-top));
		/* #endif */
	}

	.uni-fab__circle--left {
		left: 0;
	}

	.uni-fab__circle--right {
		right: 0;
	}

	.uni-fab__circle--top {
		top: 0;
	}

	.uni-fab__circle--bottom {
		bottom: 0;
	}

	.uni-fab__plus {
		font-weight: bold;
	}

	// .fab-circle-v {
	// 	position: absolute;
	// 	width: 2px;
	// 	height: 24px;
	// 	left: 0;
	// 	top: 0;
	// 	right: 0;
	// 	bottom: 0;
	// 	/* #ifndef APP-NVUE */
	// 	margin: auto;
	// 	/* #endif */
	// 	background-color: white;
	// 	transform: rotate(0deg);
	// 	transition: transform 0.3s;
	// }

	// .fab-circle-h {
	// 	position: absolute;
	// 	width: 24px;
	// 	height: 2px;
	// 	left: 0;
	// 	top: 0;
	// 	right: 0;
	// 	bottom: 0;
	// 	/* #ifndef APP-NVUE */
	// 	margin: auto;
	// 	/* #endif */
	// 	background-color: white;
	// 	transform: rotate(0deg);
	// 	transition: transform 0.3s;
	// }

	.fab-circle-icon {
		transform: rotate(0deg);
		transition: transform 0.3s;
		font-weight: 200;
	}

	.uni-fab__plus--active {
		transform: rotate(135deg);
	}

	.uni-fab__content {
		/* #ifndef APP-NVUE */
		box-sizing: border-box;
		display: flex;
		/* #endif */
		flex-direction: row;
		border-radius: 90rpx;
		overflow: hidden;
		transition-property: width, height;
		transition-duration: 0.2s;
		width: 90rpx;
		border-color: #DDDDDD;
		border-width: 1rpx;
		border-style: solid;
	}

	.uni-fab__content--other-platform {
		border-width: 0px;
		// box-shadow: $uni-shadow-base;
	}

	.uni-fab__content--left {
		justify-content: flex-start;
	}

	.uni-fab__content--right {
		justify-content: flex-end;
	}

	.uni-fab__content--flexDirection {
		flex-direction: column;
		justify-content: flex-end;
	}

	.uni-fab__content--flexDirectionStart {
		flex-direction: column;
		justify-content: flex-start;
	}

	.uni-fab__content--flexDirectionEnd {
		flex-direction: column;
		justify-content: flex-end;
	}

	.uni-fab__item {
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		flex-direction: column;
		justify-content: center;
		align-items: center;
		width: 90rpx;
		height: 90rpx;
		opacity: 0;
		transition: opacity 0.2s;
	}

	.uni-fab__item--active {
		opacity: 1;
	}

	.uni-fab__item-image {
		width: 40rpx;
		height: 40rpx;
		// margin-bottom: 8rpx;
	}

	.uni-fab__item-text {
		color: #FFFFFF;
		font-size: 24rpx;
		line-height: 24rpx;
		margin-top: 4rpx;
	}

	.uni-fab__item--first {
		width: 90rpx;
	}

	.pictrue {
		width: 90rpx;
		height: 90rpx;
		border-radius: 50%;
	}
</style>