<template>
	<view>
		<view class="comp-box" :style="[compStyle]" v-show="showComp">
			<view class="wrap" :style="[compWrapStyle]">
				<view class="comp-content">
					<u-image :src="img(imgConfig)" width="72" height="72" border-radius="20" />
					<view class="follow-title line1" :style="[titleStyle]">{{ titleConfig.value }}</view>
					<view class="follow-btn" @click="showQrcodePopup">立即关注</view>
					<view class="close-btn" @click="handelClose"><u-icon name="close" size="32" /></view>
				</view>
			</view>
		</view>
		<OfficialAccountQrcodePopup ref="official-account-qrcode-popup" />
	</view>
</template>
<script>
	import CompMixin from '../mixins/comp.js'

	export default {
		components: {

		},
		name: 'OfficialAccountAttention',
		props: {

		},
		mixins: [CompMixin],
		data() {
			return {
				md5: '',
				showComp: false,

				qrcodeUrl: '',
				loginToken: ''
			};
		},
		computed: {
			imgConfig() {
				return this.getAttr('imgConfig.url', '')
			},
			titleConfig() {
				return this.getAttr('titleConfig', {})
			},
			titleStyle() {
				const re = {
					color: this.titleConfig.color,
					fontSize: `${this.titleConfig.fontSize * 2}rpx`,
					fontWeight: this.titleConfig.fontBlod ?
						'bolder' : 'normal',
				}

				return re
			},
			isFixed() {
				return !this.getAttr('positionConifg.tabVal', 0) ? true : false
			},
			fixedZindex() {
				return this.getAttr('positionConifg.tabList[0].content[0].value', 99)
			},
			fixedBottom() {
				return this.getAttr('positionConifg.tabList[0].content[1].value', 70) * 2 + 'rpx'
			},
			// 组件容器样式
			compStyle() {
				const re = {
					backgroundColor: this.bottomBgColor,
					backgroundImage: `url(${this.$util.img2(this.bottomBgPicConfig.src)})`,
					backgroundRepeat: '',
					backgroundSize: '',
					marginTop: this.mbConfig,
					paddingTop: this.topConfig,
					paddingBottom: this.bottomConfig,
					paddingLeft: this.prConfig,
					paddingRight: this.prConfig,
				}
				if (this.bottomBgPicConfig.tabVal == 2) {
					re.backgroundSize = '100% 100%'
					re.backgroundRepeat = 'no-repeat'
				} else if (this.bottomBgPicConfig.tabVal == 1) {
					re.backgroundSize = '100%'
					re.backgroundRepeat = 'repeat'
				} else {
					re.backgroundSize = '100%'
					re.backgroundRepeat = 'no-repeat'
				}
				if (this.isFixed) {
					const positionConifg = this.getAttr('positionConifg.tabVal', 0)
					re.position = 'fixed'
					re.zIndex = this.fixedZindex
					re.left = 0
					re.right = 0
					re.bottom = this.fixedBottom
				}
				return re
			},
			closeConfig() {
				return this.getAttr('closeConfig.tabVal', 0)
			},
			qrcodeTypeConfig() {
				return this.getAttr('qrcodeTypeConfig.tabVal', 0)
			},
			customQrcodeImgConfig() {
				return this.getAttr('customQrcodeImgConfig.url', '')
			},
		},
		options: {
			styleIsolation: 'shared'
		},
		watch: {

		},
		mounted() {
			this.init()
		},
		methods: {
			async init() {
				this.md5 = this.pageConfig.version

				if (this.qrcodeTypeConfig == 1) {
					this.qrcodeUrl = this.customQrcodeImgConfig
					const data = this.getCacheData(this.md5)
					if (!data) {
						this.showComp = true
					} else {
						if (!this.isIn24Hours(data.crate_date)) {
							this.showComp = true
						}
					}
				} else {
					const res = await this.$u.api.getwxgzhqrcode({
						type: 1
					})
					if (res.login_token) {
						this.qrcodeUrl = res.url
						this.loginToken = res.login_token

						const data = this.getCacheData(this.md5)
						if (!data) {
							this.showComp = true
						} else {
							if (!this.isIn24Hours(data.crate_date)) {
								this.showComp = true
							}
						}
					} else {
						this.showComp = false
					}
				}
			},
			showQrcodePopup() {
				this.$refs['official-account-qrcode-popup'].show(this.qrcodeUrl)
			},
			getCacheData(md5) {
				const arr = uni.getStorageSync('official-account-attention-cache')
				if (arr && Array.isArray(arr)) {
					return arr.find(item => item.md5 == md5)
				}
			},
			setCacheData(md5, value) {
				let arr = uni.getStorageSync('official-account-attention-cache')
				if (!arr)
					arr = []

				if (Array.isArray(arr)) {
					let find = arr.findIndex(item => item.md5 === md5)
					if (find != -1) {
						arr.splice(find, 1, value)
					} else {
						arr.push(value)
					}
					// 清理不在24小时内数据
					const new_arr = arr.filter(item => {
						if (this.isIn24Hours(item.crate_date)) {
							return item
						}
					})
					uni.setStorageSync('official-account-attention-cache', new_arr)
				}
			},
			isIn24Hours(time) {
				let t = Date.now() - time
				if (t >= 0 && t <= 24 * 3600 * 1000)
					return true
				else
					return false
			},
			handelClose() {
				if (this.closeConfig === 0)
					this.setCacheData(this.md5, {
						md5: this.md5,
						crate_date: Date.now()
					})

				setTimeout(() => {
					this.showComp = false
				}, 200)
			},
		}
	}
</script>
<style lang="scss" scoped scoped>
	.comp-content {
		display: flex;
		align-items: center;
		height: 90rpx;
		padding: 0 40rpx;
		position: relative;
		border-radius: 56rpx;

		.follow-title {
			flex: 1;
			margin-left: 20rpx;
		}

		.follow-btn {
			width: 186rpx;
			height: 62rpx;
			background-color: #ff5f01;
			border-radius: 10rpx;
			font-size: 24rpx;
			font-weight: 500;
			color: #fff;
			display: flex;
			align-items: center;
			justify-content: center;
			margin-right: 40rpx;
		}

		.close-btn {
			position: absolute;
			right: 28rpx;
			top: 50%;
			transform: translateY(-50%);
			font-size: 40rpx;
			font-weight: 500;
			color: #9b9fa8;
		}
	}
</style>