<template>
	<view class="buy-btn" :class="{
      'size-small': size == 'small',
      'style-1': goodsType == 1 && !sysconfig.change_site_info,
      'style-2': goodsType == 2 || goodsType == 3  || sysconfig.change_site_info,
      'empty-stock': stockNum == 0 || status == 2
    }" @click="$emit('click')">
		<template v-if="status == 2"> 暂停销售 </template>
		<template v-else>
			<template v-if="stockNum">
				<template v-if="goodsType == 1 && !sysconfig.change_site_info">提取卡密</template>
				<template v-else>立即购买</template>
			</template>
			<template v-else> 已售罄 </template>
		</template>
	</view>
</template>

<script>
	export default {
		components: {},
		props: {
			goodsType: {
				type: Number,
				default: 0
			},
			stockNum: {
				type: Number,
				default: 0
			},
			status: {
				type: Number,
				default: 0
			},
			size: {
				type: String,
				default: ''
			}
		},
		data() {
			return {}
		},
		watch: {},
		compute: {},
		mounted() {},
		methods: {}
	}
</script>

<style scoped lang="scss" scoped>
	.buy-btn {
		font-size: 24rpx;
		color: #fff;
		border: 1px solid #999;
		border-radius: 4rpx;
		text-align: center;
		display: block;
		cursor: pointer;
		user-select: none;
		transition: all 0.3s;
		line-height: normal;
	}

	.size-small {
		border-radius: 48rpx;
		padding: 10rpx 24rpx;
	}

	.style-1 {
		color: #0eab0f;
		border: 1px solid #0eab0f;

		&:hover {
			color: #fff;
			background-color: #0eab0f;
		}
	}

	.style-2 {
		color: #fff;
		border: 1px solid #ff564d;
		background-color: #ff564d;

		&:hover {
			color: #fff;
			background-color: #ff564d;
		}
	}

	.empty-stock {
		background-color: #909399;
		color: #fff;
		border: 1px solid #909399;
		cursor: not-allowed;

		&:hover {
			background-color: #909399;
			color: #fff;
		}
	}
</style>