<template>
	<view class="store-num"> 库存:{{ num }}</view>
</template>

<script>
	import {
		mapGetters
	} from 'vuex'
	export default {
		components: {},
		props: {
			goodsType: {
				type: [Number, String],
				required: true
			},
			stockNum: {
				type: [Number, String],
				required: true
			}
		},
		data() {
			return {}
		},
		computed: {
			...mapGetters(['sysconfig']),
			num() {
				if (this.sysconfig.goods.goods_sale_show) {
					return (this.stockNum > 99999 ? 99999 : this.stockNum) + '件'
				} else {
					if (this.stockNum >= this.sysconfig.goods.default_warn_stock_num) {
						let str = `${this.stockNum}`
						if (
							this.goodsType == 1 &&
							this.sysconfig.goods.goods_card_density_display === true
						) {
							str = '充足'
						} else if (
							this.goodsType == 2 &&
							this.sysconfig.goods.goods_virtual_display === true
						) {
							str = '充足'
						} else if (
							this.goodsType == 3 &&
							this.sysconfig.goods.goods_normal_display === true
						) {
							str = '充足'
						}
						return str
					} else if (
						this.stockNum < this.sysconfig.goods.default_warn_stock_num &&
						this.stockNum > 0
					) {
						return '正常'
					} else {
						return '断货'
					}
				}
			}
		},
		created() {},
		mounted() {},
		methods: {}
	}
</script>
<style scoped lang="scss" scoped>
	.store-num {
		margin-top: 12rpx;
		color: #999;
		font-size: 24rpx;
	}
</style>