<template>
	<view>
		<uni-swiper-dot :info="list" :current="current" mode="round" @clickItem="clickItem" :dotsStyles="{
			backgroundColor:'#fff',
			border:'#fff',
			selectedBackgroundColor:'#fff',
			selectedBorder:'#fff'
		}">
			<swiper class="swiper" :style="{height:height+'rpx'}" :circular="true" :autoplay="swiperAutoplay"
				:interval="3000" :duration="500" :current="swiperDotIndex" @change='swiperChange'>
				<swiper-item v-for="(item,index) in list" :index="index" :key="index">
					<view class="video-wrap" v-if="item.type === 'video'">
						<video :id="`video${index}`" style="width: 100%;height: 100%;" object-fit="fill"
							:videoAutoplay="videoAutoPlay" :enable-progress-gesture="false" :src="item.url"
							@play="handleVideoPlay" @pause="handleVideoPause" @ended="handleVideoEnd"
							v-show="!hiddenVideo"></video>
					</view>
					<view class="img-wrap" v-else-if="item.type === 'image'" :style="{padding:padding}">
						<image style="width: 100%; height: 100%;" :style="{borderRadius:borderRadius}"
							:src="$util.img(item.url)" class="img" @click="handelClick(index)"></image>
					</view>
				</swiper-item>
			</swiper>
		</uni-swiper-dot>
	</view>
</template>

<script>
	export default {
		name: 'mix-swiper',
		props: {
			height: {
				type: Number,
				default: 220
			},
			list: { //banner集合
				type: Array,
				default: () => []
			},
			borderRadius: {
				type: String,
				default: '20rpx'
			},
			padding: {
				type: String,
				default: '20rpx'
			},
			hiddenVideo: {
				type: Boolean,
				default: false,
			}
		},
		data() {
			return {
				current: 0,
				swiperDotIndex: 0,

				videoAutoPlay: false,
				swiperAutoplay: false,
			}
		},
		//事件监听
		watch: {},
		mounted() {
			this.$nextTick(() => {
				setTimeout(() => {
					uni.createVideoContext("video" + (this.current)).play()
				}, 3000)
			})
		},
		methods: {
			clickItem(e) {
				this.swiperDotIndex = e
			},

			//banner事件
			swiperChange(detail) {
				//切换时要把视频暂停
				if (this.list[this.current].type == 'video') {
					uni.createVideoContext("video" + (this.current)).pause()
				}
				this.current = detail.detail.current
				this.$emit('change', detail.detail.current)
			},
			handleVideoPlay() {
				this.swiperAutoplay = false
				this.videoAutoPlays = true;
			},
			handleVideoPause() {
				this.swiperAutoplay = true
			},
			handleVideoEnd() {
				this.swiperAutoplay = true;
			},
			handelClick(index) {
				let i = index
				let imgList = []
				const videoItem = this.list[0]
				if (videoItem.type === 'video') {
					i = i - 1
					imgList = this.list.slice(1).map(item => item.url)
				} else {
					imgList = this.list.map(item => item.url)
				}

				uni.previewImage({
					urls: imgList,
					current: i,
				})
			},
		}
	}
</script>


<style lang="scss" scoped scoped>
	
	::v-deep {
		uni-image > img {
				opacity: 1 !important;
		}
	}
	
	
	.swiper {
		width: 750rpx;
		height: 440rpx;

		.video-wrap {
			height: 100%;
			// background-color: rgba(0, 0, 0, .9);
			display: flex;
			align-items: center;
			justify-content: center;
			// padding: 20rpx;
		}

		.img-wrap {
			height: 100%;

			.img {
				height: 100%;
			}
		}
	}
</style>